<#
.SYNOPSIS
  scan-av - on-demand multi-engine antivirus scanner for Windows.
  Runs ClamAV (clamscan) and/or Emsisoft Emergency Kit (a2cmd) over folders,
  downloads and large archives, working around ClamAV's 2 GiB-per-file limit by
  extracting only the executable "threat surface" with 7-Zip before scanning.

.DESCRIPTION
  First run auto-detects the scanners + 7-Zip, asks which folders to scan, and
  saves everything to a JSON config. Later runs just read the config.

  Mirrors the macOS 'scan-archive' workflow, but cross-engine:
    - Archives (.rar/.7z/.zip): extract exec/script files, scan, clean up.
    - Folders: scan in place.
    - ClamAV size-limit skips (Heuristics.Limits.Exceeded) are reported as
      "skipped", NOT as malware.
    - Running both engines: agreement = high confidence, disagreement = the
      files worth a multi-engine second opinion (e.g. packer false positives).

.PARAMETER Install
  Copy this script into %LOCALAPPDATA%\ScanAV, add it to your PATH, then configure.
.PARAMETER Configure
  (Re)run the first-run setup wizard and rewrite the config.
.PARAMETER Path
  One or more files/folders to scan, overriding the configured folders.
.PARAMETER Full
  Extract & scan EVERY file in an archive (not just executables). Slower.
.PARAMETER Engine
  clamav | emsisoft | both  (default: whatever the config has enabled)
.PARAMETER Update
  Update virus definitions first (freshclam / a2cmd /update) before scanning.
.PARAMETER VtAll
  Also reputation-check NEW/changed executables on VirusTotal for every unit this
  run, even when the local engines find nothing (needs an API key in Settings).
  Can be enabled permanently per folder via the VT badge on its card in the app.
.PARAMETER ListQuarantine
  List quarantined files.
.PARAMETER RestoreQuarantine
  Restore quarantined file(s) by (partial) name, or 'all'.
.PARAMETER Help
  Show this help.

.EXAMPLE
  .\scan-av.ps1 -Install
.EXAMPLE
  scan-av                       # scan all configured folders
.EXAMPLE
  scan-av -Path 'D:\Downloads\archive.rar' -Update
#>

[CmdletBinding()]
param(
  [switch]$Install,
  [switch]$InstallEngines,
  [switch]$Configure,
  [switch]$Shortcut,
  [switch]$NoPromptShortcut,
  [string[]]$Path,
  [switch]$Full,
  [ValidateSet('clamav','emsisoft','defender','both','all','config')] [string]$Engine = 'config',
  [switch]$Update,
  [switch]$NoUpdate,
  [switch]$NoElevate,
  [switch]$RescanAll,
  [switch]$NoIncremental,
  [string[]]$AddFolder,
  [string[]]$RemoveFolder,
  [switch]$ListFolders,
  [switch]$Gui,
  [switch]$SelfUpdate,
  [switch]$InstallContextMenu,
  [switch]$RemoveContextMenu,
  [switch]$NoPrompt,
  [string]$ContextScan,
  [ValidateSet('clamav','emsisoft','defender','both','all')] [string]$UpdateDefs,
  [switch]$VtAll,
  [switch]$ListQuarantine,
  [string[]]$RestoreQuarantine,
  [switch]$Help
)

$ScanAvVersion = '1.10.0'
$ScanAvBuild   = '2026-07-07'
$script:ScanAvIconB64 = ''

$ErrorActionPreference = 'Stop'

# ---------------------------------------------------------------- paths / dirs
$AppDir  = Join-Path $env:LOCALAPPDATA 'ScanAV'
$CfgFile = Join-Path $AppDir 'config.json'
$LogDir  = Join-Path $AppDir 'logs'
$EngDir  = Join-Path $AppDir 'engines'
$CacheFile = Join-Path $AppDir 'scan-cache.json'
$QuarDir = Join-Path $AppDir 'quarantine'
$script:LiveScan = $false   # set true by -Verbose: stream engine output live to console
$ArchiveExt = @('.rar','.7z','.zip','.zipx','.001','.tar','.gz','.cab','.iso')
$DefaultExecExt = @('exe','dll','msi','bat','cmd','ps1','vbs','scr','com','sys','jar','lnk','hta','js','wsf','ocx','cpl','efi')

# ---------------------------------------------------------------- pretty print
function Hr   { Write-Host ('=' * 64) -ForegroundColor DarkGray }
function Sec  ($t){ Hr; Write-Host $t -ForegroundColor Cyan; Hr }
function Info ($t){ Write-Host "  $t" }
function Ok   ($t){ Write-Host "  $t" -ForegroundColor Green }
function Warn ($t){ Write-Host "  $t" -ForegroundColor Yellow }
function Bad  ($t){ Write-Host "  $t" -ForegroundColor Red }

if ($Help) { Get-Help $PSCommandPath -Detailed; return }

# prune logs older than 7 days so the folder doesn't grow without bound (runs on
# both GUI launch and CLI scans - CLI-only users prune too)
function Prune-Logs {
  try { Get-ChildItem $LogDir -Filter *.log -ErrorAction SilentlyContinue | Where-Object { $_.LastWriteTime -lt (Get-Date).AddDays(-7) } | Remove-Item -Force -ErrorAction SilentlyContinue } catch {}
}

# ---------------------------------------------------------------- tool finder
function Find-Tool {
  param([string]$Exe, [string[]]$Candidates)
  # 1) already on PATH?
  $cmd = Get-Command $Exe -ErrorAction SilentlyContinue
  if ($cmd) { return $cmd.Source }
  # 2) known install locations
  foreach ($c in $Candidates) {
    if ($c -and (Test-Path $c)) { return (Resolve-Path $c).Path }
  }
  # 3) bounded search of likely roots (last resort, can be slow)
  $roots = @($EngDir, "$env:SystemDrive\", "$env:USERPROFILE\Desktop", "$env:USERPROFILE\Downloads",
             "$env:SystemDrive\EEK", "$env:ProgramData", "$env:ProgramFiles", ${env:ProgramFiles(x86)})
  foreach ($r in ($roots | Select-Object -Unique)) {
    if (-not (Test-Path $r)) { continue }
    try {
      $hit = Get-ChildItem -Path $r -Filter $Exe -Recurse -Depth 4 -ErrorAction SilentlyContinue |
             Select-Object -First 1
      if ($hit) { return $hit.FullName }
    } catch {}
  }
  return $null
}

# Microsoft Defender's command-line tool. The real binary lives under a versioned
# Platform folder that changes with each engine update, so prefer the newest one
# there; fall back to the static system copy.
function Find-Defender {
  $cands = @()
  $plat = Join-Path $env:ProgramData 'Microsoft\Windows Defender\Platform'
  if (Test-Path $plat) {
    $newest = Get-ChildItem -Path $plat -Directory -ErrorAction SilentlyContinue |
              Sort-Object Name -Descending |
              ForEach-Object { Join-Path $_.FullName 'MpCmdRun.exe' } |
              Where-Object { Test-Path $_ } | Select-Object -First 1
    if ($newest) { $cands += $newest }
  }
  $cands += "$env:ProgramFiles\Windows Defender\MpCmdRun.exe"
  foreach ($c in $cands) { if ($c -and (Test-Path $c)) { return $c } }
  return $null
}

# ---------------------------------------------------------------- elevation
function Test-IsAdmin {
  try { (New-Object Security.Principal.WindowsPrincipal([Security.Principal.WindowsIdentity]::GetCurrent())).IsInRole([Security.Principal.WindowsBuiltinRole]::Administrator) }
  catch { $false }
}

# Relaunch this script elevated, forwarding the original parameters, so Emsisoft's
# a2cmd runs inline (no separate self-elevation window mid-scan). Returns $true if a
# new elevated process was started (caller should then exit).
function Invoke-RelaunchElevated {
  param([hashtable]$Bound)
  if (-not $PSCommandPath) { return $false }   # can't relaunch a -Command invocation
  # Rebuild the invocation as a command string and pass it -EncodedCommand. Forwarding
  # array parameters via -File (-Path "a","b") binds them as ONE literal string
  # "a,b" - the same bug Start-InAppRun hit - so multi-folder elevated scans broke.
  function local:VQ([string]$s) { "'" + ($s -replace "'", "''") + "'" }
  $parts = @('&', (VQ $PSCommandPath))
  foreach ($k in $Bound.Keys) {
    if ($k -eq 'NoElevate') { continue }
    $v = $Bound[$k]
    if ($v -is [System.Management.Automation.SwitchParameter]) { if ($v.IsPresent) { $parts += "-$k" } }
    elseif ($v -is [array]) { $parts += "-$k"; $parts += (($v | ForEach-Object { VQ ([string]$_) }) -join ',') }
    else { $parts += "-$k"; $parts += (VQ ([string]$v)) }
  }
  # End with an explicit pause instead of -NoExit: the script now sets real exit
  # codes (exit 1/2), and `exit` terminates a -NoExit session anyway - the pause
  # keeps the results window open until the user dismisses it.
  $cmd = ($parts -join ' ') + "; Write-Host ''; Read-Host 'Finished - press Enter to close this window' | Out-Null"
  $enc = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($cmd))
  try {
    $hostExe = (Get-Process -Id $PID).Path   # the powershell.exe running us
    Start-Process -FilePath $hostExe -Verb RunAs -ArgumentList @('-NoProfile','-ExecutionPolicy','Bypass','-EncodedCommand', $enc) -ErrorAction Stop
    return $true
  } catch { Warn "Elevation cancelled/failed: $_"; return $false }
}

function Ask {
  param([string]$Prompt, [string]$Default)
  if ($Default) { $r = Read-Host "$Prompt [$Default]" } else { $r = Read-Host $Prompt }
  if ([string]::IsNullOrWhiteSpace($r)) { return $Default } else { return $r.Trim('"') }
}
function AskYesNo { param([string]$Prompt,[bool]$Default=$true)
  $d = if($Default){'Y/n'}else{'y/N'}; $r = Read-Host "$Prompt [$d]"
  if ([string]::IsNullOrWhiteSpace($r)) { return $Default }
  return ($r -match '^[Yy]')
}

# ---------------------------------------------------------------- configure
function Invoke-Configure {
  param([hashtable]$Pre = @{})
  Sec 'scan-av  -  first-run configuration'
  New-Item -ItemType Directory -Force -Path $AppDir, $LogDir | Out-Null

  Info 'Detecting tools (this can take a moment the first time)...'
  $sevenZ  = if ($Pre.seven) { $Pre.seven } else { Find-Tool '7z.exe'      @("$EngDir\7-Zip\7z.exe", "$env:ProgramFiles\7-Zip\7z.exe", "${env:ProgramFiles(x86)}\7-Zip\7z.exe") }
  $clam    = if ($Pre.clam)  { $Pre.clam }  else { Find-Tool 'clamscan.exe' @("$EngDir\ClamAV\clamscan.exe", "$env:ProgramFiles\ClamAV\clamscan.exe", "${env:ProgramFiles(x86)}\ClamAV\clamscan.exe", "$env:SystemDrive\ClamAV\clamscan.exe", "$env:ProgramData\chocolatey\bin\clamscan.exe") }
  $fresh   = if ($Pre.fresh) { $Pre.fresh } else { Find-Tool 'freshclam.exe' @("$EngDir\ClamAV\freshclam.exe", "$env:ProgramFiles\ClamAV\freshclam.exe", "${env:ProgramFiles(x86)}\ClamAV\freshclam.exe", "$env:SystemDrive\ClamAV\freshclam.exe") }
  $a2      = if ($Pre.a2)    { $Pre.a2 }    else { Find-Tool 'a2cmd.exe'    @("$EngDir\EEK\bin\a2cmd.exe", "$env:SystemDrive\EEK\bin\a2cmd.exe", "$env:ProgramData\EEK\bin\a2cmd.exe", "$env:USERPROFILE\Desktop\EEK\bin\a2cmd.exe", "$env:USERPROFILE\Downloads\EEK\bin\a2cmd.exe", "$env:ProgramFiles\Emsisoft Emergency Kit\bin\a2cmd.exe") }
  $defExe  = if ($Pre.defender) { $Pre.defender } else { Find-Defender }

  Write-Host ''
  Info 'Confirm or correct each path (Enter to accept, blank/"-" to disable):'
  $sevenZ = Ask '  7-Zip  (7z.exe)'        $sevenZ
  $clam   = Ask '  ClamAV (clamscan.exe)'  $clam
  $fresh  = Ask '  ClamAV (freshclam.exe)' $fresh
  $a2     = Ask '  Emsisoft (a2cmd.exe)'   $a2
  foreach ($v in 'sevenZ','clam','fresh','a2') { if ((Get-Variable $v).Value -eq '-') { Set-Variable $v '' } }

  if (-not $sevenZ) { Warn '7-Zip not set - archive (.rar/.7z) scanning will be disabled; folders still work.' }
  if ($defExe) { Ok "  Microsoft Defender detected: $defExe" } else { Warn '  Microsoft Defender (MpCmdRun.exe) not found - Defender engine disabled.' }
  $useClam = [bool]$clam   -and (AskYesNo '  Enable ClamAV engine?'             $([bool]$clam))
  $useEms  = [bool]$a2     -and (AskYesNo '  Enable Emsisoft engine?'           $([bool]$a2))
  $useDef  = [bool]$defExe -and (AskYesNo '  Enable Microsoft Defender engine?' $([bool]$defExe))
  if (-not ($useClam -or $useEms -or $useDef)) { Bad 'No engine enabled. Install ClamAV and/or Emsisoft Emergency Kit (or enable Defender), then re-run -Configure.'; return $null }

  Write-Host ''
  Info 'Which folders should "scan-av" check by default? (one per line, blank to finish)'
  $folders = @()
  while ($true) {
    $f = Read-Host '  folder'
    if ([string]::IsNullOrWhiteSpace($f)) { break }
    $f = $f.Trim('"')
    if (Test-Path -LiteralPath $f) { $folders += (Resolve-Path -LiteralPath $f).Path } else { Warn "    not found, added anyway: $f"; $folders += $f }
  }

  Write-Host ''
  $modeFull = AskYesNo '  Scan FULL archive contents instead of just executables? (slower)' $false
  $maxFile  = [int](Ask '  ClamAV max single-file size in MB (<=2000)' '2000')
  $maxScan  = [int](Ask '  ClamAV max total scan size per container in MB' '4000')
  $autoUpd  = AskYesNo '  Auto-update virus definitions before scanning?' $true
  $incr     = AskYesNo '  Skip files already scanned & unchanged (incremental)?' $true

  $cfg = [ordered]@{
    version   = 1
    tools     = [ordered]@{ sevenZip=$sevenZ; clamscan=$clam; freshclam=$fresh; a2cmd=$a2; defender=$defExe }
    engines   = [ordered]@{ clamav=$useClam; emsisoft=$useEms; defender=$useDef }
    scanFolders = $folders
    options   = [ordered]@{
      mode='exec'; maxFileSizeMB=$maxFile; maxScanSizeMB=$maxScan
      execExtensions=$DefaultExecExt; tempDir=''
      autoUpdate=$autoUpd; updateMaxAgeHours=12; autoElevate=$true; incremental=$incr
      engineTimeoutMinutes=30
      vtApiKey=''; vtUploadUnknown=$false; thirdPartySigs=$false
    }
  }
  if ($modeFull) { $cfg.options.mode = 'full' }

  ($cfg | ConvertTo-Json -Depth 6) | Set-Content -Path $CfgFile -Encoding UTF8
  Write-Host ''
  Ok "Saved config -> $CfgFile"
  Info "Engines: ClamAV=$useClam  Emsisoft=$useEms  Defender=$useDef   Folders: $($folders.Count)   Mode: $($cfg.options.mode)"
  return $cfg
}

function Load-Config {
  if (-not (Test-Path $CfgFile)) { return $null }
  return (Get-Content $CfgFile -Raw | ConvertFrom-Json)
}

# ---------------------------------------------------------------- engine auto-install
function Ensure-Tls { try { [Net.ServicePointManager]::SecurityProtocol = ([Net.ServicePointManager]::SecurityProtocol -bor [Net.SecurityProtocolType]::Tls12) } catch {} }
function Get-File { param($Url,$Out) Ensure-Tls; Info "    download: $Url"; Invoke-WebRequest -Uri $Url -OutFile $Out -UseBasicParsing }

function Install-SevenZip {
  Info '7-Zip:'
  $found = (Get-Command 7z.exe -ErrorAction SilentlyContinue).Source
  if (-not $found) { foreach ($p in "$env:ProgramFiles\7-Zip\7z.exe","${env:ProgramFiles(x86)}\7-Zip\7z.exe","$EngDir\7-Zip\7z.exe") { if (Test-Path $p) { $found = $p; break } } }
  if ($found) { Ok "  already present: $found"; return $found }
  if (Get-Command winget -ErrorAction SilentlyContinue) {
    try { winget install -e --id 7zip.7zip --accept-source-agreements --accept-package-agreements 2>$null | Out-Null } catch {}
    foreach ($p in "$env:ProgramFiles\7-Zip\7z.exe","${env:ProgramFiles(x86)}\7-Zip\7z.exe") { if (Test-Path $p) { Ok "  installed via winget"; return $p } }
  }
  try {  # NSIS silent install into a user dir (no admin needed)
    $page = (Invoke-WebRequest 'https://www.7-zip.org/download.html' -UseBasicParsing).Content
    $m = [regex]::Match($page,'a/(7z\d+-x64\.exe)')
    if ($m.Success) {
      $dl = Join-Path $env:TEMP $m.Groups[1].Value
      Get-File "https://www.7-zip.org/$($m.Value)" $dl
      $target = Join-Path $EngDir '7-Zip'
      Start-Process $dl -ArgumentList '/S',"/D=$target" -Wait
      if (Test-Path "$target\7z.exe") { Ok "  installed: $target\7z.exe"; return "$target\7z.exe" }
    }
  } catch { Warn "  7-Zip auto-install failed: $_" }
  Warn '  Could not auto-install 7-Zip (install manually from https://7-zip.org). Folder scans still work without it.'
  return $null
}

function Install-ClamAV {
  Info 'ClamAV (portable, no admin):'
  $dest = Join-Path $EngDir 'ClamAV'
  $clamExe = Get-ChildItem $dest -Recurse -Filter 'clamscan.exe' -ErrorAction SilentlyContinue | Select-Object -First 1
  if (-not $clamExe) {
    try {
      Ensure-Tls
      $rel = Invoke-RestMethod 'https://api.github.com/repos/Cisco-Talos/clamav/releases/latest' -Headers @{ 'User-Agent'='scan-av' }
      $asset = $rel.assets | Where-Object { $_.name -match 'win\.x64\.zip$' } | Select-Object -First 1
      if (-not $asset) { throw 'no win.x64.zip asset in latest release' }
      $zip = Join-Path $env:TEMP $asset.name
      Get-File $asset.browser_download_url $zip
      New-Item -ItemType Directory -Force $dest | Out-Null
      Expand-Archive -Path $zip -DestinationPath $dest -Force
      $clamExe = Get-ChildItem $dest -Recurse -Filter 'clamscan.exe' -ErrorAction SilentlyContinue | Select-Object -First 1
    } catch { Warn "  ClamAV auto-install failed: $_"; return $null }
  }
  if (-not $clamExe) { Warn '  clamscan.exe not found after extract.'; return $null }
  $bin = Split-Path $clamExe.FullName
  Ok "  installed: $($clamExe.FullName)"
  $fresh = Join-Path $bin 'freshclam.exe'
  $dbDir = Join-Path $bin 'database'; New-Item -ItemType Directory -Force $dbDir | Out-Null
  $fcConf = Join-Path $bin 'freshclam.conf'
  if (-not (Test-Path $fcConf)) { "DatabaseDirectory $dbDir`nDatabaseMirror database.clamav.net" | Set-Content $fcConf -Encoding ASCII }
  $freshPath = $null
  if (Test-Path $fresh) {
    $freshPath = $fresh
    Info '  downloading definitions (freshclam, ~300 MB first time)...'
    $frc = Invoke-Native -Exe $fresh -Arguments @("--config-file=$fcConf", "--datadir=$dbDir") -Log (Join-Path $LogDir 'freshclam_install.log')
    if ($frc -eq 0) { Ok '  definitions updated.' } else { Warn "  freshclam exit $frc (see logs\freshclam_install.log; you can run it later)." }
  }
  return [pscustomobject]@{ clamscan=$clamExe.FullName; freshclam=$freshPath }
}

function Install-Emsisoft {
  param($SevenZip)
  Info 'Emsisoft Emergency Kit (FREE for private/personal use only):'
  $dest = Join-Path $EngDir 'EEK'
  $a2 = Get-ChildItem $dest -Recurse -Filter 'a2cmd.exe' -ErrorAction SilentlyContinue | Select-Object -First 1
  if ($a2) { Ok "  already present: $($a2.FullName)"; return $a2.FullName }
  $sfx = Join-Path $env:TEMP 'EmsisoftEmergencyKit.exe'
  try { Get-File 'https://dl.emsisoft.com/EmsisoftEmergencyKit.exe' $sfx } catch { Warn "  download failed: $_"; return $null }
  New-Item -ItemType Directory -Force $dest | Out-Null
  $extracted = $false
  if ($SevenZip) { $null = Invoke-Native -Exe $SevenZip -Arguments @('x', $sfx, "-o$dest", '-y'); if (Test-Path $dest) { $extracted = $true } }
  if (-not $extracted) {
    Warn '  Could not silently extract (7-Zip needed). Launching the EEK extractor - accept the default folder, then re-run: scan-av -Configure'
    Start-Process $sfx; return $null
  }
  $a2 = Get-ChildItem $dest -Recurse -Filter 'a2cmd.exe' -ErrorAction SilentlyContinue | Select-Object -First 1
  if (-not $a2) { Warn '  a2cmd.exe not found after extraction; run the EEK GUI once, then: scan-av -Configure'; return $null }
  Ok "  installed: $($a2.FullName)"
  Info '  updating Emsisoft definitions (large first-time download)...'
  $urc = Invoke-Native -Exe $a2.FullName -Arguments @('/update') -Log (Join-Path $LogDir 'a2update_install.log')
  if ($urc -eq 0) { Ok '  definitions updated.' } else { Warn "  a2cmd /update exit $urc (run later)." }
  return $a2.FullName
}

function Install-Engines {
  Sec 'scan-av  -  auto-install engines'
  New-Item -ItemType Directory -Force -Path $EngDir, $LogDir | Out-Null
  Warn 'This downloads 7-Zip, ClamAV and Emsisoft Emergency Kit plus their signature'
  Warn 'databases - several hundred MB total, needs internet. EEK is free for PRIVATE use only.'
  if (-not (AskYesNo 'Proceed with download & install?' $true)) { Warn 'Skipped engine install.'; return }
  $sz   = Install-SevenZip
  $clam = Install-ClamAV
  $a2   = Install-Emsisoft -SevenZip $sz
  Write-Host ''
  Ok 'Engine install finished. Wiring up configuration...'
  Write-Host ''
  $pre = @{}
  if ($sz)   { $pre.seven = $sz }
  if ($clam) { $pre.clam = $clam.clamscan; if ($clam.freshclam) { $pre.fresh = $clam.freshclam } }
  if ($a2)   { $pre.a2 = $a2 }
  Invoke-Configure -Pre $pre | Out-Null
}

# ---------------------------------------------------------------- app icon
# Writes the embedded shield icon to AppDir as icon.png (WPF window/taskbar) and
# icon.ico (shortcut). The .ico just wraps the PNG (Vista+ supports PNG icons).
function Ensure-AppIcon {
  $pngPath = Join-Path $AppDir 'icon.png'; $icoPath = Join-Path $AppDir 'icon.ico'
  if (-not $script:ScanAvIconB64) { return $null }
  try {
    $png = [Convert]::FromBase64String($script:ScanAvIconB64)
    [System.IO.File]::WriteAllBytes($pngPath, $png)
    $ms = New-Object System.IO.MemoryStream; $bw = New-Object System.IO.BinaryWriter($ms)
    $bw.Write([UInt16]0); $bw.Write([UInt16]1); $bw.Write([UInt16]1)                 # ICONDIR
    $bw.Write([Byte]0); $bw.Write([Byte]0); $bw.Write([Byte]0); $bw.Write([Byte]0)   # w=256,h=256,colors,reserved
    $bw.Write([UInt16]1); $bw.Write([UInt16]32)                                       # planes, bpp
    $bw.Write([UInt32]$png.Length); $bw.Write([UInt32]22)                             # size, offset
    $bw.Write($png); $bw.Flush()
    [System.IO.File]::WriteAllBytes($icoPath, $ms.ToArray())
    $bw.Dispose(); $ms.Dispose()
    return [pscustomobject]@{ png = $pngPath; ico = $icoPath }
  } catch { return $null }
}

# ---------------------------------------------------------------- standalone launcher
# Builds a tiny Windows EXE wrapper so launchers see ScanAV.exe instead of
# powershell.exe. The scanner/UI still lives in scan-av.ps1.
function Ensure-StandaloneLauncher {
  param([switch]$Quiet, [string]$LauncherVersion = $ScanAvVersion)
  try { New-Item -ItemType Directory -Force -Path $AppDir | Out-Null } catch {}
  $ps1 = Join-Path $AppDir 'scan-av.ps1'
  if (-not (Test-Path $ps1)) {
    if (-not $Quiet) { Warn "scan-av.ps1 not found in $AppDir - run -Install first." }
    return $null
  }

  $launcher = Join-Path $AppDir 'ScanAV.exe'
  $needsBuild = $true
  if (Test-Path $launcher) {
    try {
      $exe = Get-Item -LiteralPath $launcher -ErrorAction Stop
      $src = Get-Item -LiteralPath $ps1 -ErrorAction Stop
      $fv = [Diagnostics.FileVersionInfo]::GetVersionInfo($launcher)
      $needsBuild = (($fv.ProductVersion -ne $LauncherVersion) -or ($exe.LastWriteTimeUtc -lt $src.LastWriteTimeUtc))
    } catch { $needsBuild = $true }
  }
  if (-not $needsBuild) { return $launcher }

  $icon = Ensure-AppIcon
  $tmp = Join-Path $env:TEMP ('ScanAV_' + [Guid]::NewGuid().ToString('N') + '.exe')
  $typeName = 'ScanAVLauncher_' + [Guid]::NewGuid().ToString('N')
  $versionLiteral = $LauncherVersion -replace '\\','\\' -replace '"','\"'
  $source = @"
using System;
using System.Diagnostics;
using System.IO;
using System.Reflection;
using System.Windows.Forms;

[assembly: AssemblyTitle("ScanAV")]
[assembly: AssemblyDescription("ScanAV standalone launcher")]
[assembly: AssemblyCompany("dggomes")]
[assembly: AssemblyProduct("ScanAV")]
[assembly: AssemblyVersion("1.0.0.0")]
[assembly: AssemblyFileVersion("1.0.0.0")]
[assembly: AssemblyInformationalVersion("$versionLiteral")]

public static class $typeName
{
    private static string Quote(string value)
    {
        if (String.IsNullOrEmpty(value)) return "\"\"";
        return "\"" + value.Replace("\"", "\\\"") + "\"";
    }

    [STAThread]
    public static int Main(string[] args)
    {
        try
        {
            string appDir = AppDomain.CurrentDomain.BaseDirectory.TrimEnd(Path.DirectorySeparatorChar, Path.AltDirectorySeparatorChar);
            string ps1 = Path.Combine(appDir, "scan-av.ps1");
            if (!File.Exists(ps1))
            {
                MessageBox.Show("scan-av.ps1 was not found next to ScanAV.exe.", "ScanAV", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return 2;
            }

            string powerShell = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.System), @"WindowsPowerShell\v1.0\powershell.exe");
            if (!File.Exists(powerShell)) powerShell = "powershell.exe";

            string arguments = "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File " + Quote(ps1) + " -Gui";
            foreach (string arg in args) arguments += " " + Quote(arg);

            ProcessStartInfo psi = new ProcessStartInfo();
            psi.FileName = powerShell;
            psi.Arguments = arguments;
            psi.WorkingDirectory = appDir;
            psi.UseShellExecute = false;
            Process child = Process.Start(psi);
            if (child == null) return 1;
            child.WaitForExit();
            return child.ExitCode;
        }
        catch (Exception ex)
        {
            MessageBox.Show(ex.Message, "ScanAV launch failed", MessageBoxButtons.OK, MessageBoxIcon.Error);
            return 1;
        }
    }
}
"@
  try {
    $compilerOptions = @()
    if ($icon -and (Test-Path $icon.ico)) { $compilerOptions += ('/win32icon:"{0}"' -f $icon.ico) }
    $addTypeArgs = @{
      TypeDefinition = $source
      OutputAssembly = $tmp
      OutputType = 'WindowsApplication'
      ReferencedAssemblies = @('System.dll','System.Windows.Forms.dll')
      ErrorAction = 'Stop'
    }
    if ($compilerOptions.Count) { $addTypeArgs.CompilerOptions = ($compilerOptions -join ' ') }
    $compileErr = $null
    try {
      Add-Type @addTypeArgs
    } catch {
      $compileErr = $_
    }
    if (-not (Test-Path $tmp)) {
      $csPath = Join-Path $env:TEMP ('ScanAV_' + [Guid]::NewGuid().ToString('N') + '.cs')
      Set-Content -Path $csPath -Value $source -Encoding UTF8
      $cscCandidates = @()
      try { $cscCandidates += (Join-Path ([Runtime.InteropServices.RuntimeEnvironment]::GetRuntimeDirectory()) 'csc.exe') } catch {}
      $cscCandidates += @(
        (Join-Path $env:WINDIR 'Microsoft.NET\Framework64\v4.0.30319\csc.exe'),
        (Join-Path $env:WINDIR 'Microsoft.NET\Framework\v4.0.30319\csc.exe')
      )
      $csc = @($cscCandidates | Where-Object { $_ -and (Test-Path $_) } | Select-Object -First 1)
      if (-not $csc) { throw "Could not find a C# compiler for ScanAV.exe. Add-Type error: $compileErr" }
      $cscArgs = @('/nologo','/target:winexe',('/out:{0}' -f $tmp),'/reference:System.dll','/reference:System.Windows.Forms.dll')
      if ($icon -and (Test-Path $icon.ico)) { $cscArgs += ('/win32icon:{0}' -f $icon.ico) }
      $cscArgs += $csPath
      $cscOut = & $csc @cscArgs 2>&1
      $cscRc = $LASTEXITCODE
      Remove-Item $csPath -Force -ErrorAction SilentlyContinue
      if ($cscRc -ne 0 -or -not (Test-Path $tmp)) {
        throw "Could not compile ScanAV.exe. Add-Type error: $compileErr`nC# compiler output:`n$($cscOut -join "`n")"
      }
    }
    try {
      Move-Item -Path $tmp -Destination $launcher -Force -ErrorAction Stop
    } catch {
      $pending = Join-Path $AppDir 'ScanAV.exe.pending'
      Move-Item -Path $tmp -Destination $pending -Force -ErrorAction Stop
      $waitPid = $PID
      try {
        $thisProc = Get-CimInstance Win32_Process -Filter "ProcessId=$PID" -ErrorAction Stop
        if ($thisProc.ParentProcessId) {
          $parentProc = Get-Process -Id ([int]$thisProc.ParentProcessId) -ErrorAction SilentlyContinue
          if ($parentProc -and $parentProc.ProcessName -ieq 'ScanAV') { $waitPid = [int]$thisProc.ParentProcessId }
        }
      } catch {}
      function local:Q([string]$s) { "'" + ($s -replace "'", "''") + "'" }
      $replaceCmd = "try { Wait-Process -Id $waitPid -ErrorAction SilentlyContinue } catch {}; Start-Sleep -Milliseconds 500; Move-Item -LiteralPath $(Q $pending) -Destination $(Q $launcher) -Force"
      $pw = Join-Path $PSHOME 'powershell.exe'
      Start-Process -FilePath $pw -ArgumentList @('-NoProfile','-ExecutionPolicy','Bypass','-WindowStyle','Hidden','-Command',$replaceCmd) -WindowStyle Hidden -ErrorAction SilentlyContinue | Out-Null
      $script:StandaloneLauncherPending = $true
      if (-not $Quiet) { Warn 'Standalone launcher is currently running; it will be refreshed after ScanAV closes.' }
      if (Test-Path $launcher) { return $launcher }
      return $null
    }
    $script:StandaloneLauncherPending = $false
    if (-not $Quiet) { Ok "Standalone launcher installed: $launcher" }
    return $launcher
  } catch {
    Remove-Item $tmp -Force -ErrorAction SilentlyContinue
    if (-not $Quiet) { Warn "Could not build standalone launcher: $_" }
    return $null
  }
}

# ---------------------------------------------------------------- desktop shortcut
# Plain desktop shortcut that runs scan-av. -Elevated marks it "Run as administrator"
# so Emsisoft's a2cmd (which self-elevates) doesn't pop a separate UAC/cmd window on
# every run -- you approve once at launch instead of once per scan/archive.
function New-DesktopShortcut {
  param([bool]$Elevated = $true)
  $ps1 = Join-Path $AppDir 'scan-av.ps1'
  if (-not (Test-Path $ps1)) { Warn "scan-av.ps1 not found in $AppDir - run -Install first."; return }
  $icon = Ensure-AppIcon
  try {
    $lnkPath = Join-Path ([Environment]::GetFolderPath('Desktop')) 'Scan-AV.lnk'
    $ws  = New-Object -ComObject WScript.Shell
    $lnk = $ws.CreateShortcut($lnkPath)
    $launcher = Ensure-StandaloneLauncher
    if (-not ($launcher -and (Test-Path $launcher))) {
      Warn 'Desktop shortcut not changed: ScanAV.exe could not be created.'
      Warn "Expected launcher path: $AppDir\ScanAV.exe"
      return
    }
    $lnk.TargetPath = $launcher
    $lnk.Arguments  = ''
    $lnk.WorkingDirectory = $AppDir
    $lnk.Description       = 'Open the scan-av app'
    $lnk.IconLocation     = $(if ($icon -and (Test-Path $icon.ico)) { $icon.ico } else { "$launcher,0" })
    $lnk.Save()
    if ($Elevated) {
      # set the "Run as administrator" bit (byte 0x15, flag 0x20) in the .lnk
      $b = [IO.File]::ReadAllBytes($lnkPath); $b[0x15] = $b[0x15] -bor 0x20
      [IO.File]::WriteAllBytes($lnkPath, $b)
    }
    Ok "Desktop shortcut created: $lnkPath"
    Info "Shortcut target: $launcher"
    if ($Elevated) { Info 'It runs elevated -> one UAC prompt at launch, no per-scan Emsisoft prompts.' }
  } catch { Warn "Could not create desktop shortcut: $_" }
}

# Zero-prompt option: an elevated Scheduled Task (RunLevel Highest) plus a desktop
# shortcut that triggers it. Registering the task needs admin ONCE; after that the
# task -- and therefore a2cmd -- runs elevated with no UAC prompt at all.
function Register-NoPromptTask {
  $ps1 = Join-Path $AppDir 'scan-av.ps1'
  if (-not (Test-Path $ps1)) { Warn "scan-av.ps1 not found in $AppDir - run -Install first."; return }
  try {
    $taskCmd   = "& '{0}'; Write-Host ''; Read-Host 'Finished - press Enter to close this window' | Out-Null" -f ($ps1 -replace "'", "''")
    $taskEnc   = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($taskCmd))
    $action    = New-ScheduledTaskAction -Execute 'powershell.exe' -Argument "-NoProfile -ExecutionPolicy Bypass -EncodedCommand $taskEnc"
    $principal = New-ScheduledTaskPrincipal -UserId "$env:USERNAME" -LogonType Interactive -RunLevel Highest
    $settings  = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -ExecutionTimeLimit ([TimeSpan]::Zero)
    Register-ScheduledTask -TaskName 'ScanAV' -Action $action -Principal $principal -Settings $settings -Force -ErrorAction Stop | Out-Null
    Ok "Elevated scheduled task 'ScanAV' registered (no UAC prompt when run)."
    $lnkPath = Join-Path ([Environment]::GetFolderPath('Desktop')) 'Scan-AV.lnk'
    $ws  = New-Object -ComObject WScript.Shell
    $lnk = $ws.CreateShortcut($lnkPath)
    $lnk.TargetPath   = Join-Path $env:SystemRoot 'System32\schtasks.exe'
    $lnk.Arguments    = '/run /tn ScanAV'
    $lnk.IconLocation = 'imageres.dll,79'
    $lnk.Description  = 'Run scan-av (elevated, no prompt)'
    $lnk.Save()
    Ok "Desktop shortcut now triggers the task (zero prompts): $lnkPath"
  } catch {
    Warn "Could not register the elevated task: $_"
    Warn 'Run PowerShell **as Administrator** once, then: scan-av -NoPromptShortcut'
  }
}

# ---------------------------------------------------------------- explorer menu
# Adds a per-user (HKCU, no admin) "Antivirus Scan" entry to the folder right-click
# menu. Selecting a folder and clicking it scans just that folder. On Windows 11 it
# appears under "Show more options".
function Install-ContextMenu {
  $ps1 = Join-Path $AppDir 'scan-av.ps1'
  if (-not (Test-Path $ps1)) { Warn "scan-av.ps1 not found in $AppDir - run -Install first."; return }
  $pw = Join-Path $PSHOME 'powershell.exe'
  $verb = 'AntivirusScan'; $label = 'Antivirus Scan'
  # launch hidden; scan-av -ContextScan then self-elevates into a visible window
  $cmdSel = '"{0}" -NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File "{1}" -ContextScan "%1"' -f $pw, $ps1
  $cmdBg  = '"{0}" -NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -File "{1}" -ContextScan "%V"' -f $pw, $ps1
  $ico = Ensure-AppIcon; $iconVal = if ($ico -and (Test-Path $ico.ico)) { $ico.ico } else { $pw }
  $targets = @(
    @{ root = "HKCU:\Software\Classes\Directory\shell\$verb";            cmd = $cmdSel },  # folder selected
    @{ root = "HKCU:\Software\Classes\Directory\Background\shell\$verb";  cmd = $cmdBg  }   # inside a folder
  )
  # scannable FILE types get the entry too (archives + executables), via
  # SystemFileAssociations so it doesn't hijack the whole '*' file class
  $script:CtxFileExts = @('.rar','.7z','.zip','.zipx','.001','.tar','.gz','.cab','.iso','.exe','.msi','.dll')
  foreach ($ext in $script:CtxFileExts) {
    $targets += @{ root = "HKCU:\Software\Classes\SystemFileAssociations\$ext\shell\$verb"; cmd = $cmdSel }
  }
  foreach ($t in $targets) {
    try {
      New-Item -Path $t.root -Force | Out-Null
      Set-ItemProperty -Path $t.root -Name '(Default)' -Value $label
      Set-ItemProperty -Path $t.root -Name 'Icon' -Value $iconVal
      New-Item -Path "$($t.root)\command" -Force | Out-Null
      Set-ItemProperty -Path "$($t.root)\command" -Name '(Default)' -Value $t.cmd
    } catch { Warn "  context-menu registry write failed: $_" }
  }
  Ok "Added 'Antivirus Scan' to the right-click menu (folders + archives/executables)."
  Info "On Windows 11 it's under 'Show more options' (Shift+F10 shows it directly)."
}
function Remove-ContextMenu {
  $roots = @("HKCU:\Software\Classes\Directory\shell\AntivirusScan","HKCU:\Software\Classes\Directory\Background\shell\AntivirusScan")
  foreach ($ext in @('.rar','.7z','.zip','.zipx','.001','.tar','.gz','.cab','.iso','.exe','.msi','.dll')) {
    $roots += "HKCU:\Software\Classes\SystemFileAssociations\$ext\shell\AntivirusScan"
  }
  foreach ($r in $roots) {
    if (Test-Path $r) { Remove-Item $r -Recurse -Force -ErrorAction SilentlyContinue }
  }
  Ok "Removed the 'Antivirus Scan' right-click menu entries."
}

# ---------------------------------------------------------------- install
function Invoke-Install {
  param([switch]$WithEngines)
  Sec 'scan-av  -  install'
  New-Item -ItemType Directory -Force -Path $AppDir, $LogDir | Out-Null
  $dest = Join-Path $AppDir 'scan-av.ps1'
  if ($PSCommandPath -and ((Resolve-Path $PSCommandPath).Path -ne (Join-Path $AppDir 'scan-av.ps1'))) {
    Copy-Item -Path $PSCommandPath -Destination $dest -Force
  }
  # convenience wrapper so it runs from cmd / double-click, bypassing exec policy
  $cmd = @"
@echo off
powershell -NoProfile -ExecutionPolicy Bypass -File "%~dp0scan-av.ps1" %*
"@
  Set-Content -Path (Join-Path $AppDir 'scan-av.cmd') -Value $cmd -Encoding ASCII

  # add AppDir to user PATH (persists for future terminals)
  $userPath = [Environment]::GetEnvironmentVariable('Path','User')
  if ($userPath -notlike "*$AppDir*") {
    [Environment]::SetEnvironmentVariable('Path', "$userPath;$AppDir", 'User')
    Ok "Added to PATH (User): $AppDir"
  } else { Info "Already on PATH: $AppDir" }

  # KEY FIX: also drop a launcher in %LOCALAPPDATA%\Microsoft\WindowsApps, which is
  # already on the default user PATH on Win10/11 -> 'scan-av' works in any NEW
  # terminal with no PATH-refresh dance (Windows Terminal caches PATH at launch).
  $shimDir = Join-Path $env:LOCALAPPDATA 'Microsoft\WindowsApps'
  $shimMsg = $null
  if (Test-Path $shimDir) {
    $shimCmd = @"
@echo off
powershell -NoProfile -ExecutionPolicy Bypass -File "$AppDir\scan-av.ps1" %*
"@
    try { Set-Content -Path (Join-Path $shimDir 'scan-av.cmd') -Value $shimCmd -Encoding ASCII -ErrorAction Stop
          $shimMsg = "Launcher placed on default PATH: $shimDir\scan-av.cmd" } catch { $shimMsg = $null }
  }
  if ($shimMsg) { Ok $shimMsg }

  # make 'scan-av' usable in THIS session too (User PATH only affects new terminals)
  if ($env:Path -notlike "*$AppDir*") { $env:Path += ";$AppDir" }
  Info "You can run 'scan-av' here now, and in any newly-opened terminal."
  Ok "Installed to $AppDir"
  Ensure-StandaloneLauncher | Out-Null
  Write-Host ''
  # desktop shortcut (elevated, so Emsisoft doesn't prompt per scan)
  New-DesktopShortcut -Elevated $true
  Info "For ZERO UAC prompts, run PowerShell as Admin once: scan-av -NoPromptShortcut"
  Write-Host ''
  if (AskYesNo "Add 'Antivirus Scan' to the folder right-click menu?" $true) { Install-ContextMenu }
  Write-Host ''
  if ($WithEngines -or (AskYesNo 'Auto-download & install ClamAV + Emsisoft now?' $true)) {
    Install-Engines
  } else {
    Invoke-Configure | Out-Null
  }
}

# ---------------------------------------------------------------- engines
# Run a native exe WITHOUT letting its stderr abort the script. With
# $ErrorActionPreference='Stop', PowerShell turns any native-command stderr line
# (e.g. clamscan's skippable "Can't fstat descriptor" warnings) into a terminating
# NativeCommandError. We localize EAP=Continue and capture all streams to a log.
# options.engineTimeoutMinutes (default 30): a hung engine must not freeze the
# whole scan forever - on timeout the process tree is killed and the unit is
# reported as an error (never as clean).
function Get-EngineTimeout($Cfg) {
  $m = 30
  try { if ($Cfg -and $Cfg.options.PSObject.Properties['engineTimeoutMinutes'] -and [int]$Cfg.options.engineTimeoutMinutes -gt 0) { $m = [int]$Cfg.options.engineTimeoutMinutes } } catch {}
  return $m * 60
}

function Invoke-Native {
  # $Live = $true streams output to the console (Tee-Object) AND logs it; otherwise
  # output is captured silently to $Log. Out-Host consumes the pipeline so the streamed
  # lines never leak into the function's return value ($LASTEXITCODE).
  # $TimeoutSec > 0 (non-Live only) kills the process tree after that long and
  # returns 124 so callers report an error instead of hanging the scan.
  param([Parameter(Mandatory)][string]$Exe, [string[]]$Arguments = @(), [string]$Log, [bool]$Live = $false, [int]$TimeoutSec = 0)
  if ($TimeoutSec -gt 0 -and -not $Live) {
    $psi = New-Object System.Diagnostics.ProcessStartInfo
    $psi.FileName = $Exe
    $psi.Arguments = (($Arguments | ForEach-Object { if ($_ -match '[\s"]') { '"' + ($_ -replace '"','\"') + '"' } else { $_ } }) -join ' ')
    $psi.UseShellExecute = $false; $psi.RedirectStandardOutput = $true; $psi.RedirectStandardError = $true; $psi.CreateNoWindow = $true
    try { $p = [System.Diagnostics.Process]::Start($psi) }
    catch { if ($Log) { "scan-av: failed to start $Exe : $_" | Out-File $Log -Encoding UTF8 }; return 999 }
    $outT = $p.StandardOutput.ReadToEndAsync(); $errT = $p.StandardError.ReadToEndAsync()
    if (-not $p.WaitForExit($TimeoutSec * 1000)) {
      try { Start-Process taskkill -ArgumentList "/PID $($p.Id) /T /F" -WindowStyle Hidden -Wait } catch {}
      if ($Log) { "scan-av: '$Exe' TIMED OUT after $TimeoutSec s - process killed. Partial output above/none." | Out-File $Log -Encoding UTF8 }
      return 124
    }
    $p.WaitForExit()   # flush async output
    if ($Log) { ($outT.Result + "`r`n" + $errT.Result) | Out-File $Log -Encoding UTF8 }
    return $p.ExitCode
  }
  $prev = $ErrorActionPreference
  $ErrorActionPreference = 'Continue'
  try {
    # Stringify the merged stream so native stderr shows as plain text instead of
    # red PowerShell NativeCommandError blocks (clamscan's per-file "Can't fstat"
    # warnings are not fatal and shouldn't look like a script error).
    if ($Live -and $Log) { & $Exe @Arguments 2>&1 | ForEach-Object { "$_" } | Tee-Object -FilePath $Log | ForEach-Object { Write-Host $_ } }
    elseif ($Live)       { & $Exe @Arguments 2>&1 | ForEach-Object { "$_" } | ForEach-Object { Write-Host $_ } }
    elseif ($Log)        { & $Exe @Arguments 2>&1 | ForEach-Object { "$_" } | Out-File -FilePath $Log -Encoding UTF8 }
    else                 { & $Exe @Arguments 2>&1 | Out-Null }
  } catch { if ($Log) { "scan-av: native call raised: $_" | Out-File -FilePath $Log -Append -Encoding UTF8 } }
  finally { $ErrorActionPreference = $prev }
  return $LASTEXITCODE
}

function Run-ClamAV {
  param([string]$Target, [string]$Log, $Cfg)
  $a = @('-r', "--max-filesize=$($Cfg.options.maxFileSizeMB)M",
              "--max-scansize=$($Cfg.options.maxScanSizeMB)M",
              '--alert-exceeds-max=yes', $Target)
  $rc = Invoke-Native -Exe $Cfg.tools.clamscan -Arguments $a -Log $Log -Live $script:LiveScan -TimeoutSec (Get-EngineTimeout $Cfg)
  $lines = Get-Content $Log -ErrorAction SilentlyContinue
  $hits  = @($lines | Where-Object { $_ -match ' FOUND$' -and $_ -notmatch 'Heuristics\.Limits\.Exceeded' })
  $skips = @($lines | Where-Object { $_ -match 'Heuristics\.Limits\.Exceeded' })
  # files clamscan could not read/scan (>2GiB, locked, path issues) - reported as
  # errors, NOT clean. e.g. "Can't get file status ERROR" / "Can't open file ERROR".
  $errs  = @($lines | Where-Object { $_ -match "Can't (get file status|open file|read)" -or $_ -match ': ERROR$' })
  [pscustomobject]@{ Engine='ClamAV'; Rc=$rc; Hits=$hits; Skipped=$skips.Count; Errors=$errs
    Scanned = ([regex]::Match(($lines -join "`n"),'Scanned files:\s*(\d+)').Groups[1].Value) }
}

# Attribute one batch clamscan log back to the target each per-file line belongs
# to (longest-prefix match). Pure function so it's unit-testable. clamscan prints
# one line per file ("path: OK" / "path: <Sig> FOUND" / "path: ... ERROR"), so a
# per-target scanned count can be derived even though the summary total is global.
function ConvertFrom-ClamBatchLog {
  param([string[]]$Lines, [string[]]$Targets, [int]$Rc, [string]$LogFile = '')
  $map = [ordered]@{}
  foreach ($t in $Targets) { $map[$t] = [pscustomobject]@{ Engine='ClamAV'; Rc=$Rc; Hits=@(); Skipped=0; Errors=@(); Scanned='0'; LogFile=$LogFile } }
  $sorted = @($Targets | Sort-Object Length -Descending)
  $counts = @{}
  foreach ($ln in @($Lines)) {
    if ($ln -notmatch '^([A-Za-z]:\\[^:]*|\\\\[^:]*):\s') { continue }   # per-file lines only
    $lp = $matches[1]
    $owner = $null
    foreach ($t in $sorted) { $tt = $t.TrimEnd('\'); if ($lp -eq $tt -or $lp.StartsWith($tt + '\')) { $owner = $t; break } }
    if (-not $owner) { continue }
    $r = $map[$owner]
    if ($ln -match 'Heuristics\.Limits\.Exceeded' -and $ln -match ' FOUND$') { $r.Skipped++; $counts[$owner]++ }
    elseif ($ln -match ' FOUND$') { $r.Hits += $ln; $counts[$owner]++ }
    elseif ($ln -match "Can't (get file status|open file|read)" -or $ln -match ': ERROR$') { $r.Errors += $ln }
    elseif ($ln -match ': (OK|Empty file)$') { $counts[$owner]++ }
  }
  foreach ($t in $Targets) { $map[$t].Scanned = [string][int]$counts[$t] }
  return $map
}

# One clamscan invocation over MANY units: the ~3.6M-signature database loads once
# instead of once per unit (the single biggest cost of multi-folder scans).
function Invoke-ClamBatch {
  param([string[]]$Targets, $Cfg, [string]$Log)
  $a = @('-r', "--max-filesize=$($Cfg.options.maxFileSizeMB)M",
              "--max-scansize=$($Cfg.options.maxScanSizeMB)M",
              '--alert-exceeds-max=yes') + $Targets
  $rc = Invoke-Native -Exe $Cfg.tools.clamscan -Arguments $a -Log $Log -Live $script:LiveScan -TimeoutSec (Get-EngineTimeout $Cfg)
  $lines = @(Get-Content $Log -ErrorAction SilentlyContinue)
  return (ConvertFrom-ClamBatchLog -Lines $lines -Targets $Targets -Rc ([int]$rc) -LogFile $Log)
}

# a2cmd needs its path values quoted as /f="path". PowerShell's native-argument
# passing won't reliably produce that for spaced paths (the value gets split and
# a2cmd reports "no objects to scan"). Invoke it through ProcessStartInfo with an
# explicit, correctly-quoted command line instead. Also avoids the stderr issue.
function Invoke-A2cmd {
  param([string]$Exe, [string]$Target, [string]$Log, [bool]$Live = $false, [int]$TimeoutSec = 0)
  $argStr = '/f="{0}" /s /a /pup /log="{1}" /loglevel=detailed' -f $Target, $Log
  $psi = New-Object System.Diagnostics.ProcessStartInfo
  $psi.FileName = $Exe
  $psi.Arguments = $argStr
  $psi.UseShellExecute = $false
  $psi.RedirectStandardOutput = $true
  $psi.RedirectStandardError = $true
  $psi.CreateNoWindow = $true
  $console = Join-Path $LogDir '_a2cmd_console.txt'
  try { $p = [System.Diagnostics.Process]::Start($psi) }
  catch { "scan-av: failed to start a2cmd: $_" | Out-File $console -Encoding UTF8; return 999 }
  $outT = $p.StandardOutput.ReadToEndAsync()   # async read avoids stdout/stderr deadlock
  $errT = $p.StandardError.ReadToEndAsync()
  if ($TimeoutSec -gt 0 -and -not $p.WaitForExit($TimeoutSec * 1000)) {
    try { Start-Process taskkill -ArgumentList "/PID $($p.Id) /T /F" -WindowStyle Hidden -Wait } catch {}
    "scan-av: a2cmd TIMED OUT after $TimeoutSec s - process killed." | Out-File $console -Encoding UTF8
    return 124
  }
  $p.WaitForExit()
  $txt = ($outT.Result + "`r`n" + $errT.Result)
  $txt | Out-File -FilePath $console -Encoding UTF8
  if ($Live) { Write-Host $txt }
  return $p.ExitCode
}

function Run-Emsisoft {
  param([string]$Target, [string]$Log, $Cfg)
  $rc = Invoke-A2cmd -Exe $Cfg.tools.a2cmd -Target $Target -Log $Log -Live $script:LiveScan -TimeoutSec (Get-EngineTimeout $Cfg)
  $lines = Get-Content $Log -ErrorAction SilentlyContinue
  # a2cmd detection lines contain 'detected:'; summary has 'Scanned'/'Detected'
  $hits = @($lines | Where-Object { $_ -match 'detected:' -and $_ -notmatch '^\s*Detected:' })
  $scanned  = ([regex]::Match(($lines -join "`n"),'Scanned:?\s+(\d+)').Groups[1].Value)
  [pscustomobject]@{ Engine='Emsisoft'; Rc=$rc; Hits=$hits; Skipped=0; Scanned=$scanned }
}

# Microsoft Defender via MpCmdRun. -ScanType 3 is a custom scan of -File <path>;
# -DisableRemediation makes it report-only (never quarantines/deletes the file).
# Exit code 2 = threats found, 0 = clean. MpCmdRun's text output is terse, so we
# parse "found N threats" and any "Threat : <name>" lines for the verdict.
function Run-Defender {
  param([string]$Target, [string]$Log, $Cfg)
  $a = @('-Scan', '-ScanType', '3', '-File', $Target, '-DisableRemediation')
  $rc = Invoke-Native -Exe $Cfg.tools.defender -Arguments $a -Log $Log -Live $script:LiveScan -TimeoutSec (Get-EngineTimeout $Cfg)
  $lines = Get-Content $Log -ErrorAction SilentlyContinue
  $joined = ($lines -join "`n")
  $found  = [int]([regex]::Match($joined,'found\s+(\d+)\s+threat').Groups[1].Value)
  $names  = @($lines | Where-Object { $_ -match '^\s*Threat\s*:' } | ForEach-Object { ($_ -replace '^\s*Threat\s*:\s*','').Trim() } | Where-Object { $_ })
  $hits = @()
  if ($rc -eq 2 -or $found -gt 0) {
    $hits = if ($names.Count) { $names } else { @("Microsoft Defender flagged $([Math]::Max($found,1)) threat(s) - see log") }
  }
  # Threat resource lines ("file:C:\path" / "file : C:\path"), needed for the
  # VirusTotal lookup - Defender's hit lines are threat NAMES, not file paths.
  # Archive members show as "container->member"; hash the container we have on disk.
  $paths = @($lines | ForEach-Object { if ($_ -match '(?i)\bfile\s*:\s*(.+?)(->.*)?\s*$') { $matches[1].Trim() } } | Where-Object { $_ })
  # Defender doesn't emit a scanned-file count for -File scans; derive one so a
  # clean run reports as clean (not as a "no result" error).
  $cnt = if (Test-Path -LiteralPath $Target -PathType Container) { @(Get-ChildItem -LiteralPath $Target -Recurse -File -ErrorAction SilentlyContinue).Count } else { 1 }
  $scanned = if ($rc -eq 0 -or $rc -eq 2) { [string]([Math]::Max($cnt,1)) } else { '' }
  [pscustomobject]@{ Engine='Defender'; Rc=$rc; Hits=$hits; HitPaths=$paths; Skipped=0; Scanned=$scanned }
}

# Extract the on-disk file paths that engines flagged, from their hit log-lines.
# ClamAV:  "<path>: <Sig> FOUND"   Emsisoft: "<path> detected: <Sig>"
# Used to compute SHA-256 hashes for the optional VirusTotal lookup.
function Get-HitPaths {
  param($Results)
  $paths = New-Object System.Collections.Generic.List[string]
  foreach ($r in $Results) {
    if ($r.PSObject.Properties['HitPaths'] -and $r.Hits.Count -gt 0) {
      foreach ($hp in @($r.HitPaths)) {
        $p2 = ([string]$hp).Trim().Trim('"')
        if ($p2 -and (Test-Path -LiteralPath $p2 -PathType Leaf) -and -not $paths.Contains($p2)) { $paths.Add($p2) }
      }
    }
    foreach ($h in $r.Hits) {
      $p = $null
      if     ($h -match '^(.*?):\s+\S.*\sFOUND$') { $p = $matches[1] }
      elseif ($h -match '^(.*?)\s+detected:')     { $p = $matches[1] }
      if ($p) {
        $p = $p.Trim().Trim('"')
        if ((Test-Path -LiteralPath $p -PathType Leaf) -and -not $paths.Contains($p)) { $paths.Add($p) }
      }
    }
  }
  return $paths
}

# ---------------------------------------------------------------- virustotal
$VtCacheFile = Join-Path $AppDir 'vt-cache.json'
$script:VtReqTimes = New-Object System.Collections.Generic.List[datetime]

# Free VT keys allow 4 requests/minute - wait for a free slot before each call
# instead of firing blind and failing with 429.
function Wait-VtSlot {
  while ($true) {
    $now = [DateTime]::UtcNow
    while ($script:VtReqTimes.Count -gt 0 -and ($now - $script:VtReqTimes[0]).TotalSeconds -gt 60) { $script:VtReqTimes.RemoveAt(0) }
    if ($script:VtReqTimes.Count -lt 4) { [void]$script:VtReqTimes.Add($now); return }
    $wait = [Math]::Ceiling(61 - ($now - $script:VtReqTimes[0]).TotalSeconds)
    if ($wait -gt 0) { Info ("    (VirusTotal rate limit - waiting {0}s...)" -f $wait); Start-Sleep -Seconds $wait }
  }
}

# HTTP status of a failed Invoke-RestMethod, from the exception itself (error
# message text is localized; regex on it is a fallback only).
function Get-VtStatusCode($Err) {
  try { $c = [int]$Err.Exception.Response.StatusCode; if ($c) { return $c } } catch {}
  $m = "$Err"
  foreach ($c in 404,401,429,403,400) { if ($m -match "\b$c\b") { return $c } }
  return 0
}

function Load-VtCache {
  $h = @{}
  if (Test-Path $VtCacheFile) {
    try {
      $j = Get-Content $VtCacheFile -Raw | ConvertFrom-Json
      if ($j.entries) { foreach ($p in $j.entries.PSObject.Properties) { $h[$p.Name] = $p.Value } }
    } catch {}
  }
  return $h
}
function Save-VtCache([hashtable]$Cache) {
  $o = [ordered]@{ version = 1; entries = [ordered]@{} }
  foreach ($k in $Cache.Keys) { $o.entries[$k] = $Cache[$k] }
  try { ($o | ConvertTo-Json -Depth 4) | Set-Content -Path $VtCacheFile -Encoding UTF8 } catch {}
}

# Rate-limited VT API call; on a 429 burst error, back off once and retry.
function Invoke-VtRequest {
  param([string]$ApiKey, [string]$Uri)
  Wait-VtSlot
  try { return Invoke-RestMethod -Uri $Uri -Headers @{ 'x-apikey' = $ApiKey } -ErrorAction Stop }
  catch {
    if ((Get-VtStatusCode $_) -eq 429) {
      Info '    (VirusTotal 429 - backing off 30s and retrying...)'
      Start-Sleep -Seconds 30; Wait-VtSlot
      return Invoke-RestMethod -Uri $Uri -Headers @{ 'x-apikey' = $ApiKey } -ErrorAction Stop
    }
    throw
  }
}

# Upload a file to VirusTotal for analysis. <=32 MB posts straight to /files;
# larger files get a one-time upload URL (VT caps uploads at ~650 MB). Multipart
# is built with HttpClient because Invoke-RestMethod -Form needs PS 6+ and the
# app runs under Windows PowerShell 5.1. Returns the analysis id.
function Send-VtFile {
  param([string]$ApiKey, [string]$Path)
  Add-Type -AssemblyName System.Net.Http
  $len = (Get-Item -LiteralPath $Path).Length
  if ($len -gt 650MB) { throw "file is $([Math]::Round($len/1MB)) MB - over VirusTotal's 650 MB upload limit" }
  $uri = 'https://www.virustotal.com/api/v3/files'
  if ($len -gt 32MB) { $uri = [string](Invoke-VtRequest -ApiKey $ApiKey -Uri 'https://www.virustotal.com/api/v3/files/upload_url').data }
  Wait-VtSlot
  $client = New-Object System.Net.Http.HttpClient
  $client.Timeout = [TimeSpan]::FromMinutes(30)
  try {
    $client.DefaultRequestHeaders.Add('x-apikey', $ApiKey)
    $form = New-Object System.Net.Http.MultipartFormDataContent
    $fs = [System.IO.File]::OpenRead($Path)
    try {
      $fc = New-Object System.Net.Http.StreamContent($fs)
      $fc.Headers.ContentType = [System.Net.Http.Headers.MediaTypeHeaderValue]::Parse('application/octet-stream')
      $form.Add($fc, 'file', [System.IO.Path]::GetFileName($Path))
      $resp = $client.PostAsync($uri, $form).Result
      $txt = $resp.Content.ReadAsStringAsync().Result
      if (-not $resp.IsSuccessStatusCode) { throw "HTTP $([int]$resp.StatusCode): $txt" }
      return (ConvertFrom-Json $txt).data.id
    } finally { $fs.Dispose() }
  } finally { $client.Dispose() }
}

# Poll an analysis until it completes (new files usually take 1-5 minutes).
# Returns a stats hashtable shaped like the file-lookup stats, or $null.
function Wait-VtAnalysis {
  param([string]$ApiKey, [string]$AnalysisId, [int]$TimeoutSec = 300)
  $deadline = [DateTime]::UtcNow.AddSeconds($TimeoutSec)
  while ([DateTime]::UtcNow -lt $deadline) {
    Start-Sleep -Seconds 20
    try {
      $a = Invoke-VtRequest -ApiKey $ApiKey -Uri "https://www.virustotal.com/api/v3/analyses/$AnalysisId"
      if ($a.data.attributes.status -eq 'completed') {
        $st = $a.data.attributes.stats
        return @{ malicious = [int]$st.malicious; suspicious = [int]$st.suspicious
                  total = ([int]$st.malicious + [int]$st.suspicious + [int]$st.undetected + [int]$st.harmless + [int]$st.timeout)
                  utc = ([DateTime]::UtcNow.ToString('o')) }
      }
      Info ("    analysis status: {0} - waiting..." -f $a.data.attributes.status)
    } catch { Warn "    VirusTotal analysis poll failed: $_"; return $null }
  }
  Warn '    VirusTotal: analysis did not finish in time - check the link below in a few minutes.'
  return $null
}

# For each infected file, compute its SHA-256 and look it up on VirusTotal (API v3).
# Deduped by hash, cached for 7 days (vt-cache.json) and throttled to the free
# tier's 4 requests/minute. When options.vtUploadUnknown is enabled, files VT has
# never seen are submitted for analysis (opt-in: uploads are shared with the VT
# community). Returns one record per unique hash (Sha/File/Malicious/Suspicious/
# Total/Status) so callers can fold VT verdicts into the scan summary.
function Invoke-VtLookup {
  param([string]$ApiKey, $Paths, $Cfg = $null, [bool]$AllowPrompt = $false)
  Ensure-Tls
  $uploadOk = $false
  if ($Cfg -and $Cfg.options.PSObject.Properties['vtUploadUnknown']) { $uploadOk = [bool]$Cfg.options.vtUploadUnknown }
  $cache = Load-VtCache
  $out = @()
  $byHash = [ordered]@{}   # dedupe: the same file flagged by several engines = one lookup
  foreach ($p in $Paths) {
    try { $sha = (Get-FileHash -LiteralPath $p -Algorithm SHA256 -ErrorAction Stop).Hash.ToLower() }
    catch { Warn "  VirusTotal: cannot hash $(Split-Path $p -Leaf) ($_)"; continue }
    if (-not $byHash.Contains($sha)) { $byHash[$sha] = $p }
  }
  foreach ($sha in @($byHash.Keys)) {
    $p = $byHash[$sha]; $leaf = Split-Path $p -Leaf
    Info  ("  VirusTotal: {0}" -f $leaf)
    Info  ("    SHA-256: {0}" -f $sha)
    $rec = [pscustomobject]@{ Sha = $sha; File = $leaf; Malicious = 0; Suspicious = 0; Total = 0; Status = 'error' }
    $stats = $null
    $c = $cache[$sha]
    if ($c -and $c.utc) {
      try { if (([DateTime]::UtcNow - [DateTime]::Parse([string]$c.utc).ToUniversalTime()).TotalDays -lt 7) { $stats = $c; Info '    (cached VirusTotal result)' } } catch {}
    }
    if (-not $stats) {
      try {
        $resp = Invoke-VtRequest -ApiKey $ApiKey -Uri "https://www.virustotal.com/api/v3/files/$sha"
        $st = $resp.data.attributes.last_analysis_stats
        $stats = @{ malicious = [int]$st.malicious; suspicious = [int]$st.suspicious
                    total = ([int]$st.malicious + [int]$st.suspicious + [int]$st.undetected + [int]$st.harmless + [int]$st.timeout)
                    utc = ([DateTime]::UtcNow.ToString('o')) }
        $cache[$sha] = $stats
      } catch {
        $code = Get-VtStatusCode $_
        if ($code -eq 404) {
          Warn '    VirusTotal: hash not in VT database (file never submitted).'
          $rec.Status = 'notfound'
          if ($uploadOk) {
            $go = $true
            if ($AllowPrompt) { $go = AskYesNo ("    Upload '{0}' to VirusTotal for analysis? (it will be shared with the VT community)" -f $leaf) $true }
            if ($go) {
              try {
                Info '    uploading to VirusTotal for analysis...'
                $aid = Send-VtFile -ApiKey $ApiKey -Path $p
                $stats = Wait-VtAnalysis -ApiKey $ApiKey -AnalysisId $aid
                if ($stats) { $cache[$sha] = $stats }
              } catch { Warn "    VirusTotal upload failed: $_" }
            }
          } else {
            Info '    (enable "Upload unknown files" in Settings to submit it for analysis automatically)'
          }
        }
        elseif ($code -eq 401) { Warn '    VirusTotal: API key rejected (check it in Settings).' }
        elseif ($code -eq 429) { Warn '    VirusTotal: rate limit hit (free keys allow 4 lookups/min, 500/day).' }
        else                   { Warn "    VirusTotal lookup failed: $_" }
      }
    }
    if ($stats) {
      $malsusp = [int]$stats.malicious + [int]$stats.suspicious
      $rec.Malicious = [int]$stats.malicious; $rec.Suspicious = [int]$stats.suspicious
      $rec.Total = [int]$stats.total; $rec.Status = 'ok'
      if ($malsusp -gt 0) { Bad ("    VirusTotal: {0}/{1} engines flagged this file." -f $malsusp, $rec.Total) }
      else                { Ok  ("    VirusTotal: 0/{0} engines flagged this hash (no known detections)." -f $rec.Total) }
    }
    Info ("    https://www.virustotal.com/gui/file/{0}" -f $sha)
    $out += $rec
  }
  Save-VtCache $cache
  return $out
}

# ---------------------------------------------------------------- quarantine
# Move flagged files into an inert quarantine folder (renamed .quarantined so
# they can't run), with a sidecar .json remembering where they came from.
function Invoke-Quarantine {
  param([string[]]$Paths, [string]$Reason = '')
  New-Item -ItemType Directory -Force -Path $QuarDir | Out-Null
  $moved = @()
  foreach ($p in $Paths) {
    if (-not (Test-Path -LiteralPath $p -PathType Leaf)) { Warn "  quarantine: not found: $p"; continue }
    $dest = Join-Path $QuarDir ('{0}_{1}.quarantined' -f ([DateTime]::Now.ToString('yyyyMMdd_HHmmss')), (Split-Path $p -Leaf))
    try {
      Move-Item -LiteralPath $p -Destination $dest -Force -ErrorAction Stop
      @{ original = $p; utc = [DateTime]::UtcNow.ToString('o'); reason = $Reason } | ConvertTo-Json |
        Set-Content -LiteralPath ($dest + '.json') -Encoding UTF8
      Ok "  quarantined: $(Split-Path $p -Leaf)"
      Info "    -> $dest"
      $moved += $dest
    } catch { Warn "  quarantine failed for $p : $_" }
  }
  return $moved
}
function Show-Quarantine {
  Sec 'Quarantine'
  $items = @(Get-ChildItem $QuarDir -Filter *.quarantined -ErrorAction SilentlyContinue | Sort-Object Name)
  if (-not $items.Count) { Info '  (empty)'; return }
  foreach ($i in $items) {
    $meta = $null; try { $meta = Get-Content -LiteralPath ($i.FullName + '.json') -Raw | ConvertFrom-Json } catch {}
    Info ("  {0}   ({1:N0} KB)" -f $i.Name, [Math]::Max(1, $i.Length/1KB))
    Info ("      from: {0}" -f $(if ($meta -and $meta.original) { $meta.original } else { '(unknown)' }))
  }
  Info "  restore: scan-av -RestoreQuarantine <name-fragment>   (or 'all')"
}
function Restore-QuarantineItems {
  param([string[]]$Names)
  $items = @(Get-ChildItem $QuarDir -Filter *.quarantined -ErrorAction SilentlyContinue)
  if (-not $items.Count) { Info 'Quarantine is empty.'; return }
  foreach ($n in $Names) {
    $match = @($items | Where-Object { $n -eq 'all' -or $_.Name -like "*$n*" })
    if (-not $match.Count) { Warn "no quarantined item matches '$n'"; continue }
    foreach ($i in $match) {
      $meta = $null; try { $meta = Get-Content -LiteralPath ($i.FullName + '.json') -Raw | ConvertFrom-Json } catch {}
      if (-not $meta -or -not $meta.original) { Warn "  no metadata for $($i.Name) - restore it manually from $QuarDir"; continue }
      try {
        Move-Item -LiteralPath $i.FullName -Destination $meta.original -ErrorAction Stop
        Remove-Item -LiteralPath ($i.FullName + '.json') -Force -ErrorAction SilentlyContinue
        Ok "  restored: $($meta.original)"
        Warn '    (this file was flagged - re-scan/verify before trusting it)'
      } catch { Warn "  restore failed for $($i.Name): $_" }
    }
  }
}

# Rewrite freshclam.conf's third-party (SaneSecurity) DatabaseCustomURL block.
# When enabled, adds a curated set of malware-focused unofficial signature DBs so
# ClamAV detects more. Failures on any single DB are non-fatal (freshclam warns and
# keeps the official DB). Returns nothing; mutates the conf in place.
$script:SaneSecurityFiles = @(
  'winnow_malware.hdb','winnow_malware_links.ndb','winnow.attachments.hdb',
  'malwarehash.hsb','rogue.hdb','jurlbl.ndb','phishtank.ndb','scam.ndb',
  'foxhole_filename.cdb','foxhole_generic.cdb'
)
function Set-ThirdPartySigs {
  param([string]$ConfPath, [bool]$Enabled, [string]$Base)
  if (-not (Test-Path $ConfPath)) { return }
  if (-not $Base) { $Base = 'https://ftp.swin.edu.au/sanesecurity' }
  $Base = $Base.TrimEnd('/')
  $keep = Get-Content $ConfPath -ErrorAction SilentlyContinue |
          Where-Object { $_ -notmatch '^\s*DatabaseCustomURL\b' -and $_ -notmatch '^\s*# scan-av third-party' }
  $out = @($keep)
  if ($Enabled) {
    $out += '# scan-av third-party (SaneSecurity) signatures'
    foreach ($f in $script:SaneSecurityFiles) { $out += "DatabaseCustomURL $Base/$f" }
  }
  ($out -join "`r`n") | Set-Content -Path $ConfPath -Encoding ASCII
}

# ---------------------------------------------------------------- extraction
# Returns 7-Zip's exit code (0 ok, 1 warnings, >=2 fatal) and logs its output so
# encrypted/corrupt archives are reported instead of silently "extracting" 0 files.
# The dummy -p password makes 7z FAIL on encrypted archives rather than prompt on
# stdin - which would hang forever in the GUI's hidden child process.
function Extract-Surface {
  param([string]$Archive, [string]$Dest, $Cfg)
  if (-not $Cfg.tools.sevenZip) { throw '7-Zip not configured; cannot extract archives.' }
  New-Item -ItemType Directory -Force -Path $Dest | Out-Null
  $log = Join-Path $LogDir ('extract_{0}_{1}.log' -f ((Split-Path $Archive -Leaf) -replace '[^\w\.-]','_'), (Get-Random))
  if ($Cfg.options.mode -eq 'full') {
    $rc = Invoke-Native -Exe $Cfg.tools.sevenZip -Arguments @('x', $Archive, "-o$Dest", '-pscanav-no-password', '-y') -Log $log -TimeoutSec (Get-EngineTimeout $Cfg)
  } else {
    $inc = $Cfg.options.execExtensions | ForEach-Object { "-ir!*.$_" }
    $rc = Invoke-Native -Exe $Cfg.tools.sevenZip -Arguments (@('x', $Archive, "-o$Dest", '-pscanav-no-password') + $inc + @('-y')) -Log $log -TimeoutSec (Get-EngineTimeout $Cfg)
  }
  return [int]$rc
}

# ---------------------------------------------------------------- scan a target
function Scan-Target {
  # $Preset: pre-computed engine results (from the ClamAV batch scan) keyed by
  # engine name. $VtAllFiles: per-folder "VT all" mode - also reputation-check new
  # executables on VirusTotal even when local engines are clean. $PrevScanUtc:
  # when this unit was last scanned clean (limits "new executables" to newer files).
  param([string]$Target, $Cfg, [string[]]$Engines, $Preset = $null, [bool]$VtAllFiles = $false, $PrevScanUtc = $null)
  $name = Split-Path $Target -Leaf
  $stamp = (Get-Random)
  $safe = ($name -replace '[^\w\.-]','_')
  $results = @()
  $scanRoot = $Target
  $temp = $null

  if ((Test-Path -LiteralPath $Target -PathType Leaf) -and ($ArchiveExt -contains ([IO.Path]::GetExtension($Target).ToLower()))) {
    Sec "ARCHIVE: $name"
    # list >2GiB members (ClamAV can't scan those)
    if ($Cfg.tools.sevenZip) {
      $prevEAP = $ErrorActionPreference; $ErrorActionPreference = 'Continue'
      $list = & $Cfg.tools.sevenZip l $Target '-pscanav-no-password' 2>$null   # dummy -p: fail, don't prompt, on header-encrypted archives
      $ErrorActionPreference = $prevEAP
      $big = $list | Where-Object { $_ -match '^\d{4}-\d{2}-\d{2}' } |
        ForEach-Object {
          $c = ($_ -split '\s+'); if ($c.Count -ge 5 -and $c[3] -match '^\d+$' -and [int64]$c[3] -gt 2147483647) {
            '{0,7:N1} GiB  {1}' -f ([int64]$c[3]/1GB), ($c[5..($c.Count-1)] -join ' ')
          }
        }
      if ($big) { Warn 'Files >2 GiB (ClamAV cannot scan these):'; $big | ForEach-Object { Info "    $_" } }
    }
    $temp = Join-Path ([IO.Path]::GetTempPath()) "scanav_$stamp"
    Info 'Extracting...'
    # One unscannable archive must not abort the whole multi-target run (EAP=Stop).
    try { $xrc = Extract-Surface -Archive $Target -Dest $temp -Cfg $Cfg }
    catch {
      Bad "Extraction failed: $_"
      Remove-Item -LiteralPath $temp -Recurse -Force -ErrorAction SilentlyContinue
      return [pscustomobject]@{ Target=$name; Hits=0; Valid=$false; Vt=@(); QPaths=@(); Results=@() }
    }
    $n = @(Get-ChildItem -LiteralPath $temp -Recurse -File -ErrorAction SilentlyContinue).Count
    if ($xrc -ne 0 -and $n -eq 0) {
      Warn "7-Zip could not extract this archive (exit $xrc) - encrypted, corrupt or unsupported. NOT scanned; this is not a clean verdict."
      Remove-Item -LiteralPath $temp -Recurse -Force -ErrorAction SilentlyContinue
      return [pscustomobject]@{ Target=$name; Hits=0; Valid=$false; Vt=@(); QPaths=@(); Results=@() }
    }
    if ($xrc -ge 2) { Warn "7-Zip reported errors (exit $xrc) - some members may not have been extracted (encrypted/corrupt?). See the extract log in $LogDir." }
    Info "Extracted $n file(s) to scan."
    if ($n -eq 0) {
      Info '(nothing to scan)'
      Remove-Item -LiteralPath $temp -Recurse -Force -ErrorAction SilentlyContinue
      return [pscustomobject]@{ Target=$name; Hits=0; Valid=$true; Vt=@(); QPaths=@(); Results=@() }
    }
    $scanRoot = $temp
  } elseif (Test-Path -LiteralPath $Target -PathType Container) {
    Sec "FOLDER: $Target"
  } elseif (Test-Path -LiteralPath $Target -PathType Leaf) {
    Sec "FILE: $name"   # a single loose file -> scan it directly
  } else {
    Bad "Not found or unsupported: $Target"; return
  }

  foreach ($eng in $Engines) {
    $log = Join-Path $LogDir ("{0}_{1}_{2}.log" -f $eng, $safe, $stamp)
    switch ($eng) {
      'clamav'   { if ($Preset -and $Preset['clamav']) { Info 'ClamAV: using batch-scan result.'; $r = $Preset['clamav'] }
                   else { Info 'Running ClamAV...';    $r = Run-ClamAV   -Target $scanRoot -Log $log -Cfg $Cfg } }
      'emsisoft' { Info 'Running Emsisoft...';           $r = Run-Emsisoft -Target $scanRoot -Log $log -Cfg $Cfg }
      'defender' { Info 'Running Microsoft Defender...'; $r = Run-Defender -Target $scanRoot -Log $log -Cfg $Cfg }
    }
    if ($r.PSObject.Properties['LogFile'] -and $r.LogFile) { $log = $r.LogFile }   # batch results share one log
    $results += $r
    if ($r.Hits.Count -gt 0) {
      Bad ("{0}: {1} DETECTION(S)" -f $r.Engine, $r.Hits.Count)
      $r.Hits | ForEach-Object { Bad "    $_" }
    } elseif (-not $r.Scanned -or $r.Scanned -eq '0') {
      # no summary / 0 files = the engine errored or had nothing to scan, NOT a clean result
      Warn ("{0}: no result (exit {1}) - it errored or found nothing to scan. See log." -f $r.Engine, $r.Rc)
    } else {
      $sk = if ($r.Skipped) { " ($($r.Skipped) skipped >limit)" } else { '' }
      Ok ("{0}: clean - scanned {1} file(s){2}" -f $r.Engine, $r.Scanned, $sk)
    }
    $errs = if ($r.PSObject.Properties['Errors']) { @($r.Errors) } else { @() }
    if ($errs.Count -gt 0) {
      Warn ("    {0}: {1} file(s) could NOT be scanned (too large / locked / unreadable) - not a clean verdict for them:" -f $r.Engine, $errs.Count)
      $errs | Select-Object -First 8 | ForEach-Object { Warn ("        " + (($_ -replace ': ERROR$','') -replace "^.*\\","")) }
    }
    Info "    log: $log"
  }

  $totalHits = 0; foreach ($r in $results) { $totalHits += $r.Hits.Count }
  # A unit only counts as SCANNED if at least one engine actually processed files
  # (hit something, or reported a scanned count). Otherwise every engine errored -
  # the result must not be treated (or cached) as clean.
  $valid = $false
  foreach ($r in $results) { if ($r.Hits.Count -gt 0 -or ($r.Scanned -and $r.Scanned -ne '0')) { $valid = $true } }

  $vtKey = if ($Cfg.options.PSObject.Properties['vtApiKey']) { [string]$Cfg.options.vtApiKey } else { '' }
  $vt = @()
  $hitPaths = @()
  if ($totalHits -gt 0) {
    $hitPaths = @(Get-HitPaths -Results $results)
    # engine output gave no usable path but the scanned unit IS a single file
    if ($hitPaths.Count -eq 0 -and (Test-Path -LiteralPath $scanRoot -PathType Leaf)) { $hitPaths = @($scanRoot) }
  }

  # VirusTotal hash lookup for infected files (before the temp surface is removed,
  # since archive detections live inside it). Only runs when an API key is set.
  if ($totalHits -gt 0) {
    if ($vtKey) {
      if ($hitPaths.Count -gt 0) {
        Sec 'VirusTotal hash lookup'
        $vt = @(Invoke-VtLookup -ApiKey $vtKey -Paths $hitPaths -Cfg $Cfg -AllowPrompt (-not $NoPrompt))
      }
      else { Info 'VirusTotal: could not resolve infected file path(s) from engine output.' }
    } else {
      Info 'VirusTotal: add an API key in Settings to auto-check infected file hashes.'
    }
  }

  # Per-folder "VT all" mode: reputation-check NEW/changed executables on VirusTotal
  # even when the local engines found nothing - signature scanners miss fresh
  # malware that VT's 70 engines may already know. Hash lookups only (no upload
  # unless the upload setting is on and the hash is unknown). Runs before the temp
  # dir is removed so archive contents are still on disk.
  $vtFlaggedPaths = @()
  if ($VtAllFiles -and $vtKey) {
    $already = @{}; foreach ($v in $vt) { $already[$v.Sha] = $true }
    $exts = @($Cfg.options.execExtensions | ForEach-Object { '.' + ([string]$_).ToLower() })
    $cand = @(Get-ChildItem -LiteralPath $scanRoot -Recurse -File -Force -ErrorAction SilentlyContinue |
              Where-Object { $exts -contains $_.Extension.ToLower() })
    if ($PrevScanUtc) { $cand = @($cand | Where-Object { $_.LastWriteTimeUtc -gt $PrevScanUtc }) }
    $cand = @($cand | Sort-Object LastWriteTimeUtc -Descending)
    $vtCap = 10
    if ($cand.Count -gt $vtCap) {
      Warn ("VT reputation check: {0} new executable(s) here - checking only the {1} newest (free-tier rate limits). The rest are covered by the local engines." -f $cand.Count, $vtCap)
      $cand = @($cand[0..($vtCap-1)])
    }
    if ($cand.Count -gt 0) {
      Sec ("VirusTotal reputation check - {0} new executable(s)" -f $cand.Count)
      $leafMap = @{}
      foreach ($c in $cand) { if (-not $leafMap.ContainsKey($c.Name)) { $leafMap[$c.Name] = $c.FullName } }
      $vtNew = @(Invoke-VtLookup -ApiKey $vtKey -Paths @($cand | ForEach-Object { $_.FullName }) -Cfg $Cfg -AllowPrompt (-not $NoPrompt))
      $vtNew = @($vtNew | Where-Object { -not $already[$_.Sha] })
      $vt += $vtNew
      # >=3 VT engines = treat as a detection in its own right (1-2 is common noise)
      $flaggedRecs = @($vtNew | Where-Object { ([int]$_.Malicious + [int]$_.Suspicious) -ge 3 })
      if ($flaggedRecs.Count -gt 0) {
        $vtHitLines = @($flaggedRecs | ForEach-Object { '{0} - {1}/{2} VT engines flag it' -f $_.File, ([int]$_.Malicious + [int]$_.Suspicious), $_.Total })
        $results += [pscustomobject]@{ Engine='VirusTotal'; Rc=0; Hits=$vtHitLines; Skipped=0; Scanned=[string]$cand.Count }
        $totalHits += $flaggedRecs.Count
        $vtFlaggedPaths = @($flaggedRecs | ForEach-Object { $leafMap[$_.File] } | Where-Object { $_ })
        Bad ("VirusTotal flagged {0} file(s) that the local engines passed!" -f $flaggedRecs.Count)
      }
    }
  } elseif ($VtAllFiles -and -not $vtKey) {
    Info 'VT reputation check skipped for this folder - add an API key in Settings.'
  }

  # quarantine candidates: the archive itself for archive units, else the flagged files
  $qpaths = @()
  if ($totalHits -gt 0) {
    $qpaths = if ($temp) { @($Target) }
              else { @(@($hitPaths) + @($vtFlaggedPaths) | Where-Object { $_ -and (Test-Path -LiteralPath $_ -PathType Leaf) } | Select-Object -Unique) }
  }

  if ($temp) { Remove-Item $temp -Recurse -Force -ErrorAction SilentlyContinue }

  Write-Host ''
  if ($totalHits -gt 0) {
    $engFlagged = @($results | Where-Object { $_.Hits.Count -gt 0 }).Count
    $vtKnown = @($vt | Where-Object { $_.Status -eq 'ok' })
    $vtMax = 0; foreach ($v in $vtKnown) { $s = [int]$v.Malicious + [int]$v.Suspicious; if ($s -gt $vtMax) { $vtMax = $s } }
    if ($vtKnown.Count -gt 0 -and $vtMax -ge 5) {
      Bad "==> THREAT(S) FOUND in $name - CONFIRMED by VirusTotal ($vtMax engines flag it). Do not run it."
    } elseif ($vtKnown.Count -gt 0 -and $vtMax -eq 0 -and $engFlagged -le 1) {
      Warn "==> $name flagged by ONE local engine but 0 VirusTotal engines know this hash as bad - probable packer false positive. Verify before acting."
    } else {
      Bad "==> THREAT(S) FOUND in $name. If only ONE engine flagged it, verify the file's SHA-256 on a multi-engine service before acting (could be a packer false positive)."
    }
  } elseif (-not $valid) {
    Warn "==> NOT SCANNED: $name - every engine errored (see logs). It will be retried on the next run."
  } else {
    Ok "==> CLEAN: $name"
  }
  return [pscustomobject]@{ Target=$name; Hits=$totalHits; Valid=$valid; Vt=$vt; QPaths=$qpaths; Results=$results }
}

# ---------------------------------------------------------------- definitions
function Update-Definitions {
  param($Cfg, [string[]]$Engines)
  Sec 'Updating virus definitions'
  $ok = $true
  if (($Engines -contains 'clamav') -and $Cfg.tools.freshclam) {
    Info 'freshclam...'
    $fcDir = Split-Path $Cfg.tools.freshclam
    $fa = @()
    $conf = Join-Path $fcDir 'freshclam.conf'
    if (Test-Path $conf) {
      $fa += "--config-file=$conf"
      # sync the third-party (SaneSecurity) DatabaseCustomURL block to the setting
      $tp = if ($Cfg.options.PSObject.Properties['thirdPartySigs']) { [bool]$Cfg.options.thirdPartySigs } else { $false }
      $base = if ($Cfg.options.PSObject.Properties['thirdPartyBase']) { [string]$Cfg.options.thirdPartyBase } else { '' }
      try { Set-ThirdPartySigs -ConfPath $conf -Enabled $tp -Base $base } catch { Warn "  third-party sig config failed: $_" }
      if ($tp) { Info '  including third-party (SaneSecurity) signatures.' }
    }
    $db   = Join-Path $fcDir 'database';       if (Test-Path $db)   { $fa += "--datadir=$db" }
    $rc = Invoke-Native -Exe $Cfg.tools.freshclam -Arguments $fa -Log (Join-Path $LogDir 'freshclam.log') -TimeoutSec (Get-EngineTimeout $Cfg)
    if ($rc -eq 0) { Ok 'ClamAV definitions up to date.' } else { Warn "freshclam exit $rc (see logs\freshclam.log)"; $ok = $false }
  }
  if (($Engines -contains 'emsisoft') -and $Cfg.tools.a2cmd) {
    Info 'a2cmd /update...'
    $rc = Invoke-Native -Exe $Cfg.tools.a2cmd -Arguments @('/update') -Log (Join-Path $LogDir 'a2update.log') -TimeoutSec (Get-EngineTimeout $Cfg)
    if ($rc -eq 0) { Ok 'Emsisoft definitions up to date.' } else { Warn "a2cmd /update exit $rc (see logs\a2update.log)"; $ok = $false }
  }
  if ($Engines -contains 'defender') {
    $def = if ($Cfg.tools.PSObject.Properties['defender']) { $Cfg.tools.defender } else { $null }
    if (-not $def) { $def = Find-Defender }
    if ($def) {
      Info 'Microsoft Defender signature update...'
      $rc = Invoke-Native -Exe $def -Arguments @('-SignatureUpdate') -Log (Join-Path $LogDir 'defender_update.log') -TimeoutSec (Get-EngineTimeout $Cfg)
      if ($rc -eq 0) { Ok 'Defender definitions up to date.' } else { Warn "MpCmdRun -SignatureUpdate exit $rc (see logs\defender_update.log)"; $ok = $false }
    } else { Warn 'Defender not available (MpCmdRun.exe not found).' }
  }
  if ($ok) { Set-Content -Path (Join-Path $AppDir 'last-update.txt') -Value ([DateTime]::UtcNow.ToString('o')) -Encoding ASCII }
  return $ok
}

# ---------------------------------------------------------------- self-update
$RawUrl = 'https://raw.githubusercontent.com/dggomes/avscan/main/windows/scan-av.ps1'
# Download the latest scan-av.ps1 from GitHub, validate it (non-trivial + parses),
# back up the current copy, and replace the installed file. Returns {ok,msg}.
function Update-FromGitHub {
  $dst = Join-Path $AppDir 'scan-av.ps1'
  $tmp = Join-Path $env:TEMP ('scanav_update_' + [Guid]::NewGuid().ToString('N') + '.ps1')
  # A unique query string busts the raw.githubusercontent.com (Fastly) edge cache,
  # which otherwise can serve a stale copy for several minutes after a push - the
  # 'Cache-Control' request header alone does NOT force a revalidate.
  $url = $RawUrl + '?nocache=' + [Guid]::NewGuid().ToString('N')
  try {
    [Net.ServicePointManager]::SecurityProtocol = [Net.SecurityProtocolType]::Tls12
    Invoke-WebRequest -Uri $url -OutFile $tmp -UseBasicParsing -Headers @{ 'Cache-Control' = 'no-cache'; 'Pragma' = 'no-cache' } -ErrorAction Stop
  } catch { return [pscustomobject]@{ ok = $false; msg = "Download failed: $_" } }
  $content = Get-Content $tmp -Raw -ErrorAction SilentlyContinue
  if (-not $content -or $content.Length -lt 5000 -or $content -notmatch 'function Show-Gui') {
    return [pscustomobject]@{ ok = $false; msg = 'Downloaded file looks invalid; not applied.' }
  }
  $perr = $null
  [void][System.Management.Automation.Language.Parser]::ParseInput($content, [ref]$null, [ref]$perr)
  if ($perr -and $perr.Count) { return [pscustomobject]@{ ok = $false; msg = 'Downloaded file has parse errors; not applied.' } }
  $newVer = ([regex]::Match($content, '\$ScanAvVersion\s*=\s*''([^'']+)''')).Groups[1].Value
  try {
    if (Test-Path $dst) { Copy-Item $dst "$dst.bak" -Force }
    Copy-Item $tmp $dst -Force
    Remove-Item $tmp -Force -ErrorAction SilentlyContinue
    $targetVer = if ($newVer) { $newVer } else { $ScanAvVersion }
    $launcher = Ensure-StandaloneLauncher -Quiet -LauncherVersion $targetVer
    $vtxt = if ($newVer) { "version $newVer" } else { 'the latest version' }
    $note = if ($newVer -and $newVer -eq $ScanAvVersion) { "`n`nNote: this is the same version you're already running. GitHub may still be serving a cached copy - wait a minute and try again." } else { '' }
    $launcherNote = if ($script:StandaloneLauncherPending) { "`nStandalone launcher is in use and will be refreshed after ScanAV closes: $launcher" } elseif ($launcher) { "`nStandalone launcher refreshed: $launcher" } else { "`nStandalone launcher could not be refreshed; the PowerShell shortcut fallback still works." }
    return [pscustomobject]@{ ok = $true; ver = $newVer; msg = "Updated to $vtxt from GitHub (was $ScanAvVersion). Restart to use it.$launcherNote$note" }
  } catch { return [pscustomobject]@{ ok = $false; msg = "Could not replace installed file: $_" } }
}

# ---------------------------------------------------------------- GUI
# A WinForms app: pick folders (and sub-folders) to scan, add/remove them, update
# definitions, view logs, and self-update from GitHub. Scanning is handed to the
# console engine (a new powershell window) so the UI never freezes.
# ================================================================ GUI helpers
# Script-scoped so WPF event handlers can call them reliably regardless of closure
# scope. Per-card handlers read the node from the element's .Tag (no closures).
function script:WBrush([string]$hex) { (New-Object System.Windows.Media.BrushConverter).ConvertFromString($hex) }

function script:New-ModelNode([string]$path, [bool]$isFolder, [int]$depth) {
  $hasKids = $false
  if ($isFolder) { try { $hasKids = @(Get-ChildItem -LiteralPath $path -Force -ErrorAction SilentlyContinue | Select-Object -First 1).Count -gt 0 } catch {} }
  [pscustomobject]@{ Path=$path; Name=(Split-Path $path -Leaf); IsFolder=$isFolder; HasChildren=$hasKids; Expanded=$false; Checked=$false; Loaded=$false; Children=@(); Depth=$depth }
}
function script:Load-ModelChildren($node) {
  if ($node.Loaded) { return }
  $kids = @()
  try {
    Get-ChildItem -LiteralPath $node.Path -Force -ErrorAction SilentlyContinue | Sort-Object @{e={-not $_.PSIsContainer}}, Name | ForEach-Object {
      $kids += (New-ModelNode $_.FullName ([bool]$_.PSIsContainer) ($node.Depth + 1))
    }
  } catch {}
  $node.Children = $kids; $node.Loaded = $true
  # A checked folder means "scan everything under here", so children (including any
  # new ones that just appeared) inherit the checked state when they load.
  if ($node.Checked) { foreach ($c in $kids) { $c.Checked = $true } }
}
# Set a node's checked state and cascade it to all loaded descendants, so ticking a
# parent folder visibly selects its sub-folders (and unticking clears them).
function script:Set-CheckCascade($node, [bool]$value) {
  $node.Checked = $value
  foreach ($c in $node.Children) { Set-CheckCascade $c $value }
}
function script:New-TargetCard($node) {
  $card = New-Object System.Windows.Controls.Border
  $card.Background = (WBrush '#10141E'); $card.CornerRadius = New-Object System.Windows.CornerRadius 14
  $card.BorderBrush = (WBrush '#1A2130'); $card.BorderThickness = New-Object System.Windows.Thickness 1
  $card.Margin = New-Object System.Windows.Thickness (($node.Depth * 26),0,0,8)
  $card.Padding = New-Object System.Windows.Thickness 14,10,14,10
  $card.MinHeight = 62; $card.Cursor = [System.Windows.Input.Cursors]::Hand; $card.Tag = $node

  $g = New-Object System.Windows.Controls.Grid
  $gAuto = [System.Windows.GridLength]::Auto
  $gStar = New-Object System.Windows.GridLength(1, [System.Windows.GridUnitType]::Star)
  $c0 = New-Object System.Windows.Controls.ColumnDefinition; $c0.Width = $gAuto
  $c1 = New-Object System.Windows.Controls.ColumnDefinition; $c1.Width = $gStar
  $c2 = New-Object System.Windows.Controls.ColumnDefinition; $c2.Width = $gAuto
  $g.ColumnDefinitions.Add($c0); $g.ColumnDefinitions.Add($c1); $g.ColumnDefinitions.Add($c2)

  $chip = New-Object System.Windows.Controls.Border
  $chip.Width = 40; $chip.Height = 40; $chip.CornerRadius = New-Object System.Windows.CornerRadius 10
  $chip.Background = (WBrush '#1A2231'); $chip.Margin = New-Object System.Windows.Thickness 0,0,14,0
  $gl = New-Object System.Windows.Controls.TextBlock
  $gl.Text = [string]$(if ($node.IsFolder) { [char]0xE8B7 } else { [char]0xE8A5 })
  $gl.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe MDL2 Assets'
  $gl.FontSize = 18; $gl.Foreground = (WBrush '#9AA6BC'); $gl.HorizontalAlignment = 'Center'; $gl.VerticalAlignment = 'Center'
  $chip.Child = $gl
  [System.Windows.Controls.Grid]::SetColumn($chip,0); [void]$g.Children.Add($chip)

  $sp = New-Object System.Windows.Controls.StackPanel; $sp.VerticalAlignment = 'Center'
  $cn = Get-FolderName $node.Path
  $t1 = New-Object System.Windows.Controls.TextBlock; $t1.Text = $(if ($cn) { $cn } else { $node.Name }); $t1.FontSize = 16; $t1.Foreground = (WBrush '#FFFFFF'); $t1.TextTrimming = 'CharacterEllipsis'
  $t2 = New-Object System.Windows.Controls.TextBlock; $t2.Text = $node.Path; $t2.FontSize = 12; $t2.Foreground = (WBrush '#8A93A6'); $t2.Margin = New-Object System.Windows.Thickness 0,2,0,0; $t2.TextTrimming = 'CharacterEllipsis'
  [void]$sp.Children.Add($t1); [void]$sp.Children.Add($t2)
  [System.Windows.Controls.Grid]::SetColumn($sp,1); [void]$g.Children.Add($sp)

  $tr = New-Object System.Windows.Controls.StackPanel; $tr.Orientation = 'Horizontal'; $tr.VerticalAlignment = 'Center'
  if ($node.IsFolder -and $node.Depth -eq 0) {
    # "VT" badge: toggles this folder between VirusTotal-on-flagged-only (default)
    # and VirusTotal-on-all-new-executables
    $vtOn = Get-FolderVtAll $node.Path
    $vtb = New-Object System.Windows.Controls.Border
    $vtb.CornerRadius = New-Object System.Windows.CornerRadius 8
    $vtb.Padding = New-Object System.Windows.Thickness 9,4,9,4
    $vtb.Margin = New-Object System.Windows.Thickness 0,0,14,0
    $vtb.VerticalAlignment = 'Center'; $vtb.Cursor = [System.Windows.Input.Cursors]::Hand; $vtb.Tag = $node
    $vtb.Background = (WBrush $(if ($vtOn) { '#6D5BF0' } else { '#1A2231' }))
    $vtb.ToolTip = "VirusTotal mode for this folder`nOFF: check only files the engines flag`nON: also reputation-check NEW executables against VirusTotal (needs API key in Settings)"
    $vtt = New-Object System.Windows.Controls.TextBlock
    $vtt.Text = 'VT'; $vtt.FontSize = 12; $vtt.FontWeight = 'SemiBold'
    $vtt.Foreground = (WBrush $(if ($vtOn) { '#FFFFFF' } else { '#8A93A6' }))
    $vtb.Child = $vtt
    $vtb.Add_MouseLeftButtonUp({ param($s,$e) $e.Handled = $true; $n = $s.Tag; Set-FolderVtAll $n.Path (-not (Get-FolderVtAll $n.Path)); Render-Targets })
    [void]$tr.Children.Add($vtb)
  }
  if ($node.IsFolder) {
    $open = New-Object System.Windows.Controls.TextBlock
    $open.Text = [string][char]0xE838
    $open.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe MDL2 Assets'
    $open.FontSize = 16; $open.Foreground = (WBrush '#8A93A6'); $open.Margin = New-Object System.Windows.Thickness 0,0,16,0; $open.VerticalAlignment = 'Center'; $open.Cursor = [System.Windows.Input.Cursors]::Hand; $open.Tag = $node
    $open.ToolTip = 'Open folder'
    $open.Add_MouseLeftButtonUp({ param($s,$e) $e.Handled = $true; Open-FolderNode $s.Tag })
    [void]$tr.Children.Add($open)

    $move = New-Object System.Windows.Controls.TextBlock
    $move.Text = [string][char]0xE8DE
    $move.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe MDL2 Assets'
    $move.FontSize = 16; $move.Foreground = (WBrush '#8A93A6'); $move.Margin = New-Object System.Windows.Thickness 0,0,16,0; $move.VerticalAlignment = 'Center'; $move.Cursor = [System.Windows.Input.Cursors]::Hand; $move.Tag = $node
    $move.ToolTip = 'Move or rename folder'
    $move.Add_MouseLeftButtonUp({ param($s,$e) $e.Handled = $true; Move-FolderNode $s.Tag })
    [void]$tr.Children.Add($move)

    $pen = New-Object System.Windows.Controls.TextBlock
    $pen.Text = [string][char]0xE70F   # pencil - display label
    $pen.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe MDL2 Assets'
    $pen.FontSize = 16; $pen.Foreground = (WBrush '#8A93A6'); $pen.Margin = New-Object System.Windows.Thickness 0,0,16,0; $pen.VerticalAlignment = 'Center'; $pen.Cursor = [System.Windows.Input.Cursors]::Hand; $pen.Tag = $node
    $pen.ToolTip = 'Edit display name'
    $pen.Add_MouseLeftButtonUp({ param($s,$e) $e.Handled = $true; Rename-FolderNode $s.Tag })
    [void]$tr.Children.Add($pen)
  }
  if ($node.IsFolder -and $node.HasChildren) {
    $chev = New-Object System.Windows.Controls.TextBlock
    $chev.Text = [string]$(if ($node.Expanded) { [char]0xE70E } else { [char]0xE70D })
    $chev.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe MDL2 Assets'
    $chev.FontSize = 16; $chev.Foreground = (WBrush '#8A93A6'); $chev.Margin = New-Object System.Windows.Thickness 0,0,14,0; $chev.VerticalAlignment = 'Center'
    [void]$tr.Children.Add($chev)
  }
  $box = New-Object System.Windows.Controls.Border
  $box.Width = 34; $box.Height = 34; $box.CornerRadius = New-Object System.Windows.CornerRadius 9; $box.VerticalAlignment = 'Center'; $box.Tag = $node
  if ($node.Checked) {
    $box.Background = (WBrush '#6D5BF0'); $box.BorderThickness = New-Object System.Windows.Thickness 0
    $ck = New-Object System.Windows.Controls.TextBlock; $ck.Text = [string][char]0xE73E; $ck.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe MDL2 Assets'; $ck.FontSize = 16; $ck.Foreground = (WBrush '#FFFFFF'); $ck.HorizontalAlignment='Center'; $ck.VerticalAlignment='Center'
    $box.Child = $ck
  } else {
    $box.Background = (WBrush '#0C1018'); $box.BorderBrush = (WBrush '#39414F'); $box.BorderThickness = New-Object System.Windows.Thickness 2
  }
  [void]$tr.Children.Add($box)
  [System.Windows.Controls.Grid]::SetColumn($tr,2); [void]$g.Children.Add($tr)
  $card.Child = $g

  $box.Add_MouseLeftButtonUp({ param($s,$e) $n = $s.Tag; Set-CheckCascade $n (-not $n.Checked); $e.Handled = $true; Render-Targets })
  $card.Add_MouseLeftButtonUp({
    param($s,$e)
    $n = $s.Tag
    if ($n.IsFolder -and $n.HasChildren) {
      if (-not $n.Expanded -and -not $n.Loaded) { Load-ModelChildren $n }
      $n.Expanded = -not $n.Expanded
    } else { Set-CheckCascade $n (-not $n.Checked) }
    Render-Targets
  })
  return $card
}
function script:Emit-Node($node) {
  [void]$script:TargetsPanel.Children.Add((New-TargetCard $node))
  if ($node.Expanded) { foreach ($c in $node.Children) { Emit-Node $c } }
}
function script:Render-Targets {
  if (-not $script:TargetsPanel) { return }
  $script:TargetsPanel.Children.Clear()
  foreach ($n in $script:rootNodes) { Emit-Node $n }
}
function script:Rebuild-Roots {
  $script:rootNodes = @()
  foreach ($f in @($script:guiCfg.scanFolders)) {
    if (Test-Path -LiteralPath $f) { $n = New-ModelNode $f $true 0; $n.Checked = $true; $script:rootNodes += $n }
  }
  Render-Targets
}
# Capture which nodes are currently expanded/checked (by path) so a refresh can
# rebuild the tree from disk - picking up newly added sub-folders - without losing
# the user's place or selection.
function script:Get-TargetState {
  $expanded = New-Object System.Collections.Generic.List[string]
  $checked  = New-Object System.Collections.Generic.List[string]
  function walk($n) {
    if ($n.Expanded) { [void]$expanded.Add([string]$n.Path) }
    if ($n.Checked)  { [void]$checked.Add([string]$n.Path) }
    foreach ($c in $n.Children) { walk $c }
  }
  foreach ($n in @($script:rootNodes)) { walk $n }
  return @{ Expanded = $expanded; Checked = $checked }
}
function script:Restore-TargetState($state) {
  function walk($n) {
    # apply Checked BEFORE loading children: Load-ModelChildren makes new
    # sub-folders inherit the parent's checked state, so the order matters
    if ($state.Checked -contains $n.Path) { $n.Checked = $true }
    if ($state.Expanded -contains $n.Path) {
      if (-not $n.Loaded) { Load-ModelChildren $n }   # re-reads disk -> new folders appear
      $n.Expanded = $true
    }
    foreach ($c in $n.Children) { walk $c }
  }
  foreach ($n in @($script:rootNodes)) { walk $n }
}
# A cheap fingerprint of the sub-folder names visible in the tree right now: each
# configured root plus any expanded folder. Changes when a sub-folder is added or
# removed on disk, which the folder-watch timer uses to auto-refresh.
function script:Get-VisibleFingerprint {
  $sb = New-Object System.Text.StringBuilder
  function fp($path) {
    try {
      $names = @(Get-ChildItem -LiteralPath $path -Force -Directory -ErrorAction SilentlyContinue | ForEach-Object { $_.Name } | Sort-Object) -join '|'
      [void]$sb.Append($path).Append('=').Append($names).Append(';')
    } catch {}
  }
  function walk($n) { if ($n.IsFolder -and $n.Expanded) { fp $n.Path }; foreach ($c in $n.Children) { walk $c } }
  foreach ($f in @($script:guiCfg.scanFolders)) { fp $f }                 # roots (even if collapsed)
  foreach ($n in @($script:rootNodes)) { walk $n }                        # expanded sub-folders
  return $sb.ToString()
}
# Re-enumerate the scan folders from disk, preserving expand/check state. Safe to
# call repeatedly (runs on window activation and the 3s folder-watch timer).
# Roots are NOT force-checked here: that would silently re-tick folders the user
# unchecked every time the window regains focus. Only Restore-TargetState decides.
function script:Refresh-Targets {
  if (-not $script:guiCfg) { return }
  $st = Get-TargetState
  $script:rootNodes = @()
  foreach ($f in @($script:guiCfg.scanFolders)) {
    if (Test-Path -LiteralPath $f) { $script:rootNodes += (New-ModelNode $f $true 0) }
  }
  Restore-TargetState $st
  Render-Targets
}
function script:Collect-Targets {
  $acc = New-Object System.Collections.Generic.List[string]
  function walk($n) { if ($n.Checked) { $acc.Add([string]$n.Path) }; foreach ($c in $n.Children) { walk $c } }
  foreach ($n in $script:rootNodes) { walk $n }
  $set = @($acc | Select-Object -Unique); $tops = @()
  foreach ($p in $set) {
    $cov = $false
    foreach ($q in $set) { if ($q -ne $p -and $p.StartsWith($q + '\')) { $cov = $true; break } }
    if (-not $cov) { $tops += $p }
  }
  # Return the list unrolled (NOT ,$tops): the callers wrap with @(Collect-Targets),
  # and ,$tops would make that a NESTED array - a single element that is the whole
  # path list, which then string-interpolates (space-joined) into one bogus path
  # like "C:\Scanned C:\Users\...\Downloads". Plain $tops keeps each path separate.
  $tops
}
function script:Save-GuiCfg { ($script:guiCfg | ConvertTo-Json -Depth 6) | Set-Content -Path $CfgFile -Encoding UTF8 }
# Set a property if it exists, else add it. Avoids the pipe-to-Add-Member form,
# which can behave differently when a NoteProperty already exists.
function script:Set-CfgProp { param($Obj, [string]$Name, $Value)
  if (-not $Obj) { return }
  $p = $Obj.PSObject.Properties[$Name]
  if ($p) { $p.Value = $Value } else { Add-Member -InputObject $Obj -NotePropertyName $Name -NotePropertyValue $Value -Force }
}
