# Folder picker used by both the dashboard "Add Folder" tile and the "Add" button
# in the Scan Targets header. It includes manual path entry because elevated apps
# may not see all network drives mapped in the user's unelevated Explorer session.
function script:Normalize-ScanFolderPath([string]$path) {
  if (-not $path) { return '' }
  $p = [Environment]::ExpandEnvironmentVariables($path.Trim().Trim('"'))
  if ($p -match '^file:') {
    try { $p = ([Uri]$p).LocalPath } catch {}
  }
  try {
    $full = [IO.Path]::GetFullPath($p)
    $root = [IO.Path]::GetPathRoot($full)
    if ($root -and [string]::Equals($full.TrimEnd('\','/'), $root.TrimEnd('\','/'), [StringComparison]::OrdinalIgnoreCase)) { return $root }
    return $full.TrimEnd('\','/')
  } catch { return $p.TrimEnd('\','/') }
}
function script:Get-KnownNetworkFolders {
  $items = New-Object System.Collections.Generic.List[object]
  $seen = @{}
  function local:AddKnown([string]$path, [string]$label) {
    $p = Normalize-ScanFolderPath $path
    if (-not $p) { return }
    $key = $p.ToLowerInvariant()
    if ($seen.ContainsKey($key)) { return }
    $seen[$key] = $true
    $items.Add([pscustomobject]@{ Path = $p; Label = $(if ($label) { $label } else { $p }) }) | Out-Null
  }
  try {
    $net = New-Object -ComObject WScript.Network
    $drives = $net.EnumNetworkDrives()
    for ($i = 0; $i -lt $drives.Count(); $i += 2) {
      $drive = [string]$drives.Item($i)
      $remote = [string]$drives.Item($i + 1)
      if ($drive) { AddKnown ($drive.TrimEnd('\') + '\') $drive }
      if ($remote) { AddKnown $remote ("{0} {1}" -f $drive, $remote) }
    }
  } catch {}
  try {
    $mapped = @(Get-CimInstance Win32_LogicalDisk -Filter 'DriveType = 4' -ErrorAction Stop)
  } catch {
    try { $mapped = @(Get-WmiObject Win32_LogicalDisk -Filter 'DriveType = 4' -ErrorAction SilentlyContinue) } catch { $mapped = @() }
  }
  foreach ($d in @($mapped)) {
    try {
      $remote = [string]$d.ProviderName
      $drive = [string]$d.DeviceID
      if ($drive) { AddKnown ($drive.TrimEnd('\') + '\') $drive }
      if ($remote) { AddKnown $remote ("{0} {1}" -f $drive, $remote) }
    } catch {}
  }
  try {
    Get-PSDrive -PSProvider FileSystem -ErrorAction SilentlyContinue | Where-Object { $_.DisplayRoot } | ForEach-Object {
      AddKnown ([string]$_.DisplayRoot) ("{0}: {1}" -f $_.Name, $_.DisplayRoot)
    }
  } catch {}
  try {
    if (Test-Path 'HKCU:\Network') {
      Get-ChildItem 'HKCU:\Network' -ErrorAction SilentlyContinue | ForEach-Object {
        $remote = (Get-ItemProperty -LiteralPath $_.PSPath -ErrorAction SilentlyContinue).RemotePath
        $drive = "{0}:\" -f $_.PSChildName
        AddKnown $drive $drive
        if ($remote) { AddKnown ([string]$remote) ("{0}: {1}" -f $_.PSChildName, $remote) }
      }
    }
  } catch {}
  try {
    $netUse = @(cmd.exe /c net use 2>$null)
    foreach ($line in $netUse) {
      if ($line -match '^\s*(OK|Disconnected|Unavailable)?\s*([A-Z]:)\s+(\\\\\S+)') {
        AddKnown ($matches[2] + '\') $matches[2]
        AddKnown $matches[3] ("{0} {1}" -f $matches[2], $matches[3])
      }
    }
  } catch {}
  try {
    $shortcutRoot = Join-Path $env:APPDATA 'Microsoft\Windows\Network Shortcuts'
    if (Test-Path -LiteralPath $shortcutRoot) {
      $ws = New-Object -ComObject WScript.Shell
      Get-ChildItem -LiteralPath $shortcutRoot -Recurse -File -Force -Filter *.lnk -ErrorAction SilentlyContinue | ForEach-Object {
        try {
          $lnk = $ws.CreateShortcut($_.FullName)
          if ($lnk.TargetPath) { AddKnown ([string]$lnk.TargetPath) ("{0}: {1}" -f $_.BaseName, $lnk.TargetPath) }
        } catch {}
      }
    }
  } catch {}
  return @($items)
}
function script:Add-ScanFolderPath([string]$path, [switch]$NoNamePrompt) {
  $p = Normalize-ScanFolderPath $path
  if (-not $p) { [System.Windows.MessageBox]::Show('Enter or choose a folder path.','scan-av') | Out-Null; return $false }
  if (-not (Test-Path -LiteralPath $p -PathType Container)) {
    [System.Windows.MessageBox]::Show("Could not access this folder:`n$p`n`nFor network locations, try the UNC path (for example \\server\share) instead of a mapped drive letter.",'scan-av') | Out-Null
    return $false
  }
  $exists = @($script:guiCfg.scanFolders) | Where-Object { [string]::Equals((Normalize-ScanFolderPath ([string]$_)), $p, [StringComparison]::OrdinalIgnoreCase) }
  if ($exists.Count) { [System.Windows.MessageBox]::Show('That folder is already in the scan list.','scan-av') | Out-Null; return $false }
  $script:guiCfg.scanFolders = @(@($script:guiCfg.scanFolders) + $p)
  if ($NoNamePrompt) {
    Save-GuiCfg
  } else {
    Add-Type -AssemblyName Microsoft.VisualBasic
    $defaultName = Split-Path $p -Leaf
    if (-not $defaultName) { $defaultName = $p }
    $nm = [Microsoft.VisualBasic.Interaction]::InputBox(("Display name for this folder (optional):`n{0}" -f $p), 'Folder name', $defaultName)
    if ($null -ne $nm -and $nm.Trim() -ne '') { Set-FolderName $p ($nm.Trim()) } else { Save-GuiCfg }
  }
  Rebuild-Roots
  return $true
}
function script:Add-ScanFolderPaths([object[]]$paths) {
  $added = 0; $skipped = 0
  $current = @{}
  foreach ($existing in @($script:guiCfg.scanFolders)) {
    $n = Normalize-ScanFolderPath ([string]$existing)
    if ($n) { $current[$n.ToLowerInvariant()] = $true }
  }
  foreach ($p in @($paths)) {
    if (-not $p) { continue }
    $n = Normalize-ScanFolderPath ([string]$p)
    if (-not $n -or -not (Test-Path -LiteralPath $n -PathType Container)) { $skipped++; continue }
    $key = $n.ToLowerInvariant()
    if ($current.ContainsKey($key)) { $skipped++; continue }
    $script:guiCfg.scanFolders = @(@($script:guiCfg.scanFolders) + $n)
    $current[$key] = $true
    $added++
  }
  if ($added -gt 0) {
    Save-GuiCfg
    Rebuild-Roots
    [System.Windows.MessageBox]::Show(("Added {0} folder(s){1}." -f $added, $(if ($skipped) { " ($skipped skipped)" } else { '' })),'scan-av') | Out-Null
  } elseif ($skipped -gt 0) {
    [System.Windows.MessageBox]::Show('No new accessible folders were added.','scan-av') | Out-Null
  }
}
function script:Show-AddScanFolderSimpleDialog {
  try {
    Add-Type -AssemblyName PresentationFramework
    Add-Type -AssemblyName PresentationCore
    Add-Type -AssemblyName WindowsBase
    try { $known = @(Get-KnownNetworkFolders) } catch { $known = @() }
    $roots = New-Object System.Collections.Generic.List[object]
    $seenRoots = @{}
    function local:AddRoot([string]$path, [string]$label = '') {
      $p = Normalize-ScanFolderPath $path
      if (-not $p) { return }
      $key = $p.ToLowerInvariant()
      if ($seenRoots.ContainsKey($key)) { return }
      $seenRoots[$key] = $true
      if (-not $label) { $label = $p }
      [void]$roots.Add([pscustomobject]@{ Path = $p; Label = $label })
    }
    AddRoot $env:USERPROFILE 'Home'
    AddRoot (Join-Path $env:USERPROFILE 'Desktop') 'Desktop'
    AddRoot (Join-Path $env:USERPROFILE 'Downloads') 'Downloads'
    AddRoot (Join-Path $env:USERPROFILE 'Documents') 'Documents'
    foreach ($p in @($script:guiCfg.scanFolders)) { AddRoot ([string]$p) ([string]$p) }
    foreach ($k in @($known)) { AddRoot ([string]$k.Path) ([string]$k.Label) }
    try {
      foreach ($d in [System.IO.DriveInfo]::GetDrives()) {
        try {
          $label = "{0} ({1})" -f $d.Name.TrimEnd('\'), $d.DriveType
          AddRoot $d.RootDirectory.FullName $label
        } catch {}
      }
    } catch {}

    $dlg = New-Object System.Windows.Window
    $dlg.Title = 'Add scan folder'
    $dlg.Width = 760; $dlg.Height = 640; $dlg.ResizeMode = [System.Windows.ResizeMode]::CanResize
    $dlg.WindowStartupLocation = 'CenterOwner'
    if ($script:win) { $dlg.Owner = $script:win }
    $dlg.Background = (WBrush '#070910'); $dlg.Foreground = (WBrush '#FFFFFF')
    $dlg.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe UI'

    $panel = New-Object System.Windows.Controls.DockPanel
    $panel.Margin = New-Object System.Windows.Thickness 22
    $panel.LastChildFill = $true

    $top = New-Object System.Windows.Controls.StackPanel
    [System.Windows.Controls.DockPanel]::SetDock($top, [System.Windows.Controls.Dock]::Top)
    [void]$panel.Children.Add($top)

    $title = New-Object System.Windows.Controls.TextBlock
    $title.Text = 'Add scan folder'; $title.FontSize = 21; $title.FontWeight = 'SemiBold'; $title.Margin = New-Object System.Windows.Thickness 0,0,0,8
    [void]$top.Children.Add($title)
    $help = New-Object System.Windows.Controls.TextBlock
    $help.Text = 'Choose a folder below, select a mapped/network location, or paste a path such as \\server\share.'
    $help.FontSize = 13; $help.Foreground = (WBrush '#8A93A6'); $help.TextWrapping = 'Wrap'; $help.Margin = New-Object System.Windows.Thickness 0,0,0,12
    [void]$top.Children.Add($help)

    $pathBox = New-Object System.Windows.Controls.TextBox
    $pathBox.MinHeight = 34; $pathBox.Padding = New-Object System.Windows.Thickness 8,5,8,5
    $pathBox.Background = (WBrush '#11151F'); $pathBox.Foreground = (WBrush '#FFFFFF'); $pathBox.BorderBrush = (WBrush '#222A38')
    [void]$top.Children.Add($pathBox)

    $combo = New-Object System.Windows.Controls.ComboBox
    $combo.MinHeight = 32; $combo.Margin = New-Object System.Windows.Thickness 0,10,0,10
    foreach ($r in @($roots)) {
      $item = New-Object System.Windows.Controls.ComboBoxItem
      $item.Content = [string]$r.Label
      $item.Tag = [string]$r.Path
      [void]$combo.Items.Add($item)
    }
    if (-not $roots.Count) {
      $combo.IsEnabled = $false
      $item = New-Object System.Windows.Controls.ComboBoxItem
      $item.Content = 'No folders discovered'
      [void]$combo.Items.Add($item)
      $combo.SelectedIndex = 0
    }
    [void]$top.Children.Add($combo)

    $nav = New-Object System.Windows.Controls.StackPanel
    $nav.Orientation = 'Horizontal'; $nav.Margin = New-Object System.Windows.Thickness 0,0,0,10
    $open = New-Object System.Windows.Controls.Button; $open.Content = 'Open Path'; $open.MinWidth = 96; $open.Margin = New-Object System.Windows.Thickness 0,0,8,0
    $up = New-Object System.Windows.Controls.Button; $up.Content = 'Up'; $up.MinWidth = 70; $up.Margin = New-Object System.Windows.Thickness 0,0,8,0
    $refresh = New-Object System.Windows.Controls.Button; $refresh.Content = 'Refresh'; $refresh.MinWidth = 86
    try { if ($script:win) { $open.Style = $script:win.FindResource('Soft'); $up.Style = $script:win.FindResource('Soft'); $refresh.Style = $script:win.FindResource('Soft') } } catch {}
    [void]$nav.Children.Add($open); [void]$nav.Children.Add($up); [void]$nav.Children.Add($refresh)
    [void]$top.Children.Add($nav)

    $list = New-Object System.Windows.Controls.ListBox
    $list.MinHeight = 260
    $list.Background = (WBrush '#11151F'); $list.Foreground = (WBrush '#FFFFFF'); $list.BorderBrush = (WBrush '#222A38')

    $buttons = New-Object System.Windows.Controls.StackPanel
    $buttons.Orientation = 'Horizontal'; $buttons.HorizontalAlignment = 'Right'; $buttons.Margin = New-Object System.Windows.Thickness 0,12,0,0
    [System.Windows.Controls.DockPanel]::SetDock($buttons, [System.Windows.Controls.Dock]::Bottom)
    $cancel = New-Object System.Windows.Controls.Button; $cancel.Content = 'Cancel'; $cancel.MinWidth = 90; $cancel.Margin = New-Object System.Windows.Thickness 0,0,8,0
    $addAll = New-Object System.Windows.Controls.Button; $addAll.Content = 'Add All Mapped'; $addAll.MinWidth = 124; $addAll.Margin = New-Object System.Windows.Thickness 0,0,8,0; $addAll.IsEnabled = ($known.Count -gt 0)
    $add = New-Object System.Windows.Controls.Button; $add.Content = 'Add Folder'; $add.MinWidth = 104
    try { if ($script:win) { $cancel.Style = $script:win.FindResource('Soft'); $addAll.Style = $script:win.FindResource('Soft'); $add.Style = $script:win.FindResource('Primary') } } catch {}
    $state = @{ Current = '' }
    function local:LoadFolder([string]$path) {
      $p = Normalize-ScanFolderPath $path
      if (-not $p -or -not (Test-Path -LiteralPath $p -PathType Container)) {
        [System.Windows.MessageBox]::Show("Could not access this folder:`n$p",'scan-av') | Out-Null
        return
      }
      $state.Current = $p
      $pathBox.Text = $p
      $list.Items.Clear()
      try {
        $dirs = @(Get-ChildItem -LiteralPath $p -Directory -Force -ErrorAction Stop | Sort-Object Name)
        foreach ($d in $dirs) {
          $item = New-Object System.Windows.Controls.ListBoxItem
          $item.Content = $d.Name
          $item.Tag = $d.FullName
          [void]$list.Items.Add($item)
        }
        if (-not $dirs.Count) {
          $item = New-Object System.Windows.Controls.ListBoxItem
          $item.Content = '(no subfolders)'
          $item.IsEnabled = $false
          [void]$list.Items.Add($item)
        }
      } catch {
        $item = New-Object System.Windows.Controls.ListBoxItem
        $item.Content = '(cannot list subfolders)'
        $item.IsEnabled = $false
        [void]$list.Items.Add($item)
      }
    }
    $combo.Add_SelectionChanged({ try { if ($combo.SelectedItem -and $combo.SelectedItem.Tag) { LoadFolder ([string]$combo.SelectedItem.Tag) } } catch {} })
    $open.Add_Click({ LoadFolder ([string]$pathBox.Text) })
    $refresh.Add_Click({ LoadFolder ([string]$pathBox.Text) })
    $up.Add_Click({
      try {
        $parent = Split-Path ([string]$state.Current) -Parent
        if ($parent) { LoadFolder $parent }
      } catch {}
    })
    $list.Add_SelectionChanged({ try { if ($list.SelectedItem -and $list.SelectedItem.Tag) { $pathBox.Text = [string]$list.SelectedItem.Tag } } catch {} })
    $list.Add_MouseDoubleClick({ try { if ($list.SelectedItem -and $list.SelectedItem.Tag) { LoadFolder ([string]$list.SelectedItem.Tag) } } catch {} })
    $cancel.Add_Click({ try { $dlg.DialogResult = $false; $dlg.Close() } catch { $dlg.Close() } })
    $addAll.Add_Click({
      Add-ScanFolderPaths @($known | ForEach-Object { [string]$_.Path })
      try { $dlg.DialogResult = $true; $dlg.Close() } catch { $dlg.Close() }
    })
    $add.Add_Click({
      $path = [string]$pathBox.Text
      if (Add-ScanFolderPath $path -NoNamePrompt) {
        try { $dlg.DialogResult = $true; $dlg.Close() } catch { $dlg.Close() }
      }
    })
    [void]$buttons.Children.Add($cancel); [void]$buttons.Children.Add($addAll); [void]$buttons.Children.Add($add)
    [void]$panel.Children.Add($buttons)
    [void]$panel.Children.Add($list)
    $dlg.Content = $panel
    if ($combo.Items.Count -gt 0 -and $combo.IsEnabled) { $combo.SelectedIndex = 0 }
    [void]$dlg.ShowDialog()
  } catch {
    [System.Windows.MessageBox]::Show("Could not open Add Folder:`n$($_.Exception.Message)",'scan-av') | Out-Null
  }
}
function script:Show-SafeFolderPicker([string]$Title = 'Choose folder', [string]$InitialPath = '') {
  Add-Type -AssemblyName System.Windows.Forms
  Add-Type -AssemblyName System.Drawing
  $roots = New-Object System.Collections.Generic.List[string]
  $seen = @{}
  function local:AddRoot([string]$path) {
    $p = Normalize-ScanFolderPath $path
    if (-not $p) { return }
    $key = $p.ToLowerInvariant()
    if ($seen.ContainsKey($key)) { return }
    $seen[$key] = $true
    [void]$roots.Add($p)
  }
  AddRoot $InitialPath
  AddRoot $env:USERPROFILE
  AddRoot (Join-Path $env:USERPROFILE 'Desktop')
  AddRoot (Join-Path $env:USERPROFILE 'Downloads')
  AddRoot (Join-Path $env:USERPROFILE 'Documents')
  foreach ($p in @($script:guiCfg.scanFolders)) { AddRoot ([string]$p) }
  foreach ($n in @(Get-KnownNetworkFolders)) { AddRoot ([string]$n.Path) }
  try {
    foreach ($d in [System.IO.DriveInfo]::GetDrives()) {
      try {
        if ($d.IsReady -or $d.DriveType -eq [System.IO.DriveType]::Network) { AddRoot $d.RootDirectory.FullName }
      } catch {}
    }
  } catch {}

  $form = New-Object System.Windows.Forms.Form
  $form.Text = $Title
  $form.StartPosition = 'CenterScreen'
  $form.Size = New-Object System.Drawing.Size -ArgumentList 760,560
  $form.MinimumSize = New-Object System.Drawing.Size -ArgumentList 620,440
  $form.BackColor = [System.Drawing.Color]::FromArgb(7,9,16)
  $form.ForeColor = [System.Drawing.Color]::White
  $form.Font = New-Object System.Drawing.Font -ArgumentList 'Segoe UI', 9
  $form.Tag = $null

  $hint = New-Object System.Windows.Forms.Label
  $hint.Text = 'Type a path, choose a mapped/network location, or navigate folders below.'
  $hint.Left = 16; $hint.Top = 14; $hint.Width = 700; $hint.Height = 24
  $hint.ForeColor = [System.Drawing.Color]::FromArgb(199,206,218)
  [void]$form.Controls.Add($hint)

  $pathBox = New-Object System.Windows.Forms.TextBox
  $pathBox.Left = 16; $pathBox.Top = 44; $pathBox.Width = 610; $pathBox.Height = 28
  [void]$form.Controls.Add($pathBox)

  $go = New-Object System.Windows.Forms.Button
  $go.Text = 'Open'
  $go.Left = 638; $go.Top = 42; $go.Width = 86; $go.Height = 30
  [void]$form.Controls.Add($go)

  $rootBox = New-Object System.Windows.Forms.ComboBox
  $rootBox.Left = 16; $rootBox.Top = 86; $rootBox.Width = 610; $rootBox.Height = 28
  $rootBox.DropDownStyle = [System.Windows.Forms.ComboBoxStyle]::DropDownList
  foreach ($r in @($roots)) { [void]$rootBox.Items.Add($r) }
  [void]$form.Controls.Add($rootBox)

  $up = New-Object System.Windows.Forms.Button
  $up.Text = 'Up'
  $up.Left = 638; $up.Top = 84; $up.Width = 86; $up.Height = 30
  [void]$form.Controls.Add($up)

  $list = New-Object System.Windows.Forms.ListBox
  $list.Left = 16; $list.Top = 128; $list.Width = 708; $list.Height = 340
  $list.BackColor = [System.Drawing.Color]::FromArgb(17,21,31)
  $list.ForeColor = [System.Drawing.Color]::White
  [void]$form.Controls.Add($list)

  $cancel = New-Object System.Windows.Forms.Button
  $cancel.Text = 'Cancel'
  $cancel.Left = 16; $cancel.Top = 486; $cancel.Width = 96; $cancel.Height = 34
  $cancel.DialogResult = [System.Windows.Forms.DialogResult]::Cancel
  [void]$form.Controls.Add($cancel)
  $form.CancelButton = $cancel

  $select = New-Object System.Windows.Forms.Button
  $select.Text = 'Use This Folder'
  $select.Left = 584; $select.Top = 486; $select.Width = 140; $select.Height = 34
  [void]$form.Controls.Add($select)

  $state = @{ Current = '' }
  function local:SetCurrent([string]$path) {
    $p = Normalize-ScanFolderPath $path
    if (-not $p -or -not (Test-Path -LiteralPath $p -PathType Container)) {
      [System.Windows.Forms.MessageBox]::Show("Could not access this folder:`n$p",'scan-av') | Out-Null
      return
    }
    $state.Current = $p
    $pathBox.Text = $p
    $list.Items.Clear()
    try {
      $dirs = @(Get-ChildItem -LiteralPath $p -Directory -Force -ErrorAction Stop | Sort-Object Name)
      foreach ($d in $dirs) { [void]$list.Items.Add($d.FullName) }
      if (-not $dirs.Count) { [void]$list.Items.Add('(no subfolders)') }
    } catch {
      [void]$list.Items.Add('(cannot list subfolders)')
    }
  }
  $go.Add_Click({ SetCurrent ([string]$pathBox.Text) })
  $rootBox.Add_SelectedIndexChanged({ if ($rootBox.SelectedItem) { SetCurrent ([string]$rootBox.SelectedItem) } })
  $up.Add_Click({
    try {
      $parent = Split-Path ([string]$state.Current) -Parent
      if ($parent) { SetCurrent $parent }
    } catch {}
  })
  $list.Add_DoubleClick({
    try {
      $p = [string]$list.SelectedItem
      if ($p -and (Test-Path -LiteralPath $p -PathType Container)) { SetCurrent $p }
    } catch {}
  })
  $select.Add_Click({
    $p = Normalize-ScanFolderPath ([string]$pathBox.Text)
    if ($p -and (Test-Path -LiteralPath $p -PathType Container)) {
      $form.Tag = $p
      $form.DialogResult = [System.Windows.Forms.DialogResult]::OK
      $form.Close()
    } else {
      [System.Windows.Forms.MessageBox]::Show("Could not access this folder:`n$p",'scan-av') | Out-Null
    }
  })
  if ($InitialPath -and (Test-Path -LiteralPath $InitialPath -PathType Container)) {
    SetCurrent $InitialPath
  } elseif ($roots.Count) {
    $rootBox.SelectedIndex = 0
  }
  if ($form.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) { return [string]$form.Tag }
  return $null
}
function script:Show-AddScanFolderFallbackDialog([string]$reason = '') {
