    $manual = [Microsoft.VisualBasic.Interaction]::InputBox($prompt, 'Add scan folder', '')
    if ($manual -and $manual.Trim()) { [void](Add-ScanFolderPath $manual); return }
  } catch {
    [System.Windows.MessageBox]::Show("Could not open Add Folder:`n$_",'scan-av') | Out-Null
  }
}
function script:Show-AddScanFolderWinFormsDialog {
  try {
    Add-Type -AssemblyName System.Windows.Forms
    Add-Type -AssemblyName System.Drawing
    $known = @(Get-KnownNetworkFolders)
    $form = New-Object System.Windows.Forms.Form
    $form.Text = 'Add scan folder'
    $form.StartPosition = 'CenterScreen'
