    $browse = New-Object System.Windows.Forms.Button
    $browse.Text = 'Browse'
    $browse.Left = 586; $browse.Top = 46; $browse.Width = 96; $browse.Height = 30
    [void]$form.Controls.Add($browse)

    $networkLabel = New-Object System.Windows.Forms.Label
    $networkLabel.Text = 'Mapped and known network locations'
    $networkLabel.AutoSize = $false
    $networkLabel.Left = 16; $networkLabel.Top = 92; $networkLabel.Width = 660; $networkLabel.Height = 22
    $networkLabel.ForeColor = [System.Drawing.Color]::FromArgb(199,206,218)
    [void]$form.Controls.Add($networkLabel)

    $list = New-Object System.Windows.Forms.CheckedListBox
    $list.Left = 16; $list.Top = 118; $list.Width = 666; $list.Height = 270
    $list.CheckOnClick = $true
    $list.BackColor = [System.Drawing.Color]::FromArgb(17,21,31)
    $list.ForeColor = [System.Drawing.Color]::White
    if ($known.Count) {
      foreach ($k in $known) { [void]$list.Items.Add([string]$k.Label, $false) }
    } else {
      [void]$list.Items.Add('No mapped network locations found. Paste a UNC path above.', $false)
      $list.Enabled = $false
    }
    [void]$form.Controls.Add($list)

    $addOne = New-Object System.Windows.Forms.Button
    $addOne.Text = 'Add Folder'
    $addOne.Left = 272; $addOne.Top = 408; $addOne.Width = 112; $addOne.Height = 34
    [void]$form.Controls.Add($addOne)

    $addSelected = New-Object System.Windows.Forms.Button
    $addSelected.Text = 'Add Selected'
    $addSelected.Left = 394; $addSelected.Top = 408; $addSelected.Width = 122; $addSelected.Height = 34
    [void]$form.Controls.Add($addSelected)

    $addAll = New-Object System.Windows.Forms.Button
    $addAll.Text = 'Add All Mapped'
    $addAll.Left = 526; $addAll.Top = 408; $addAll.Width = 124; $addAll.Height = 34
    [void]$form.Controls.Add($addAll)

    $cancel = New-Object System.Windows.Forms.Button
    $cancel.Text = 'Cancel'
    $cancel.Left = 16; $cancel.Top = 408; $cancel.Width = 96; $cancel.Height = 34
    $cancel.DialogResult = [System.Windows.Forms.DialogResult]::Cancel
    [void]$form.Controls.Add($cancel)
    $form.CancelButton = $cancel

    $browse.Add_Click({
      try {
        $picked = Show-SafeFolderPicker 'Choose scan folder' ([string]$pathBox.Text)
        if ($picked) { $pathBox.Text = $picked }
      } catch { [System.Windows.Forms.MessageBox]::Show("Could not browse folders:`n$_",'scan-av') | Out-Null }
    })
    $list.Add_SelectedIndexChanged({
      try {
        if ($list.SelectedIndex -ge 0 -and $known.Count -gt $list.SelectedIndex) { $pathBox.Text = [string]$known[$list.SelectedIndex].Path }
      } catch {}
    })
    $addOne.Add_Click({
      try {
        if (Add-ScanFolderPath ([string]$pathBox.Text)) { $form.Close() }
      } catch { [System.Windows.Forms.MessageBox]::Show("Could not add folder:`n$_",'scan-av') | Out-Null }
    })
    $addSelected.Add_Click({
      try {
        $paths = @()
        foreach ($idx in @($list.CheckedIndices)) {
          if ($known.Count -gt [int]$idx) { $paths += [string]$known[[int]$idx].Path }
        }
        if (-not $paths.Count) { [System.Windows.Forms.MessageBox]::Show('Select one or more mapped/network locations first.','scan-av') | Out-Null; return }
        Add-ScanFolderPaths $paths
        $form.Close()
      } catch { [System.Windows.Forms.MessageBox]::Show("Could not add selected folders:`n$_",'scan-av') | Out-Null }
    })
    $addAll.Add_Click({
      try {
        $paths = @($known | ForEach-Object { [string]$_.Path })
        if (-not $paths.Count) { [System.Windows.Forms.MessageBox]::Show('No mapped/network locations were found.','scan-av') | Out-Null; return }
        Add-ScanFolderPaths $paths
        $form.Close()
      } catch { [System.Windows.Forms.MessageBox]::Show("Could not add mapped folders:`n$_",'scan-av') | Out-Null }
    })

    [void]$form.ShowDialog()
  } catch {
    Show-AddScanFolderFallbackDialog ([string]$_)
  }
}
