  function script:Rename-FolderNode($node) {
    Add-Type -AssemblyName Microsoft.VisualBasic
    $cur = Get-FolderName $node.Path; if (-not $cur) { $cur = $node.Name }
    $new = [Microsoft.VisualBasic.Interaction]::InputBox(("Display name for this folder:`n{0}" -f $node.Path), 'Folder name', $cur)
    if ($null -ne $new -and $new.Trim() -ne '') { Set-FolderName $node.Path ($new.Trim()); Render-Targets }
  }
  function script:Open-PathAction([string]$path) {
    if (-not $path -or -not (Test-Path -LiteralPath $path)) {
      [System.Windows.MessageBox]::Show('Item not found. Refresh the target list and try again.','scan-av') | Out-Null
      return
    }
    try {
      if (Test-Path -LiteralPath $path -PathType Container) { Start-Process explorer.exe -ArgumentList ('"{0}"' -f $path) }
      else { Start-Process explorer.exe -ArgumentList ('/select,"{0}"' -f $path) }
    } catch { [System.Windows.MessageBox]::Show("Could not open item:`n$_",'scan-av') | Out-Null }
  }
  function script:Open-FolderNode($node) {
    if ($node) { Open-PathAction $node.Path }
  }
  function script:Move-ConfigPathPrefix([string]$oldPath, [string]$newPath) {
    $oldFull = [IO.Path]::GetFullPath($oldPath).TrimEnd('\')
    $newFull = [IO.Path]::GetFullPath($newPath).TrimEnd('\')
    function local:MapPath([string]$p) {
      if (-not $p) { return $p }
      $full = [IO.Path]::GetFullPath($p).TrimEnd('\')
      if ($full.Equals($oldFull, [StringComparison]::OrdinalIgnoreCase)) { return $newFull }
      if ($full.StartsWith($oldFull + '\', [StringComparison]::OrdinalIgnoreCase)) { return $newFull + $full.Substring($oldFull.Length) }
      return $p
    }
    $script:guiCfg.scanFolders = @(@($script:guiCfg.scanFolders) | ForEach-Object { MapPath ([string]$_) })
    foreach ($propName in @('folderNames','folderVtAll')) {
      $prop = $script:guiCfg.PSObject.Properties[$propName]
      if (-not $prop -or -not $prop.Value) { continue }
      $next = New-Object PSObject
      foreach ($p in @($prop.Value.PSObject.Properties)) {
        Add-Member -InputObject $next -NotePropertyName (MapPath ([string]$p.Name)) -NotePropertyValue $p.Value -Force
      }
      $prop.Value = $next
    }
    Save-GuiCfg
  }
  function script:Get-PreferredMoveRoot([string]$path) {
    $roots = @(@($script:guiCfg.scanFolders) | Where-Object { $_ -and (Test-Path -LiteralPath $_) })
    $candidates = @($roots | Where-Object {
      $full = [IO.Path]::GetFullPath([string]$_).TrimEnd('\')
      (-not $path) -or -not ([IO.Path]::GetFullPath($path).TrimEnd('\').Equals($full, [StringComparison]::OrdinalIgnoreCase))
    })
    if ($candidates.Count) { return [string]$candidates[0] }
    return ''
  }
  function script:Show-MoveFolderDialog($node, [string]$PreferredDestination = '') {
    $roots = @(@($script:guiCfg.scanFolders) | Where-Object {
      $_ -and (Test-Path -LiteralPath $_) -and
      -not ([IO.Path]::GetFullPath($_).TrimEnd('\').Equals([IO.Path]::GetFullPath($node.Path).TrimEnd('\'), [StringComparison]::OrdinalIgnoreCase)) -and
      -not ([IO.Path]::GetFullPath($_).TrimEnd('\').StartsWith([IO.Path]::GetFullPath($node.Path).TrimEnd('\') + '\', [StringComparison]::OrdinalIgnoreCase))
    })
    if (-not $roots.Count) {
      [System.Windows.MessageBox]::Show('Add another scan folder first, then move items between them.','scan-av') | Out-Null
      return $null
    }

    $dlg = New-Object System.Windows.Window
    $dlg.Title = 'Move item'
    $dlg.Width = 560; $dlg.SizeToContent = 'Height'; $dlg.ResizeMode = 'NoResize'
    $dlg.WindowStartupLocation = 'CenterOwner'; $dlg.Owner = $script:win
    $dlg.Background = (WBrush '#070910'); $dlg.Foreground = (WBrush '#FFFFFF'); $dlg.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe UI'

    $panel = New-Object System.Windows.Controls.StackPanel
    $panel.Margin = New-Object System.Windows.Thickness 22

    $title = New-Object System.Windows.Controls.TextBlock
    $title.Text = 'Move or rename item'; $title.FontSize = 22; $title.FontWeight = 'SemiBold'; $title.Margin = New-Object System.Windows.Thickness 0,0,0,12
    [void]$panel.Children.Add($title)

    $from = New-Object System.Windows.Controls.TextBlock
    $from.Text = $node.Path; $from.FontSize = 12; $from.Foreground = (WBrush '#8A93A6'); $from.TextWrapping = 'Wrap'; $from.Margin = New-Object System.Windows.Thickness 0,0,0,18
    [void]$panel.Children.Add($from)

    $destLabel = New-Object System.Windows.Controls.TextBlock
    $destLabel.Text = 'Destination scan folder'; $destLabel.FontSize = 13; $destLabel.Foreground = (WBrush '#C7CEDA'); $destLabel.Margin = New-Object System.Windows.Thickness 0,0,0,6
    [void]$panel.Children.Add($destLabel)

    $dest = New-Object System.Windows.Controls.ComboBox
    $dest.MinHeight = 34; $dest.Margin = New-Object System.Windows.Thickness 0,0,0,16
    foreach ($r in $roots) { [void]$dest.Items.Add([string]$r) }
    $dest.SelectedIndex = 0
    if ($PreferredDestination) {
      for ($i = 0; $i -lt $dest.Items.Count; $i++) {
        if ([string]::Equals([string]$dest.Items[$i], $PreferredDestination, [StringComparison]::OrdinalIgnoreCase)) { $dest.SelectedIndex = $i; break }
      }
    }
    [void]$panel.Children.Add($dest)

    $nameLabel = New-Object System.Windows.Controls.TextBlock
    $nameLabel.Text = 'New name'; $nameLabel.FontSize = 13; $nameLabel.Foreground = (WBrush '#C7CEDA'); $nameLabel.Margin = New-Object System.Windows.Thickness 0,0,0,6
    [void]$panel.Children.Add($nameLabel)

    $name = New-Object System.Windows.Controls.TextBox
    $name.Text = $node.Name; $name.MinHeight = 34; $name.Padding = New-Object System.Windows.Thickness 8,5,8,5; $name.Margin = New-Object System.Windows.Thickness 0,0,0,20
    [void]$panel.Children.Add($name)

    $buttons = New-Object System.Windows.Controls.StackPanel
    $buttons.Orientation = 'Horizontal'; $buttons.HorizontalAlignment = 'Right'
    $cancel = New-Object System.Windows.Controls.Button; $cancel.Content = 'Cancel'; $cancel.MinWidth = 96; $cancel.Margin = New-Object System.Windows.Thickness 0,0,10,0
    $move = New-Object System.Windows.Controls.Button; $move.Content = 'Move'; $move.MinWidth = 104
    try { $cancel.Style = $script:win.FindResource('Soft'); $move.Style = $script:win.FindResource('Primary') } catch {}
    $cancel.Add_Click({ $dlg.DialogResult = $false; $dlg.Close() })
    $move.Add_Click({
      $newName = ([string]$name.Text).Trim()
      if (-not $newName) { [System.Windows.MessageBox]::Show('Enter a folder name.','scan-av') | Out-Null; return }
      if ($newName.IndexOfAny([IO.Path]::GetInvalidFileNameChars()) -ge 0) { [System.Windows.MessageBox]::Show('Folder name contains characters Windows cannot use.','scan-av') | Out-Null; return }
      $dlg.Tag = [pscustomobject]@{ Destination = [string]$dest.SelectedItem; Name = $newName }
      $dlg.DialogResult = $true
      $dlg.Close()
    })
    [void]$buttons.Children.Add($cancel); [void]$buttons.Children.Add($move); [void]$panel.Children.Add($buttons)
    $dlg.Content = $panel
    if ($dlg.ShowDialog() -eq $true) { return $dlg.Tag }
    return $null
  }
  function script:Move-PathWithDialog([string]$path, [string]$PreferredDestination = '') {
    if (-not $path -or -not (Test-Path -LiteralPath $path)) {
      [System.Windows.MessageBox]::Show('Item not found. Refresh the target list and try again.','scan-av') | Out-Null
      return
    }
    $item = Get-Item -LiteralPath $path -Force
    $node = [pscustomobject]@{ Path = $item.FullName; Name = $item.Name; IsFolder = [bool]$item.PSIsContainer }
    $choice = Show-MoveFolderDialog $node $PreferredDestination
    if (-not $choice) { return }
    $oldPath = [IO.Path]::GetFullPath($node.Path).TrimEnd('\')
    $destRoot = [IO.Path]::GetFullPath([string]$choice.Destination).TrimEnd('\')
    $newPath = [IO.Path]::Combine($destRoot, [string]$choice.Name)
    if ($newPath.Equals($oldPath, [StringComparison]::OrdinalIgnoreCase)) { return }
    if ($destRoot.Equals($oldPath, [StringComparison]::OrdinalIgnoreCase) -or $destRoot.StartsWith($oldPath + '\', [StringComparison]::OrdinalIgnoreCase)) {
      [System.Windows.MessageBox]::Show('Cannot move a folder into itself.','scan-av') | Out-Null
      return
    }
    if (Test-Path -LiteralPath $newPath) {
      [System.Windows.MessageBox]::Show("A folder already exists there:`n$newPath",'scan-av') | Out-Null
      return
    }
    if ([System.Windows.MessageBox]::Show(("Move this folder?`n`nFrom: {0}`nTo:   {1}" -f $oldPath, $newPath),'scan-av','YesNo','Question') -ne 'Yes') { return }
    try {
      Move-Item -LiteralPath $oldPath -Destination $newPath -ErrorAction Stop
      if ($node.IsFolder) { Move-ConfigPathPrefix $oldPath $newPath }
      Refresh-Targets
      return $newPath
    } catch {
      [System.Windows.MessageBox]::Show("Could not move folder:`n$_",'scan-av') | Out-Null
    }
  }
  function script:Move-FolderNode($node) {
    if ($node) { Move-PathWithDialog $node.Path }
  }
  function script:Choose-FolderForMove([string]$initialFolder = '') {
    return (Show-SafeFolderPicker 'Choose folder to rename or move' $initialFolder)
  }
  function script:Choose-ExecutableFile([string]$folder) {
    $dlg = New-Object System.Windows.Forms.OpenFileDialog
    $dlg.Title = 'Choose EXE to run'
    if ($folder -and (Test-Path -LiteralPath $folder -PathType Container)) { $dlg.InitialDirectory = $folder }
    $dlg.Filter = 'Executable files (*.exe)|*.exe|All files (*.*)|*.*'
    $dlg.CheckFileExists = $true
    $dlg.Multiselect = $false
    if ($dlg.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) { return $dlg.FileName }
    return $null
  }
  function script:Set-SystemEnhancedDpi([string]$path) {
    $full = [IO.Path]::GetFullPath($path)
    $key = 'HKCU:\Software\Microsoft\Windows NT\CurrentVersion\AppCompatFlags\Layers'
    New-Item -Path $key -Force | Out-Null
    New-ItemProperty -Path $key -Name $full -Value '~ GDIDPISCALING DPIUNAWARE' -PropertyType String -Force | Out-Null
  }
  function script:Run-CleanExecutable([string]$path, [bool]$SystemEnhancedDpi = $false) {
    if (-not $path -or -not (Test-Path -LiteralPath $path)) {
      [System.Windows.MessageBox]::Show('File not found.','scan-av') | Out-Null
      return
    }
    $mode = if ($SystemEnhancedDpi) { "`n`nHigh DPI scaling override: System (Enhanced)" } else { '' }
    if ([System.Windows.MessageBox]::Show(("Run this clean file now?`n`n{0}{1}" -f $path, $mode),'scan-av','YesNo','Question') -ne 'Yes') { return }
    try {
      if ($SystemEnhancedDpi) {
        if ([IO.Path]::GetExtension($path).Equals('.exe', [StringComparison]::OrdinalIgnoreCase)) {
          Set-SystemEnhancedDpi $path
        } else {
          [System.Windows.MessageBox]::Show('The System (Enhanced) DPI override can be applied to .exe files only. This file will run normally.','scan-av') | Out-Null
        }
      }
      Start-Process -FilePath $path -WorkingDirectory (Split-Path $path -Parent)
    } catch { [System.Windows.MessageBox]::Show("Could not start file:`n$_",'scan-av') | Out-Null }
  }

  function script:Ensure-TrayIcon {
    try {
      if (-not $script:trayIcon) {
        $script:trayIcon = New-Object System.Windows.Forms.NotifyIcon
        $icoPath = Join-Path $AppDir 'icon.ico'
        $script:trayIcon.Icon = $(if (Test-Path $icoPath) { New-Object System.Drawing.Icon($icoPath) } else { [System.Drawing.SystemIcons]::Shield })
        $script:trayIcon.Text = 'Scan-AV'
        $menu = New-Object System.Windows.Forms.ContextMenuStrip
        $openItem = $menu.Items.Add('Open Scan-AV')
        $exitItem = $menu.Items.Add('Exit')
        $openItem.Add_Click({ try { $script:win.Dispatcher.Invoke([action]{ Restore-FromTray }) } catch {} })
        $exitItem.Add_Click({ try { $script:win.Dispatcher.Invoke([action]{ Exit-App }) } catch {} })
        $script:trayIcon.ContextMenuStrip = $menu
        $script:trayIcon.Add_DoubleClick({ try { $script:win.Dispatcher.Invoke([action]{ Restore-FromTray }) } catch {} })
      }
      $script:trayIcon.Visible = $true
      return $script:trayIcon
    } catch { return $null }
  }
  function script:Restore-FromTray {
    try {
      if (-not $script:win) { return }
      $script:win.Show()
      if ($script:win.WindowState -eq 'Minimized') { $script:win.WindowState = 'Normal' }
      $script:win.Activate() | Out-Null
    } catch {}
  }
  function script:Hide-ToTray {
    try {
      $ti = Ensure-TrayIcon
      if ($script:win) { $script:win.Hide() }
      if ($ti) { $ti.ShowBalloonTip(3000, 'Scan-AV is still running', 'Double-click the tray icon to reopen it.', [System.Windows.Forms.ToolTipIcon]::Info) }
    } catch {}
  }
  function script:Exit-App {
    try {
      if (-not $script:win) { return }
      $script:win.Show()
      if ($script:win.WindowState -eq 'Minimized') { $script:win.WindowState = 'Normal' }
      $script:win.Activate() | Out-Null
      $script:win.Close()
    } catch {}
  }
  function script:Show-ExitChoiceDialog {
    try {
      $choice = [System.Windows.MessageBox]::Show("What do you want to do?`n`nYes = minimize to tray`nNo = quit`nCancel = stay open",'scan-av','YesNoCancel','Question')
      if ($choice -eq 'Yes') { Hide-ToTray }
      elseif ($choice -eq 'No') { Exit-App }
    } catch {}
  }
  function script:Restart-AppViaLauncher {
    try {
      $launcher = Ensure-StandaloneLauncher -Quiet
      if (-not ($launcher -and (Test-Path $launcher))) {
        [System.Windows.MessageBox]::Show("The app was updated, but ScanAV.exe could not be created.`n`nExpected path:`n$AppDir\ScanAV.exe`n`nThe app was not restarted through PowerShell.",'scan-av') | Out-Null
        return $false
      }
      Start-Process -FilePath $launcher -WorkingDirectory $AppDir
      return $true
    } catch {
      [System.Windows.MessageBox]::Show("Could not restart ScanAV.exe:`n$_",'scan-av') | Out-Null
      return $false
    }
  }
  # One-shot balloon notification via the tray (reliable for unpackaged apps, unlike
  # WinRT toasts which need a Start-menu shortcut with a registered AppUserModelID).
  function script:Show-TrayToast([string]$title, [string]$msg, [bool]$bad = $false) {
    try {
      $ti = Ensure-TrayIcon
      if (-not $ti) { return }
      $ti.ShowBalloonTip(5000, $title, $msg, $(if ($bad) { [System.Windows.Forms.ToolTipIcon]::Warning } else { [System.Windows.Forms.ToolTipIcon]::Info }))
    } catch {}
  }

function script:Get-CleanActionStartFolder($res) {
  foreach ($c in @($res.clean)) {
    $p = [string]$c.target
    if (-not $p -or -not (Test-Path -LiteralPath $p)) { continue }
    if (Test-Path -LiteralPath $p -PathType Container) { return $p }
    $parent = Split-Path $p -Parent
    if ($parent -and (Test-Path -LiteralPath $parent -PathType Container)) { return $parent }
  }
  foreach ($p in @($script:guiCfg.scanFolders)) {
    if ($p -and (Test-Path -LiteralPath $p -PathType Container)) { return [string]$p }
  }
  return ''
}
function script:Invoke-CleanRenameMove($res) {
  $start = Get-CleanActionStartFolder $res
  $folder = Choose-FolderForMove $start
  if ($folder) { [void](Move-PathWithDialog $folder (Get-PreferredMoveRoot $folder)) }
}
function script:Invoke-CleanRunExe($res, [bool]$SystemEnhancedDpi = $false) {
  $start = Get-CleanActionStartFolder $res
  $exe = Choose-ExecutableFile $start
  if (-not $exe) { return }
  if (-not [IO.Path]::GetExtension($exe).Equals('.exe', [StringComparison]::OrdinalIgnoreCase)) {
    [System.Windows.MessageBox]::Show('Choose an .exe file to run.','scan-av') | Out-Null
    return
  }
  Run-CleanExecutable $exe $SystemEnhancedDpi
}
function script:Show-CleanNextStepDialog($res) {
  $dlg = New-Object System.Windows.Window
  $dlg.Title = 'Scan complete'
  $dlg.Width = 560; $dlg.SizeToContent = 'Height'; $dlg.ResizeMode = 'NoResize'
  $dlg.WindowStartupLocation = 'CenterOwner'; $dlg.Owner = $script:win
  $dlg.Background = (WBrush '#070910'); $dlg.Foreground = (WBrush '#FFFFFF'); $dlg.FontFamily = New-Object System.Windows.Media.FontFamily 'Segoe UI'
  $dlg.Tag = 'Close'

  $panel = New-Object System.Windows.Controls.StackPanel
  $panel.Margin = New-Object System.Windows.Thickness 24

  $title = New-Object System.Windows.Controls.TextBlock
  $title.Text = 'All clean'; $title.FontSize = 24; $title.FontWeight = 'SemiBold'; $title.Foreground = (WBrush '#CFF7D8'); $title.Margin = New-Object System.Windows.Thickness 0,0,0,8
  [void]$panel.Children.Add($title)

  $summary = New-Object System.Windows.Controls.TextBlock
  $scanned = [int]$res.scanned
  $skipped = [int]$res.skipped
  $summary.Text = ("No threats were found in {0} scanned item(s){1}. Choose next step." -f $scanned, $(if ($skipped) { " ($skipped unchanged item(s) skipped)" } else { '' }))
  $summary.FontSize = 14; $summary.Foreground = (WBrush '#C7CEDA'); $summary.TextWrapping = 'Wrap'; $summary.Margin = New-Object System.Windows.Thickness 0,0,0,18
  [void]$panel.Children.Add($summary)

  $compat = New-Object System.Windows.Controls.CheckBox
  $compat.Content = 'Run EXE with compatibility settings'
  $compat.FontSize = 14; $compat.Foreground = (WBrush '#C7CEDA'); $compat.Margin = New-Object System.Windows.Thickness 0,0,0,18
  [void]$panel.Children.Add($compat)

  $buttons = New-Object System.Windows.Controls.StackPanel
  $buttons.Orientation = 'Horizontal'; $buttons.HorizontalAlignment = 'Right'
  $close = New-Object System.Windows.Controls.Button; $close.Content = 'Close'; $close.MinWidth = 96; $close.Margin = New-Object System.Windows.Thickness 0,0,10,0
  $move = New-Object System.Windows.Controls.Button; $move.Content = 'Rename + Move Folder'; $move.MinWidth = 176; $move.Margin = New-Object System.Windows.Thickness 0,0,10,0
  $run = New-Object System.Windows.Controls.Button; $run.Content = 'Run EXE'; $run.MinWidth = 104
  try { $close.Style = $script:win.FindResource('Soft'); $move.Style = $script:win.FindResource('Soft'); $run.Style = $script:win.FindResource('Primary') } catch {}
  $close.Add_Click({ $dlg.Tag = 'Close'; $dlg.DialogResult = $false; $dlg.Close() })
  $move.Add_Click({ $dlg.Tag = 'Move'; $dlg.DialogResult = $true; $dlg.Close() })
  $run.Add_Click({ $dlg.Tag = 'Run'; $dlg.DialogResult = $true; $dlg.Close() })
  [void]$buttons.Children.Add($close); [void]$buttons.Children.Add($move); [void]$buttons.Children.Add($run)
  [void]$panel.Children.Add($buttons)
  $dlg.Content = $panel

  [void]$dlg.ShowDialog()
  switch ([string]$dlg.Tag) {
    'Move' { Invoke-CleanRenameMove $res }
    'Run'  { Invoke-CleanRunExe $res ([bool]$compat.IsChecked) }
  }
}

# Render last-results.json threat cards above the raw console output. Clean runs
# use a modal next-step dialog instead of inline per-item cards.
function script:Show-RunResults($res) {
  if (-not $script:runResults) { return }
  $script:runResults.Children.Clear()
  $threats = @($res.threats)
  $clean = @($res.clean)
  if (-not $threats.Count -and (-not $clean.Count -or [int]$res.failed -gt 0)) { $script:runResultsWrap.Visibility = 'Collapsed'; return }
  if (-not $threats.Count -and $clean.Count) {
    $script:runResultsWrap.Visibility = 'Collapsed'
    Show-CleanNextStepDialog $res
    return
  }
  if ($threats.Count) {
    $script:runResultsWrap.Background = (WBrush '#170D12')
    $script:runResultsWrap.BorderBrush = (WBrush '#5A2430')
  } else {
    $script:runResultsWrap.Background = (WBrush '#0D1712')
    $script:runResultsWrap.BorderBrush = (WBrush '#255A35')
  }
  foreach ($t in $threats) {
    $card = New-Object System.Windows.Controls.Border
    $card.Background = (WBrush '#221016'); $card.CornerRadius = New-Object System.Windows.CornerRadius 10
    $card.BorderBrush = (WBrush '#6B2A38'); $card.BorderThickness = New-Object System.Windows.Thickness 1
    $card.Padding = New-Object System.Windows.Thickness 12,10,12,10; $card.Margin = New-Object System.Windows.Thickness 0,0,0,8
    $sp = New-Object System.Windows.Controls.StackPanel
    $vtTxt = if ([int]$t.vtTotal -gt 0) { "   -   VirusTotal: $($t.vtMax)/$($t.vtTotal) engines" } else { '' }
    $h = New-Object System.Windows.Controls.TextBlock
    $h.Text = ("THREAT: {0}   ({1} hit(s)){2}" -f $t.target, $t.hits, $vtTxt)
    $h.FontSize = 14; $h.FontWeight = 'SemiBold'; $h.Foreground = (WBrush '#FF8A9A'); $h.TextWrapping = 'Wrap'
    [void]$sp.Children.Add($h)
    $btns = New-Object System.Windows.Controls.StackPanel; $btns.Orientation = 'Horizontal'; $btns.Margin = New-Object System.Windows.Thickness 0,8,0,0
    if ($t.vtLink) {
      $b1 = New-Object System.Windows.Controls.Button; $b1.Style = $script:win.FindResource('Soft'); $b1.Content = 'Open VirusTotal'; $b1.Margin = New-Object System.Windows.Thickness 0,0,10,0; $b1.Tag = [string]$t.vtLink
      $b1.Add_Click({ param($s,$e) try { Start-Process ([string]$s.Tag) } catch {} })
      [void]$btns.Children.Add($b1)
    }
    $qp = @($t.qpaths | Where-Object { $_ })
    if ($qp.Count) {
      $b2 = New-Object System.Windows.Controls.Button; $b2.Style = $script:win.FindResource('Soft'); $b2.Content = 'Show in Explorer'; $b2.Margin = New-Object System.Windows.Thickness 0,0,10,0; $b2.Tag = [string]$qp[0]
      $b2.Add_Click({ param($s,$e) try { Start-Process explorer.exe -ArgumentList ('/select,"{0}"' -f [string]$s.Tag) } catch {} })
      [void]$btns.Children.Add($b2)
      $b3 = New-Object System.Windows.Controls.Button; $b3.Style = $script:win.FindResource('Soft'); $b3.Content = 'Quarantine'; $b3.Tag = @($qp)
      $b3.Add_Click({
        param($s,$e)
        $paths = @($s.Tag)
        if (([System.Windows.MessageBox]::Show(("Move {0} file(s) to quarantine? They are renamed so they can't run and can be restored later." -f $paths.Count),'scan-av','YesNo','Warning')) -ne 'Yes') { return }
        $moved = @(Invoke-Quarantine -Paths $paths -Reason 'flagged by scan (app)')
        $s.Content = $(if ($moved.Count) { "Quarantined ($($moved.Count))" } else { 'Quarantine failed - see console' })
        $s.IsEnabled = $false
      })
      [void]$btns.Children.Add($b3)
    }
    [void]$sp.Children.Add($btns)
    $card.Child = $sp
    [void]$script:runResults.Children.Add($card)
  }
  $script:runResultsWrap.Visibility = 'Visible'
}

# ---- in-app run: launch a scan-av operation hidden and stream its output to the
# run panel (no separate console). Output is redirected to a temp file that a
# DispatcherTimer (UI thread) tails - avoids cross-thread UI updates. ##PROGRESS
# marker lines emitted by the child (unit i of N) drive a real progress bar and
# are stripped from the visible console text.
$script:runTick = {
  try {
    if ($script:runOutFile -and (Test-Path $script:runOutFile)) {
      $fs = [System.IO.File]::Open($script:runOutFile, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
      [void]$fs.Seek($script:runPos, [System.IO.SeekOrigin]::Begin)
      $sr = New-Object System.IO.StreamReader($fs)
      $new = $sr.ReadToEnd(); $script:runPos = $fs.Position; $sr.Close(); $fs.Close()
      if ($new) {
        # hold back a trailing partial line so a half-written ##PROGRESS marker
        # isn't printed; it completes on the next tick
        $text = [string]$script:runCarry + $new; $script:runCarry = ''
        if ($text -notmatch "`n$") {
          $lastNl = $text.LastIndexOf("`n")
          if ($lastNl -ge 0) { $script:runCarry = $text.Substring($lastNl + 1); $text = $text.Substring(0, $lastNl + 1) }
          elseif ($text -like '##*') { $script:runCarry = $text; $text = '' }
        }
        if ($text) {
          $keep = New-Object System.Text.StringBuilder
          foreach ($ln in ($text -split "(?<=`n)")) {
            if ($ln -match '^##PROGRESS\|(\d+)\|(\d+)\|(.*?)\r?\n?$') {
              $ci = [int]$matches[1]; $cn = [Math]::Max([int]$matches[2], 1); $cnm = $matches[3].Trim()
              try {
                $script:runProgress.IsIndeterminate = $false; $script:runProgress.Maximum = $cn; $script:runProgress.Value = $ci
                $script:runTitle.Text = ("{0}   ({1}/{2}: {3})" -f $script:runBaseTitle, $ci, $cn, $cnm)
                if ($script:headerProgText) { $script:headerProgText.Text = ("{0}/{1}: {2}" -f $ci, $cn, $cnm) }
                if ($script:headerProgress) { $script:headerProgress.IsIndeterminate = $false; $script:headerProgress.Maximum = $cn; $script:headerProgress.Value = $ci }
              } catch {}
            } else { [void]$keep.Append($ln) }
          }
          if ($keep.Length) { $script:runBox.AppendText($keep.ToString()); $script:runBox.ScrollToEnd() }
        }
      }
    }
  } catch {}
  if ($script:runProc -and $script:runProc.HasExited) {
    if ($script:runTimer) { $script:runTimer.Stop() }
    $script:runProc = $null
    if ($script:runCarry) { try { $script:runBox.AppendText([string]$script:runCarry) } catch {}; $script:runCarry = '' }
    $script:runProgress.IsIndeterminate = $false; $script:runProgress.Visibility = 'Collapsed'
    $script:runTitle.Text = 'Done'
    $script:runBack.Content = 'Back to Dashboard'
    if ($script:runCancel) { $script:runCancel.Visibility = 'Collapsed' }
    if ($script:headerProgWrap) { $script:headerProgWrap.Visibility = 'Collapsed' }
    if ($script:headerProgress) { $script:headerProgress.IsIndeterminate = $true }
    # structured results (only if this run produced them - definition updates don't)
    try {
      $rf = Join-Path $AppDir 'last-results.json'
      if ((Test-Path $rf) -and $script:runStartUtc -and ((Get-Item $rf).LastWriteTimeUtc -gt $script:runStartUtc)) {
        $res = Get-Content $rf -Raw | ConvertFrom-Json
        Show-RunResults $res
        $tc = @($res.threats).Count
        if ($tc -gt 0) { Show-TrayToast 'Antivirus Scan' ("Scan finished - {0} THREAT(S) found. Review the results." -f $tc) $true }
        elseif ([int]$res.failed -gt 0) { Show-TrayToast 'Antivirus Scan' ("Scan finished - {0} item(s) could not be scanned (see logs)." -f [int]$res.failed) $true }
        else { Show-TrayToast 'Antivirus Scan' 'Scan finished - no threats found.' $false }
      }
    } catch {}
  }
}
function script:Stop-InAppRun {
  if ($script:runProc -and -not $script:runProc.HasExited) {
    try { Start-Process taskkill -ArgumentList "/PID $($script:runProc.Id) /T /F" -WindowStyle Hidden -Wait } catch {}
  }
  if ($script:runTimer) { $script:runTimer.Stop() }
  $script:runProc = $null
  $script:runCarry = ''
  $script:runProgress.IsIndeterminate = $false; $script:runProgress.Visibility = 'Collapsed'
  $script:runTitle.Text = 'Cancelled'
  $script:runBack.Content = 'Back to Dashboard'
  if ($script:runCancel) { $script:runCancel.Visibility = 'Collapsed' }
  if ($script:headerProgWrap) { $script:headerProgWrap.Visibility = 'Collapsed' }
  if ($script:headerProgress) { $script:headerProgress.IsIndeterminate = $true }   # clear stale determinate state
  if ($script:runBox) { $script:runBox.AppendText("`r`n--- cancelled by user ---`r`n"); $script:runBox.ScrollToEnd() }
}
function script:Start-InAppRun([string]$title, [string]$paramExpr) {
  # one run at a time: a second Start-Process would orphan the first child
  # (still scanning, no longer tailed, and Cancel would kill the wrong PID)
  if ($script:runProc -and -not $script:runProc.HasExited) {
    [System.Windows.MessageBox]::Show('An operation is already running. Wait for it to finish or cancel it on the Scan page.','scan-av') | Out-Null
    Show-Page 'Scan'; return
  }
  $tmp = Join-Path $env:TEMP ('scanav_run_' + [Guid]::NewGuid().ToString('N') + '.log')
  Set-Content -Path $tmp -Value '' -Encoding UTF8
  $script:runOutFile = $tmp; $script:runPos = 0
  $script:runTitle.Text = $title
  $script:runBaseTitle = $title
  $script:runCarry = ''
  $script:runStartUtc = [DateTime]::UtcNow
  if ($script:runResultsWrap) { $script:runResultsWrap.Visibility = 'Collapsed'; $script:runResults.Children.Clear() }
  $script:runBox.Text = ''
  if ($script:logListBorder) { $script:logListBorder.Visibility = 'Collapsed'; $script:logListCol.Width = New-Object System.Windows.GridLength(0) }
  $script:runProgress.IsIndeterminate = $true; $script:runProgress.Visibility = 'Visible'
  $script:runBack.Content = 'Hide'
  if ($script:runCancel) { $script:runCancel.Visibility = 'Visible' }
  if ($script:headerProgress) { $script:headerProgress.IsIndeterminate = $true }   # reset any determinate state from the previous run
  if ($script:headerProgWrap) { $script:headerProgText.Text = $title + '...'; $script:headerProgWrap.Visibility = 'Visible' }
  Show-Page 'Scan'
  $ps1q = $script:guiPs1 -replace "'", "''"; $tmpq = $tmp -replace "'", "''"
  $cmd = "& '$ps1q' $paramExpr -NoElevate -NoPrompt -Verbose *>&1 | Out-File -LiteralPath '$tmpq' -Encoding utf8"
  # Pass the command base64-encoded (-EncodedCommand). Passing it as a -Command
  # string via Start-Process -ArgumentList mangled multi-value args: e.g.
  # -Path 'a','b' collapsed into the single string "a b", so two watched folders
  # became one bogus path that scanned nothing. EncodedCommand is one opaque blob
  # with no quotes/commas for the arg parser to break.
  $enc = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($cmd))
  $psArgs = "-NoProfile -ExecutionPolicy Bypass -WindowStyle Hidden -EncodedCommand $enc"
  try { $script:runProc = Start-Process powershell.exe -ArgumentList $psArgs -WindowStyle Hidden -PassThru }
  catch { $script:runProc = $null; $script:runBox.AppendText("Failed to start: $_") }
  if (-not $script:runTimer) {
    $script:runTimer = New-Object System.Windows.Threading.DispatcherTimer
    $script:runTimer.Interval = [TimeSpan]::FromMilliseconds(400)
    $script:runTimer.add_Tick($script:runTick)
  }
  $script:runTimer.Start()
}
function script:Load-LogIntoBox([string]$path) {
  try { $script:runBox.Text = (Get-Content -LiteralPath $path -Raw -ErrorAction Stop) } catch { $script:runBox.Text = "Could not read log: $_" }
  $script:runTitle.Text = "Log: " + (Split-Path $path -Leaf)
  $script:runBox.ScrollToHome()
}
function script:New-LogButton($file) {
  $b = New-Object System.Windows.Controls.Border
  $b.Background = (WBrush '#10141E'); $b.CornerRadius = New-Object System.Windows.CornerRadius 10
  $b.BorderBrush = (WBrush '#1A2130'); $b.BorderThickness = New-Object System.Windows.Thickness 1
  $b.Margin = New-Object System.Windows.Thickness 0,0,0,8; $b.Padding = New-Object System.Windows.Thickness 12,8,12,8
  $b.Cursor = [System.Windows.Input.Cursors]::Hand; $b.Tag = $file.FullName
  $sp = New-Object System.Windows.Controls.StackPanel
  $n = New-Object System.Windows.Controls.TextBlock; $n.Text = $file.Name; $n.FontSize = 13; $n.Foreground = (WBrush '#E7ECF3'); $n.TextTrimming = 'CharacterEllipsis'
  $d = New-Object System.Windows.Controls.TextBlock; $d.Text = $file.LastWriteTime.ToString('yyyy-MM-dd HH:mm') + "   -   " + ('{0:N0} KB' -f ([math]::Max(1, $file.Length/1KB))); $d.FontSize = 11; $d.Foreground = (WBrush '#8A93A6'); $d.Margin = New-Object System.Windows.Thickness 0,2,0,0
  [void]$sp.Children.Add($n); [void]$sp.Children.Add($d); $b.Child = $sp
  $b.Add_MouseLeftButtonUp({ param($s,$e) Load-LogIntoBox ([string]$s.Tag) })
  return $b
}
function script:Show-LogsInApp {
  # while a run is active the console box belongs to its live output - loading a
  # log into it would get interleaved with new scan lines and hide Cancel
  if ($script:runProc -and -not $script:runProc.HasExited) {
    [System.Windows.MessageBox]::Show('A scan is running - its live output is on the Scan page. Open Logs after it finishes.','scan-av') | Out-Null
    Show-Page 'Scan'; return
  }
  $script:runTitle.Text = 'Logs'
  $script:runProgress.Visibility = 'Collapsed'
  $script:runBack.Content = 'Back to Dashboard'
  if ($script:runCancel) { $script:runCancel.Visibility = 'Collapsed' }
  if ($script:runResultsWrap) { $script:runResultsWrap.Visibility = 'Collapsed' }   # cards belong to the scan view
  $script:logListBorder.Visibility = 'Visible'
  $script:logListCol.Width = New-Object System.Windows.GridLength(300)
  $script:logList.Children.Clear()
  $files = @(Get-ChildItem $LogDir -Filter *.log -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending)
  if (-not $files.Count) {
    $script:runBox.Text = 'No logs yet. Run a scan first.'
  } else {
    foreach ($f in $files) { [void]$script:logList.Children.Add((New-LogButton $f)) }
    Load-LogIntoBox $files[0].FullName
  }
  Show-Page 'Scan'
}
function script:Show-Page([string]$name) {
  $pages = @{ Dashboard = $script:pageDashboard; Scan = $script:pageScan; Settings = $script:pageSettings; About = $script:pageAbout; Updates = $script:pageUpdates }
  foreach ($k in @($pages.Keys)) { if ($pages[$k]) { $pages[$k].Visibility = $(if ($k -eq $name) { 'Visible' } else { 'Collapsed' }) } }
  if ($script:navButtons) { foreach ($e in $script:navButtons.GetEnumerator()) { try { $e.Value.Tag = $(if ($e.Key -eq $name) { 'sel' } else { '' }) } catch {} } }
}

# ================================================================ GUI window
function Show-Gui {
  Add-Type -AssemblyName PresentationFramework
  Add-Type -AssemblyName PresentationCore
  Add-Type -AssemblyName WindowsBase
  Add-Type -AssemblyName System.Windows.Forms
  Add-Type -AssemblyName System.Drawing
  # give the process its own taskbar identity (so it isn't grouped/iconned as powershell.exe)
  if (-not ('Native.WinIcon' -as [type])) {
    Add-Type -Namespace Native -Name WinIcon -MemberDefinition @'
[System.Runtime.InteropServices.DllImport("user32.dll")]
public static extern System.IntPtr SendMessage(System.IntPtr hWnd, int Msg, System.IntPtr wParam, System.IntPtr lParam);
[System.Runtime.InteropServices.DllImport("shell32.dll", SetLastError=true)]
public static extern int SetCurrentProcessExplicitAppUserModelID([System.Runtime.InteropServices.MarshalAs(System.Runtime.InteropServices.UnmanagedType.LPWStr)] string AppID);
[System.Runtime.InteropServices.DllImport("shell32.dll")]
public static extern void SHChangeNotify(int eventId, int flags, System.IntPtr item1, System.IntPtr item2);
'@
  }
  try { [Native.WinIcon]::SetCurrentProcessExplicitAppUserModelID('dggomes.AntivirusScan') | Out-Null } catch {}
  $cfg = Load-Config
  if (-not $cfg) {
    [System.Windows.Forms.MessageBox]::Show('No configuration found. Run "scan-av -Install" first.','scan-av') | Out-Null
    return
  }
  $script:guiCfg = $cfg
  $ps1 = if ($PSCommandPath) { $PSCommandPath } else { Join-Path $AppDir 'scan-av.ps1' }
  $script:guiPs1 = $ps1
  try { Ensure-StandaloneLauncher -Quiet | Out-Null } catch {}
  try { Install-ContextMenu | Out-Null } catch {}
  # refresh an existing desktop shortcut so it picks up the current app icon (the
  # self-updater only refreshes the script, not the shortcut). Recreate it (keeps
  # the elevated bit) only if it already exists, then nudge Explorer's icon cache.
  try {
    $lnkPath = Join-Path ([Environment]::GetFolderPath('Desktop')) 'Scan-AV.lnk'
    if (Test-Path $lnkPath) {
      New-DesktopShortcut -Elevated $true | Out-Null
      [Native.WinIcon]::SHChangeNotify(0x08000000, 0, [IntPtr]::Zero, [IntPtr]::Zero)  # SHCNE_ASSOCCHANGED
    }
  } catch {}
  Prune-Logs
  $incOn = if ($null -ne $cfg.options.incremental) { [bool]$cfg.options.incremental } else { $true }

  $xaml = @"
<Window xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="Antivirus Scan" WindowState="Maximized" WindowStartupLocation="CenterScreen"
        Background="#070910" FontFamily="Segoe UI" Foreground="#FFFFFF">
  <Window.Resources>
    <Style x:Key="Nav" TargetType="Button">
      <Setter Property="Background" Value="Transparent"/><Setter Property="Foreground" Value="#AEB6C6"/>
      <Setter Property="Cursor" Value="Hand"/><Setter Property="Margin" Value="10,4"/><Setter Property="Height" Value="66"/>
      <Setter Property="Template"><Setter.Value><ControlTemplate TargetType="Button">
        <Border x:Name="b" Background="{TemplateBinding Background}" CornerRadius="14" Padding="6"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
        <ControlTemplate.Triggers>
          <Trigger Property="IsMouseOver" Value="True"><Setter TargetName="b" Property="Background" Value="#141A28"/></Trigger>
          <Trigger Property="Tag" Value="sel"><Setter TargetName="b" Property="Background" Value="#1C2742"/><Setter Property="Foreground" Value="#FFFFFF"/></Trigger>
        </ControlTemplate.Triggers>
      </ControlTemplate></Setter.Value></Setter>
    </Style>
    <Style x:Key="Tile" TargetType="Button">
      <Setter Property="Background" Value="#11151F"/><Setter Property="Foreground" Value="#FFFFFF"/><Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template"><Setter.Value><ControlTemplate TargetType="Button">
        <Border x:Name="b" Background="{TemplateBinding Background}" CornerRadius="16" Padding="14" BorderBrush="#1C2230" BorderThickness="1"><ContentPresenter HorizontalAlignment="Left" VerticalAlignment="Center"/></Border>
        <ControlTemplate.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter TargetName="b" Property="Background" Value="#19202E"/></Trigger></ControlTemplate.Triggers>
      </ControlTemplate></Setter.Value></Setter>
    </Style>
    <Style x:Key="Primary" TargetType="Button">
      <Setter Property="Foreground" Value="#FFFFFF"/><Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template"><Setter.Value><ControlTemplate TargetType="Button">
        <Border x:Name="b" CornerRadius="16" Padding="22,14"><Border.Background><LinearGradientBrush StartPoint="0,0" EndPoint="1,1"><GradientStop Color="#6D5BF0" Offset="0"/><GradientStop Color="#8B5CF6" Offset="1"/></LinearGradientBrush></Border.Background><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
        <ControlTemplate.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter TargetName="b" Property="Opacity" Value="0.92"/></Trigger></ControlTemplate.Triggers>
      </ControlTemplate></Setter.Value></Setter>
    </Style>
    <Style x:Key="Soft" TargetType="Button">
      <Setter Property="Background" Value="#11151F"/><Setter Property="Foreground" Value="#C7CEDA"/><Setter Property="Cursor" Value="Hand"/>
      <Setter Property="Template"><Setter.Value><ControlTemplate TargetType="Button">
        <Border x:Name="b" Background="{TemplateBinding Background}" CornerRadius="12" Padding="14,8" BorderBrush="#222A38" BorderThickness="1"><ContentPresenter HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
        <ControlTemplate.Triggers><Trigger Property="IsMouseOver" Value="True"><Setter TargetName="b" Property="Background" Value="#19202E"/></Trigger></ControlTemplate.Triggers>
      </ControlTemplate></Setter.Value></Setter>
    </Style>
  </Window.Resources>

  <Grid>
    <Grid.ColumnDefinitions><ColumnDefinition Width="104"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions>

    <Border Grid.Column="0" Background="#0B0E16">
      <StackPanel Margin="0,18">
        <Border Width="56" Height="56" CornerRadius="16" Margin="0,0,0,18" HorizontalAlignment="Center"><Border.Background><LinearGradientBrush StartPoint="0,0" EndPoint="1,1"><GradientStop Color="#6D5BF0" Offset="0"/><GradientStop Color="#8B5CF6" Offset="1"/></LinearGradientBrush></Border.Background><TextBlock Text="&#xE721;" FontFamily="Segoe MDL2 Assets" FontSize="24" Foreground="White" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border>
        <Button x:Name="NavDashboard" Style="{StaticResource Nav}"><StackPanel><TextBlock Text="&#xE80F;" FontFamily="Segoe MDL2 Assets" FontSize="22" HorizontalAlignment="Center"/><TextBlock Text="Dashboard" FontSize="12" Margin="0,4,0,0" HorizontalAlignment="Center"/></StackPanel></Button>
        <Button x:Name="NavScan" Style="{StaticResource Nav}"><StackPanel><TextBlock Text="&#xE721;" FontFamily="Segoe MDL2 Assets" FontSize="22" HorizontalAlignment="Center"/><TextBlock Text="Scan" FontSize="12" Margin="0,4,0,0" HorizontalAlignment="Center"/></StackPanel></Button>
        <Button x:Name="NavUpdates" Style="{StaticResource Nav}"><StackPanel><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="22" HorizontalAlignment="Center"/><TextBlock Text="Updates" FontSize="12" Margin="0,4,0,0" HorizontalAlignment="Center"/></StackPanel></Button>
        <Button x:Name="NavLogs" Style="{StaticResource Nav}"><StackPanel><TextBlock Text="&#xE8A5;" FontFamily="Segoe MDL2 Assets" FontSize="22" HorizontalAlignment="Center"/><TextBlock Text="Logs" FontSize="12" Margin="0,4,0,0" HorizontalAlignment="Center"/></StackPanel></Button>
        <Button x:Name="NavSettings" Style="{StaticResource Nav}"><StackPanel><TextBlock Text="&#xE713;" FontFamily="Segoe MDL2 Assets" FontSize="22" HorizontalAlignment="Center"/><TextBlock Text="Settings" FontSize="12" Margin="0,4,0,0" HorizontalAlignment="Center"/></StackPanel></Button>
        <Button x:Name="NavAbout" Style="{StaticResource Nav}"><StackPanel><TextBlock Text="&#xE946;" FontFamily="Segoe MDL2 Assets" FontSize="22" HorizontalAlignment="Center"/><TextBlock Text="About" FontSize="12" Margin="0,4,0,0" HorizontalAlignment="Center"/></StackPanel></Button>
        <TextBlock x:Name="VerLabel" Text="" FontSize="11" Foreground="#5A6270" HorizontalAlignment="Center" Margin="0,14,0,0"/>
        <TextBlock x:Name="BuildLabel" Text="" FontSize="9" Foreground="#454C5A" HorizontalAlignment="Center" Margin="0,2,0,0"/>
      </StackPanel>
    </Border>

    <Grid Grid.Column="1" Margin="28,22,28,18">
      <Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/><RowDefinition Height="Auto"/></Grid.RowDefinitions>

      <Grid Grid.Row="0" Margin="0,0,0,18">
        <Grid.ColumnDefinitions><ColumnDefinition Width="Auto"/><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions>
        <StackPanel Grid.Column="0" HorizontalAlignment="Left" VerticalAlignment="Center"><TextBlock Text="Antivirus Scan - Downloaded Files" FontSize="24" FontWeight="Bold"/><TextBlock x:Name="HeaderInfo" FontSize="14" Foreground="#8A93A6" Margin="0,4,0,0"/></StackPanel>
        <StackPanel x:Name="HeaderProgWrap" Grid.Column="1" VerticalAlignment="Center" Margin="28,0,28,0" Visibility="Collapsed">
          <TextBlock x:Name="HeaderProgText" Text="Scanning..." FontSize="12" Foreground="#8B8BF8" Margin="2,0,0,5"/>
          <ProgressBar x:Name="HeaderProgress" IsIndeterminate="True" Height="8" Background="#11151F" Foreground="#6D5BF0" BorderThickness="0"/>
        </StackPanel>
        <StackPanel Grid.Column="2" Orientation="Horizontal" HorizontalAlignment="Right" VerticalAlignment="Center">
          <Button x:Name="BtnSettings" Style="{StaticResource Soft}" Margin="0,0,10,0"><StackPanel Orientation="Horizontal"><TextBlock Text="&#xE713;" FontFamily="Segoe MDL2 Assets" FontSize="16" Margin="0,0,8,0"/><TextBlock Text="Settings" FontSize="15"/></StackPanel></Button>
          <Button x:Name="BtnExit" Style="{StaticResource Soft}" Margin="0,0,10,0"><StackPanel Orientation="Horizontal"><TextBlock Text="&#xE711;" FontFamily="Segoe MDL2 Assets" FontSize="16" Margin="0,0,8,0"/><TextBlock Text="Exit" FontSize="15"/></StackPanel></Button>
          <Button x:Name="BtnUpdate" Style="{StaticResource Soft}"><StackPanel Orientation="Horizontal"><TextBlock Text="&#xE895;" FontFamily="Segoe MDL2 Assets" FontSize="16" Margin="0,0,8,0"/><TextBlock Text="Update" FontSize="15"/></StackPanel></Button>
        </StackPanel>
      </Grid>

      <Grid Grid.Row="1">
        <!-- ===================== DASHBOARD PAGE ===================== -->
        <Grid x:Name="PageDashboard">
          <Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/></Grid.RowDefinitions>
          <Border Grid.Row="0" CornerRadius="20" BorderBrush="#3A3580" BorderThickness="1.5" Margin="0,0,0,22">
            <Border.Background><LinearGradientBrush StartPoint="0,0" EndPoint="1,0"><GradientStop Color="#141233" Offset="0"/><GradientStop Color="#0A0F18" Offset="0.6"/></LinearGradientBrush></Border.Background>
            <Grid Margin="26,22">
              <Grid.ColumnDefinitions><ColumnDefinition Width="Auto"/><ColumnDefinition Width="*"/><ColumnDefinition Width="Auto"/></Grid.ColumnDefinitions>
              <Grid Grid.Column="0" Width="120" Height="120" Margin="0,0,28,0"><Ellipse Stroke="#6D5BF0" StrokeThickness="7"/><TextBlock Text="&#xE721;" FontFamily="Segoe MDL2 Assets" FontSize="48" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Grid>
              <StackPanel Grid.Column="1" VerticalAlignment="Center">
                <TextBlock Text="Ready to scan" FontSize="30" FontWeight="Bold"/>
                <TextBlock Text="On-demand malware scanner. Run a scan to check your folders, downloads and archives." FontSize="15" Foreground="#9BA3B4" Margin="0,6,0,0" TextWrapping="Wrap"/>
                <TextBlock x:Name="HeroLast" Text="Last scan: Never" FontSize="13" Foreground="#6B7280" Margin="0,10,0,0"/>
              </StackPanel>
              <Button x:Name="ScanNow" Grid.Column="2" Style="{StaticResource Primary}" VerticalAlignment="Center">
                <StackPanel><StackPanel Orientation="Horizontal" HorizontalAlignment="Center"><TextBlock Text="&#xE721;" FontFamily="Segoe MDL2 Assets" FontSize="20" Margin="0,0,8,0"/><TextBlock Text="Scan Now" FontSize="20" FontWeight="SemiBold"/></StackPanel><TextBlock Text="Incremental" FontSize="13" Foreground="#E5E0FF" HorizontalAlignment="Center" Margin="0,4,0,0"/></StackPanel>
              </Button>
            </Grid>
          </Border>
          <Grid Grid.Row="1">
            <Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="360"/></Grid.ColumnDefinitions>
            <Grid Grid.Column="0" Margin="0,0,22,0">
              <Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="*"/></Grid.RowDefinitions>
              <Grid Grid.Row="0" Margin="0,0,0,12">
                <StackPanel HorizontalAlignment="Left"><TextBlock Text="Scan Targets" FontSize="22" FontWeight="Bold"/><TextBlock Text="Tap a row to expand  -  tap the box to select" FontSize="13" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel>
                <StackPanel Orientation="Horizontal" HorizontalAlignment="Right" VerticalAlignment="Top">
                  <Button x:Name="BtnAddTop" Style="{StaticResource Soft}" Margin="0,0,10,0"><StackPanel Orientation="Horizontal"><TextBlock Text="&#xE710;" FontFamily="Segoe MDL2 Assets" FontSize="14" Margin="0,0,8,0"/><TextBlock Text="Add" FontSize="14"/></StackPanel></Button>
                  <Button x:Name="BtnRefresh" Style="{StaticResource Soft}" Margin="0,0,10,0"><StackPanel Orientation="Horizontal"><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="14" Margin="0,0,8,0"/><TextBlock Text="Refresh" FontSize="14"/></StackPanel></Button>
                  <Button x:Name="BtnEdit" Style="{StaticResource Soft}"><StackPanel Orientation="Horizontal"><TextBlock Text="&#xE74D;" FontFamily="Segoe MDL2 Assets" FontSize="14" Margin="0,0,8,0"/><TextBlock Text="Remove" FontSize="14"/></StackPanel></Button>
                </StackPanel>
              </Grid>
              <ScrollViewer Grid.Row="1" VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly"><StackPanel x:Name="TargetsPanel"/></ScrollViewer>
            </Grid>
            <ScrollViewer Grid.Column="1" VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly">
              <StackPanel>
                <Button x:Name="TileScanAll" Style="{StaticResource Tile}" Margin="0,0,0,10" MinHeight="58"><StackPanel Orientation="Horizontal"><Border Width="40" Height="40" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE721;" FontFamily="Segoe MDL2 Assets" FontSize="20" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Scan All" FontSize="16" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="Full or incremental" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
                <Button x:Name="TileScanChecked" Style="{StaticResource Tile}" Margin="0,0,0,10" MinHeight="58"><StackPanel Orientation="Horizontal"><Border Width="40" Height="40" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE73E;" FontFamily="Segoe MDL2 Assets" FontSize="20" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Scan Checked" FontSize="16" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="Selected items" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
                <Button x:Name="TileUpdateDefs" Style="{StaticResource Tile}" Margin="0,0,0,10" MinHeight="58"><StackPanel Orientation="Horizontal"><Border Width="40" Height="40" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="20" Foreground="#54D98C" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Update Definitions" FontSize="16" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="Virus database" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
                <Button x:Name="TileLogs" Style="{StaticResource Tile}" Margin="0,0,0,10" MinHeight="58"><StackPanel Orientation="Horizontal"><Border Width="40" Height="40" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE8A5;" FontFamily="Segoe MDL2 Assets" FontSize="20" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="View Logs" FontSize="16" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="Browse scan logs" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
                <Button x:Name="TileAdd" Style="{StaticResource Tile}" Margin="0,0,0,0" MinHeight="58"><StackPanel Orientation="Horizontal"><Border Width="40" Height="40" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE710;" FontFamily="Segoe MDL2 Assets" FontSize="20" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Add Folder" FontSize="16" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="Pick a folder to scan" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
              </StackPanel>
            </ScrollViewer>
          </Grid>
        </Grid>

        <!-- ===================== SCAN PAGE ===================== -->
        <Grid x:Name="PageScan" Visibility="Collapsed">
          <Grid.RowDefinitions><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="Auto"/><RowDefinition Height="*"/><RowDefinition Height="Auto"/></Grid.RowDefinitions>
          <TextBlock x:Name="RunTitle" Grid.Row="0" Text="Scan" FontSize="24" FontWeight="Bold"/>
          <ProgressBar x:Name="RunProgress" Grid.Row="1" IsIndeterminate="True" Height="6" Margin="0,12,0,12" Background="#11151F" Foreground="#6D5BF0" BorderThickness="0" Visibility="Collapsed"/>
          <Border x:Name="RunResultsWrap" Grid.Row="2" CornerRadius="14" Background="#170D12" BorderBrush="#5A2430" BorderThickness="1" Padding="12" Margin="0,0,0,12" MaxHeight="280" Visibility="Collapsed">
            <ScrollViewer VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly"><StackPanel x:Name="RunResults"/></ScrollViewer>
          </Border>
          <Grid Grid.Row="3">
            <Grid.ColumnDefinitions><ColumnDefinition x:Name="LogListCol" Width="0"/><ColumnDefinition Width="*"/></Grid.ColumnDefinitions>
            <Border x:Name="LogListBorder" Grid.Column="0" Margin="0,0,12,0" Visibility="Collapsed"><ScrollViewer VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly"><StackPanel x:Name="LogList"/></ScrollViewer></Border>
            <Border Grid.Column="1" CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Padding="6"><TextBox x:Name="RunBox" Background="Transparent" Foreground="#C7CEDA" BorderThickness="0" IsReadOnly="True" FontFamily="Consolas" FontSize="13" TextWrapping="NoWrap" VerticalScrollBarVisibility="Auto" HorizontalScrollBarVisibility="Auto"/></Border>
          </Grid>
          <StackPanel Grid.Row="4" Orientation="Horizontal" Margin="0,14,0,0">
            <Button x:Name="RunBack" Style="{StaticResource Soft}" Content="Back to Dashboard"/>
            <Button x:Name="RunCancel" Style="{StaticResource Soft}" Content="Cancel" Margin="10,0,0,0" Visibility="Collapsed"/>
          </StackPanel>
        </Grid>

        <!-- ===================== SETTINGS PAGE ===================== -->
        <ScrollViewer x:Name="PageSettings" Visibility="Collapsed" VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly">
          <StackPanel MaxWidth="720" HorizontalAlignment="Left">
            <TextBlock Text="Settings" FontSize="24" FontWeight="Bold" Margin="0,0,0,16"/>
            <Border CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Padding="20" Margin="0,0,0,14">
              <StackPanel>
                <TextBlock Text="Engines" FontSize="16" FontWeight="SemiBold" Margin="0,0,0,10"/>
                <CheckBox x:Name="SetClamAV" Content="ClamAV" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <CheckBox x:Name="SetEmsisoft" Content="Emsisoft" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <CheckBox x:Name="SetDefender" Content="Microsoft Defender" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <CheckBox x:Name="SetThirdParty" Content="Third-party ClamAV signatures (SaneSecurity)" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
              </StackPanel>
            </Border>
            <Border CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Padding="20" Margin="0,0,0,14">
              <StackPanel>
                <TextBlock Text="VirusTotal" FontSize="16" FontWeight="SemiBold" Margin="0,0,0,6"/>
                <TextBlock TextWrapping="Wrap" Text="Optional. When set, infected files are hashed and checked against VirusTotal's multi-engine database. Get a free key at virustotal.com. Tip: the VT badge on each folder card switches that folder to also reputation-check ALL new executables, not just flagged ones." FontSize="13" Foreground="#8A93A6" Margin="0,0,0,10"/>
                <TextBlock Text="API key" FontSize="15" Margin="0,0,0,4"/>
                <TextBox x:Name="SetVtKey" FontSize="14" Padding="8,6" Background="#11151F" Foreground="#FFFFFF" BorderBrush="#222A38"/>
                <CheckBox x:Name="SetVtUpload" Content="Upload files VirusTotal doesn't know for analysis" FontSize="15" Foreground="#E7ECF3" Margin="0,14,0,0"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <TextBlock TextWrapping="Wrap" Text="Warning: uploaded files are shared with VirusTotal and its community of researchers. Never enable this for folders that may contain private or sensitive files. Max 650 MB per file; free keys allow 4 requests/min." FontSize="12" Foreground="#D9A24A" Margin="0,8,0,0"/>
              </StackPanel>
            </Border>
            <Border CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Padding="20" Margin="0,0,0,14">
              <StackPanel>
                <TextBlock Text="Scanning" FontSize="16" FontWeight="SemiBold" Margin="0,0,0,10"/>
                <CheckBox x:Name="SetIncremental" Content="Incremental (skip unchanged files)" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <CheckBox x:Name="SetModeFull" Content="Full archive contents (slower; off = executables only)" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <CheckBox x:Name="SetAutoElevate" Content="Auto-elevate for Emsisoft (run scans as admin)" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <Grid Margin="0,10,0,4"><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="120"/></Grid.ColumnDefinitions><TextBlock Grid.Column="0" Text="ClamAV max file size (MB)" FontSize="15" VerticalAlignment="Center"/><TextBox x:Name="SetMaxFile" Grid.Column="1" FontSize="15" Padding="8,6" Background="#11151F" Foreground="#FFFFFF" BorderBrush="#222A38"/></Grid>
                <Grid Margin="0,8,0,4"><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="120"/></Grid.ColumnDefinitions><TextBlock Grid.Column="0" Text="ClamAV max scan size (MB)" FontSize="15" VerticalAlignment="Center"/><TextBox x:Name="SetMaxScan" Grid.Column="1" FontSize="15" Padding="8,6" Background="#11151F" Foreground="#FFFFFF" BorderBrush="#222A38"/></Grid>
                <Grid Margin="0,8,0,4"><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="120"/></Grid.ColumnDefinitions><TextBlock Grid.Column="0" Text="Engine timeout (minutes; kills a stuck engine)" FontSize="15" VerticalAlignment="Center"/><TextBox x:Name="SetTimeout" Grid.Column="1" FontSize="15" Padding="8,6" Background="#11151F" Foreground="#FFFFFF" BorderBrush="#222A38"/></Grid>
              </StackPanel>
            </Border>
            <Border CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Padding="20" Margin="0,0,0,14">
              <StackPanel>
                <TextBlock Text="Updates" FontSize="16" FontWeight="SemiBold" Margin="0,0,0,10"/>
                <CheckBox x:Name="SetAutoUpdate" Content="Auto-update definitions before scanning" FontSize="15" Foreground="#E7ECF3" Margin="0,6"><CheckBox.LayoutTransform><ScaleTransform ScaleX="1.3" ScaleY="1.3"/></CheckBox.LayoutTransform></CheckBox>
                <Grid Margin="0,10,0,4"><Grid.ColumnDefinitions><ColumnDefinition Width="*"/><ColumnDefinition Width="120"/></Grid.ColumnDefinitions><TextBlock Grid.Column="0" Text="Only if older than (hours)" FontSize="15" VerticalAlignment="Center"/><TextBox x:Name="SetUpdateAge" Grid.Column="1" FontSize="15" Padding="8,6" Background="#11151F" Foreground="#FFFFFF" BorderBrush="#222A38"/></Grid>
              </StackPanel>
            </Border>
            <StackPanel Orientation="Horizontal" Margin="0,4,0,20">
              <Button x:Name="BtnSaveSettings" Style="{StaticResource Primary}" Content="Save settings"/>
              <Button x:Name="BtnReloadSettings" Style="{StaticResource Soft}" Content="Reload" Margin="12,0,0,0"/>
              <TextBlock x:Name="SettingsMsg" VerticalAlignment="Center" Margin="14,0,0,0" Foreground="#54D98C" FontSize="14"/>
            </StackPanel>
          </StackPanel>
        </ScrollViewer>

        <!-- ===================== ABOUT PAGE ===================== -->
        <ScrollViewer x:Name="PageAbout" Visibility="Collapsed" VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly">
          <StackPanel MaxWidth="760" HorizontalAlignment="Left">
            <TextBlock Text="About" FontSize="24" FontWeight="Bold" Margin="0,0,0,16"/>
            <Border CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Padding="22">
              <StackPanel>
                <TextBlock Text="Antivirus Scan - Downloaded Files" FontSize="20" FontWeight="Bold"/>
                <TextBlock x:Name="AboutVersion" Text="" FontSize="14" Foreground="#8A93A6" Margin="0,4,0,14"/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="An on-demand, multi-engine malware scanner for Windows. It scans folders, downloads and archives with up to three engines (ClamAV, Emsisoft, Microsoft Defender) plus VirusTotal hash lookups, and works around scanner size limits by extracting and checking the executable surface of large archives. It does not provide always-on/real-time protection."/>
                <TextBlock Text="Repository" FontSize="15" FontWeight="SemiBold" Margin="0,16,0,2"/>
                <TextBlock FontSize="15"><Hyperlink x:Name="RepoLink" NavigateUri="https://github.com/dggomes/avscan" Foreground="#8B8BF8">github.com/dggomes/avscan</Hyperlink></TextBlock>
                <TextBlock Text="Author" FontSize="15" FontWeight="SemiBold" Margin="0,16,0,2"/>
                <TextBlock Text="dggomes" FontSize="15" Foreground="#C7CEDA"/>
                <TextBlock Text="License" FontSize="15" FontWeight="SemiBold" Margin="0,16,0,2"/>
                <TextBlock Text="MIT - provided as-is, no warranty." FontSize="15" Foreground="#C7CEDA"/>
                <TextBlock Text="Attribution" FontSize="15" FontWeight="SemiBold" Margin="0,16,0,2"/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="ClamAV (Cisco Talos, GPLv2) - signature scanning engine."/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="Emsisoft Emergency Kit / a2cmd - free for private/personal use only."/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="Microsoft Defender (MpCmdRun) - built-in Windows engine."/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="SaneSecurity - optional third-party ClamAV signatures."/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="VirusTotal - optional multi-engine hash lookup (API key required)."/>
                <TextBlock TextWrapping="Wrap" FontSize="15" Foreground="#C7CEDA" Text="7-Zip (Igor Pavlov) - archive extraction."/>
                <TextBlock TextWrapping="Wrap" FontSize="13" Foreground="#6B7280" Margin="0,16,0,0" Text="Signature scanning is not proof of safety. For files from untrusted sources, verify suspicious files on a multi-engine service such as VirusTotal."/>
              </StackPanel>
            </Border>
          </StackPanel>
        </ScrollViewer>

        <!-- ===================== UPDATES PAGE ===================== -->
        <ScrollViewer x:Name="PageUpdates" Visibility="Collapsed" VerticalScrollBarVisibility="Auto" PanningMode="VerticalOnly">
          <StackPanel MaxWidth="760" HorizontalAlignment="Left">
            <TextBlock Text="Updates" FontSize="24" FontWeight="Bold" Margin="0,0,0,6"/>
            <TextBlock Text="Update the app and the scan-engine virus definitions." FontSize="14" Foreground="#8A93A6" Margin="0,0,0,16"/>
            <Button x:Name="UpdAppBtn" Style="{StaticResource Tile}" Margin="0,0,0,12" MinHeight="64"><StackPanel Orientation="Horizontal"><Border Width="44" Height="44" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xEBD3;" FontFamily="Segoe MDL2 Assets" FontSize="22" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Update App" FontSize="17" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="Download the latest app version from GitHub" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
            <Button x:Name="UpdAllBtn" Style="{StaticResource Tile}" Margin="0,0,0,12" MinHeight="64"><StackPanel Orientation="Horizontal"><Border Width="44" Height="44" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="22" Foreground="#54D98C" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Update All Definitions" FontSize="17" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="ClamAV + Emsisoft + Defender virus databases" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
            <Button x:Name="UpdClamBtn" Style="{StaticResource Tile}" Margin="0,0,0,12" MinHeight="64"><StackPanel Orientation="Horizontal"><Border Width="44" Height="44" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="22" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Update ClamAV Definitions" FontSize="17" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="freshclam - ClamAV database only" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
            <Button x:Name="UpdEmsiBtn" Style="{StaticResource Tile}" Margin="0,0,0,12" MinHeight="64"><StackPanel Orientation="Horizontal"><Border Width="44" Height="44" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="22" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Update Emsisoft Definitions" FontSize="17" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="a2cmd /update - Emsisoft database only" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
            <Button x:Name="UpdDefBtn" Style="{StaticResource Tile}" Margin="0,0,0,12" MinHeight="64"><StackPanel Orientation="Horizontal"><Border Width="44" Height="44" CornerRadius="10" Background="#1A2231"><TextBlock Text="&#xE72C;" FontFamily="Segoe MDL2 Assets" FontSize="22" Foreground="#8B8BF8" HorizontalAlignment="Center" VerticalAlignment="Center"/></Border><StackPanel VerticalAlignment="Center" Margin="14,0,0,0"><TextBlock Text="Update Defender Definitions" FontSize="17" FontWeight="SemiBold" Foreground="#FFFFFF"/><TextBlock Text="MpCmdRun -SignatureUpdate - Defender database only" FontSize="12" Foreground="#8A93A6" Margin="0,2,0,0"/></StackPanel></StackPanel></Button>
          </StackPanel>
        </ScrollViewer>
      </Grid>

      <Border Grid.Row="2" CornerRadius="14" Background="#0B0F18" BorderBrush="#1A2130" BorderThickness="1" Margin="0,18,0,0" Padding="18,12">
        <Grid>
          <StackPanel Orientation="Horizontal" HorizontalAlignment="Left"><TextBlock Text="&#xE721;" FontFamily="Segoe MDL2 Assets" FontSize="20" Foreground="#8B8BF8" VerticalAlignment="Center" Margin="0,0,12,0"/><StackPanel><TextBlock Text="On-demand scanner" FontSize="15" FontWeight="SemiBold"/><TextBlock Text="This app scans on demand - it does not provide always-on protection." FontSize="12" Foreground="#8A93A6"/></StackPanel></StackPanel>
          <StackPanel Orientation="Horizontal" HorizontalAlignment="Right" VerticalAlignment="Center"><TextBlock Text="&#xE701;" FontFamily="Segoe MDL2 Assets" FontSize="18" Foreground="#9BA3B4" Margin="0,0,18,0"/><TextBlock Text="&#xE83F;" FontFamily="Segoe MDL2 Assets" FontSize="18" Foreground="#9BA3B4" Margin="0,0,8,0"/><TextBlock x:Name="StatusTime" Text="" FontSize="15" Foreground="#C7CEDA"/></StackPanel>
        </Grid>
      </Border>
    </Grid>
  </Grid>
</Window>
"@

  try {
    $reader = New-Object System.Xml.XmlNodeReader ([xml]$xaml)
    $win = [Windows.Markup.XamlReader]::Load($reader)
  } catch {
    [System.Windows.Forms.MessageBox]::Show("Failed to build the UI: $_",'scan-av') | Out-Null
    return
  }
  $find = { param($n) $win.FindName($n) }

  # page + nav refs
  $script:pageDashboard = (& $find 'PageDashboard'); $script:pageScan = (& $find 'PageScan')
  $script:pageSettings  = (& $find 'PageSettings');  $script:pageAbout = (& $find 'PageAbout')
  $script:pageUpdates   = (& $find 'PageUpdates')
  $script:navButtons = @{ Dashboard=(& $find 'NavDashboard'); Scan=(& $find 'NavScan'); Updates=(& $find 'NavUpdates'); Logs=(& $find 'NavLogs'); Settings=(& $find 'NavSettings'); About=(& $find 'NavAbout') }

  # run / log refs
  $script:runTitle = (& $find 'RunTitle'); $script:runProgress = (& $find 'RunProgress')
  $script:runBox = (& $find 'RunBox'); $script:runBack = (& $find 'RunBack'); $script:runCancel = (& $find 'RunCancel')
  $script:logListBorder = (& $find 'LogListBorder'); $script:logListCol = (& $find 'LogListCol'); $script:logList = (& $find 'LogList')
  $script:TargetsPanel = (& $find 'TargetsPanel')
  $script:headerProgWrap = (& $find 'HeaderProgWrap'); $script:headerProgText = (& $find 'HeaderProgText')
  $script:headerProgress = (& $find 'HeaderProgress')
  $script:runResults = (& $find 'RunResults'); $script:runResultsWrap = (& $find 'RunResultsWrap')
  $script:win = $win
  $script:runCarry = ''; $script:runStartUtc = $null; $script:runBaseTitle = 'Scan'
  $script:runTimer = $null; $script:runProc = $null
  $ic = Ensure-AppIcon
  if ($ic -and (Test-Path $ic.png)) { try { $win.Icon = [System.Windows.Media.Imaging.BitmapFrame]::Create((New-Object System.Uri($ic.png))) } catch {} }
  if ($ic -and (Test-Path $ic.ico)) {
    $win.Add_SourceInitialized({
      try {
        $script:winIco = New-Object System.Drawing.Icon($ic.ico)   # keep alive for the HICON handle
        $h = (New-Object System.Windows.Interop.WindowInteropHelper($win)).Handle
        [void][Native.WinIcon]::SendMessage($h, 0x80, [IntPtr]0, $script:winIco.Handle)   # WM_SETICON small
        [void][Native.WinIcon]::SendMessage($h, 0x80, [IntPtr]1, $script:winIco.Handle)   # WM_SETICON big
      } catch {}
    })
  }

  $cfgDefHdr = if ($cfg.engines.PSObject.Properties['defender']) { [bool]$cfg.engines.defender } else { $false }
  $engHdr = ((@($(if ($cfg.engines.clamav) {'ClamAV'}), $(if ($cfg.engines.emsisoft) {'Emsisoft'}), $(if ($cfgDefHdr) {'Defender'})) | Where-Object { $_ }) -join ' ')
  (& $find 'HeaderInfo').Text = ("Engine: {0}   -   Mode: {1}   -   Incremental: {2}" -f $engHdr, $cfg.options.mode, $(if ($incOn) {'On'} else {'Off'}))
  try { $lastLog = Get-ChildItem $LogDir -Filter *.log -ErrorAction SilentlyContinue | Sort-Object LastWriteTime -Descending | Select-Object -First 1; if ($lastLog) { (& $find 'HeroLast').Text = "Last scan: " + $lastLog.LastWriteTime.ToString('ddd, HH:mm') } } catch {}
  try { (& $find 'StatusTime').Text = (Get-Date).ToString('HH:mm') } catch {}
  try { (& $find 'VerLabel').Text = "v$ScanAvVersion"; (& $find 'BuildLabel').Text = "Build $ScanAvBuild"; (& $find 'AboutVersion').Text = "Version $ScanAvVersion   -   Build $ScanAvBuild" } catch {}
  Rebuild-Roots
  # Folder-watch: poll the visible folders every few seconds and auto-refresh the
  # tree when a sub-folder is added/removed on disk (e.g. new content finishes
  # downloading) - no need to leave/return to the app or hit Refresh manually.
  $script:folderFingerprint = Get-VisibleFingerprint
  $script:folderWatchTimer = New-Object System.Windows.Threading.DispatcherTimer
  $script:folderWatchTimer.Interval = [TimeSpan]::FromSeconds(3)
  $script:folderWatchTimer.Add_Tick({
    try {
      $fp = Get-VisibleFingerprint
      if ($fp -ne $script:folderFingerprint) { $script:folderFingerprint = $fp; Refresh-Targets }
    } catch {}
  })
  $script:folderWatchTimer.Start()
  Show-Page 'Dashboard'

  # ---- settings load/save ----
  $loadSettings = {
   try {
    $o = $script:guiCfg
    (& $find 'SetClamAV').IsChecked    = [bool]$o.engines.clamav
    (& $find 'SetEmsisoft').IsChecked  = [bool]$o.engines.emsisoft
    (& $find 'SetDefender').IsChecked  = $(if ($o.engines.PSObject.Properties['defender']) { [bool]$o.engines.defender } else { $false })
    (& $find 'SetThirdParty').IsChecked = $(if ($o.options.PSObject.Properties['thirdPartySigs']) { [bool]$o.options.thirdPartySigs } else { $false })
    (& $find 'SetVtKey').Text          = $(if ($o.options.PSObject.Properties['vtApiKey']) { [string]$o.options.vtApiKey } else { '' })
    (& $find 'SetVtUpload').IsChecked  = $(if ($o.options.PSObject.Properties['vtUploadUnknown']) { [bool]$o.options.vtUploadUnknown } else { $false })
    (& $find 'SetIncremental').IsChecked = $(if ($null -ne $o.options.incremental) { [bool]$o.options.incremental } else { $true })
    (& $find 'SetModeFull').IsChecked  = ($o.options.mode -eq 'full')
    (& $find 'SetAutoElevate').IsChecked = $(if ($null -ne $o.options.autoElevate) { [bool]$o.options.autoElevate } else { $true })
    (& $find 'SetAutoUpdate').IsChecked = $(if ($null -ne $o.options.autoUpdate) { [bool]$o.options.autoUpdate } else { $true })
    (& $find 'SetMaxFile').Text   = [string]$o.options.maxFileSizeMB
    (& $find 'SetMaxScan').Text   = [string]$o.options.maxScanSizeMB
    (& $find 'SetTimeout').Text   = [string]$(if ($o.options.PSObject.Properties['engineTimeoutMinutes'] -and [int]$o.options.engineTimeoutMinutes -gt 0) { $o.options.engineTimeoutMinutes } else { 30 })
    (& $find 'SetUpdateAge').Text = [string]$(if ($o.options.updateMaxAgeHours) { $o.options.updateMaxAgeHours } else { 12 })
    (& $find 'SettingsMsg').Text = ''
   } catch { [System.Windows.MessageBox]::Show("Could not load settings:`n$_",'scan-av') | Out-Null }
  }
  $saveSettings = {
    try {
      $o = $script:guiCfg
      Set-CfgProp $o.engines 'clamav'         ([bool](& $find 'SetClamAV').IsChecked)
      Set-CfgProp $o.engines 'emsisoft'       ([bool](& $find 'SetEmsisoft').IsChecked)
      Set-CfgProp $o.engines 'defender'       ([bool](& $find 'SetDefender').IsChecked)
      Set-CfgProp $o.options 'thirdPartySigs' ([bool](& $find 'SetThirdParty').IsChecked)
      Set-CfgProp $o.options 'vtApiKey'       (([string](& $find 'SetVtKey').Text).Trim())
      Set-CfgProp $o.options 'vtUploadUnknown' ([bool](& $find 'SetVtUpload').IsChecked)
      Set-CfgProp $o.options 'incremental'    ([bool](& $find 'SetIncremental').IsChecked)
      Set-CfgProp $o.options 'mode'           $(if ((& $find 'SetModeFull').IsChecked) { 'full' } else { 'exec' })
      Set-CfgProp $o.options 'autoElevate'    ([bool](& $find 'SetAutoElevate').IsChecked)
      Set-CfgProp $o.options 'autoUpdate'     ([bool](& $find 'SetAutoUpdate').IsChecked)
      $mf = 0; if ([int]::TryParse((& $find 'SetMaxFile').Text, [ref]$mf) -and $mf -gt 0) { Set-CfgProp $o.options 'maxFileSizeMB' $mf }
      $ms = 0; if ([int]::TryParse((& $find 'SetMaxScan').Text, [ref]$ms) -and $ms -gt 0) { Set-CfgProp $o.options 'maxScanSizeMB' $ms }
      $tm = 0; if ([int]::TryParse((& $find 'SetTimeout').Text, [ref]$tm) -and $tm -gt 0) { Set-CfgProp $o.options 'engineTimeoutMinutes' $tm }
      $ua = 0; if ([int]::TryParse((& $find 'SetUpdateAge').Text, [ref]$ua) -and $ua -ge 0) { Set-CfgProp $o.options 'updateMaxAgeHours' $ua }
      Save-GuiCfg
      $incNow = [bool]$o.options.incremental
      $engStr = ((@($(if ($o.engines.clamav) {'ClamAV'}), $(if ($o.engines.emsisoft) {'Emsisoft'}), $(if ([bool](& $find 'SetDefender').IsChecked) {'Defender'})) | Where-Object { $_ }) -join ' ')
      (& $find 'HeaderInfo').Text = ("Engine: {0}   -   Mode: {1}   -   Incremental: {2}" -f $engStr, $o.options.mode, $(if ($incNow) {'On'} else {'Off'}))
      (& $find 'SettingsMsg').Text = 'Saved.'
    } catch {
      try { (& $find 'SettingsMsg').Text = 'Save failed.' } catch {}
      [System.Windows.MessageBox]::Show("Could not save settings:`n$_",'scan-av') | Out-Null
    }
  }
  & $loadSettings

  # ---- actions ----
  $confirm = { param($msg) (([System.Windows.MessageBox]::Show($msg,'scan-av','YesNo','Question')) -eq 'Yes') }
  $askScanType = {
    # returns 'full', 'inc', or $null (cancel)
    $r = [System.Windows.MessageBox]::Show("Scan type:`n`nYes = Full (re-scan everything)`nNo = Incremental (only new/changed)",'Scan type','YesNoCancel','Question')
    if ($r -eq 'Yes') { 'full' } elseif ($r -eq 'No') { 'inc' } else { $null }
  }
  $runScan = { param([string]$title, [string]$pathExpr, [bool]$full)
    $extra = if ($full) { ' -RescanAll' } else { '' }
    Start-InAppRun $title ("$pathExpr$extra")
  }
  $scanChecked = {
    $sel = @(Collect-Targets)
    if (-not $sel.Count) { [System.Windows.MessageBox]::Show('Nothing checked. Tick at least one item, or use Scan All.','scan-av') | Out-Null; return }
    $t = & $askScanType; if (-not $t) { return }
    $pathExpr = '-Path ' + (($sel | ForEach-Object { "'" + ($_ -replace "'", "''") + "'" }) -join ',')
    & $runScan ("Scanning {0} selected item(s)" -f $sel.Count) $pathExpr ($t -eq 'full')
  }
  $scanAll = {
    $t = & $askScanType; if (-not $t) { return }
    & $runScan 'Scanning all folders' '' ($t -eq 'full')
  }
  $scanNow = {
    # Scan Now = incremental on the checked items (or all if none checked)
    $sel = @(Collect-Targets)
    if (-not (& $confirm 'Run an incremental scan now?')) { return }
    if ($sel.Count) {
      $pathExpr = '-Path ' + (($sel | ForEach-Object { "'" + ($_ -replace "'", "''") + "'" }) -join ',')
      & $runScan ("Scanning {0} item(s) (incremental)" -f $sel.Count) $pathExpr $false
    } else { & $runScan 'Scanning all folders (incremental)' '' $false }
  }
  $updateDefs = { if (& $confirm 'Update virus definitions now? This refreshes ClamAV, Emsisoft and Defender.') { Start-InAppRun 'Updating definitions' '-UpdateDefs all' } }
  $doUpdateApp = {
    if (-not (& $confirm 'Check GitHub and download the latest app version?')) { return }
    $r = Update-FromGitHub
    if ($r.ok) {
      $a = [System.Windows.MessageBox]::Show("$($r.msg)`n`nRestart the app now?",'scan-av','YesNo','Question')
      if ($a -eq 'Yes') { if (Restart-AppViaLauncher) { $win.Close() } }
    } else { [System.Windows.MessageBox]::Show($r.msg,'scan-av') | Out-Null }
  }
  $showScanPage = {
    if (-not ($script:runProc -or $script:runBox.Text)) { $script:runTitle.Text = 'Scan'; $script:runProgress.Visibility = 'Collapsed'; $script:runBox.Text = 'No scan running. Start one from the Dashboard.' }
    Show-Page 'Scan'
  }

  (& $find 'ScanNow').Add_Click($scanNow)
  (& $find 'TileScanAll').Add_Click($scanAll)
  (& $find 'TileScanChecked').Add_Click($scanChecked)
  (& $find 'TileUpdateDefs').Add_Click($updateDefs)
  (& $find 'TileLogs').Add_Click({ Show-LogsInApp })
  (& $find 'TileAdd').Add_Click({ Invoke-AddScanFolderDialog })
  (& $find 'BtnAddTop').Add_Click({ Invoke-AddScanFolderDialog })
  (& $find 'BtnEdit').Add_Click({
    $tops = @($script:rootNodes | Where-Object { $_.Checked } | ForEach-Object { $_.Path })
    if (-not $tops.Count) { [System.Windows.MessageBox]::Show('Check the top-level folder(s) to remove from the scan list, then tap Remove. (Use Add to add a new folder.)','scan-av') | Out-Null; return }
    if (& $confirm ("Remove {0} folder(s) from the scan list?" -f $tops.Count)) { $script:guiCfg.scanFolders = @(@($script:guiCfg.scanFolders) | Where-Object { $tops -notcontains $_ }); Save-GuiCfg; Rebuild-Roots }
  })
  (& $find 'BtnRefresh').Add_Click({ Refresh-Targets })
  # Auto-refresh the target tree from disk whenever the window is brought forward
  # (e.g. after creating a folder in Explorer and switching back). Debounced so
  # rapid focus changes don't rebuild repeatedly.
  $script:lastTargetsRefresh = [Environment]::TickCount
  $win.Add_Activated({ if (([Environment]::TickCount - $script:lastTargetsRefresh) -gt 1500) { $script:lastTargetsRefresh = [Environment]::TickCount; try { Refresh-Targets } catch {} } })
  (& $find 'RunBack').Add_Click({ Show-Page 'Dashboard' })
  (& $find 'RunCancel').Add_Click({ if (& $confirm 'Cancel the running operation?') { Stop-InAppRun } })
  (& $find 'NavDashboard').Add_Click({ Show-Page 'Dashboard' })
  (& $find 'NavScan').Add_Click($showScanPage)
  (& $find 'NavUpdates').Add_Click({ Show-Page 'Updates' })
  (& $find 'NavLogs').Add_Click({ Show-LogsInApp })
  (& $find 'UpdAppBtn').Add_Click($doUpdateApp)
  (& $find 'UpdAllBtn').Add_Click({ if (& $confirm 'Update ALL virus definitions (ClamAV + Emsisoft + Defender) now?') { Start-InAppRun 'Updating all definitions' '-UpdateDefs all' } })
  (& $find 'UpdClamBtn').Add_Click({ if (& $confirm 'Update ClamAV definitions now?') { Start-InAppRun 'Updating ClamAV definitions' '-UpdateDefs clamav' } })
  (& $find 'UpdEmsiBtn').Add_Click({ if (& $confirm 'Update Emsisoft definitions now?') { Start-InAppRun 'Updating Emsisoft definitions' '-UpdateDefs emsisoft' } })
  (& $find 'UpdDefBtn').Add_Click({ if (& $confirm 'Update Microsoft Defender definitions now?') { Start-InAppRun 'Updating Defender definitions' '-UpdateDefs defender' } })
  (& $find 'NavSettings').Add_Click({ & $loadSettings; Show-Page 'Settings' })
  (& $find 'NavAbout').Add_Click({ Show-Page 'About' })
  (& $find 'BtnSettings').Add_Click({ & $loadSettings; Show-Page 'Settings' })
  (& $find 'BtnExit').Add_Click({ Show-ExitChoiceDialog })
  (& $find 'BtnUpdate').Add_Click($doUpdateApp)
  (& $find 'BtnSaveSettings').Add_Click($saveSettings)
  (& $find 'BtnReloadSettings').Add_Click($loadSettings)
  (& $find 'RepoLink').Add_RequestNavigate({ param($s,$e) try { Start-Process $e.Uri.AbsoluteUri } catch {}; $e.Handled = $true })

  $win.Add_Closing({
    param($s,$e)
    # closing mid-scan would leave the hidden child scanning with no UI to cancel it
    if ($script:runProc -and -not $script:runProc.HasExited) {
      $a = [System.Windows.MessageBox]::Show("A scan is still running.`n`nYes = cancel the scan and close`nNo = keep the app open",'scan-av','YesNo','Warning')
      if ($a -eq 'Yes') { try { Stop-InAppRun } catch {} } else { $e.Cancel = $true }
    }
  })
  $win.Add_Closed({
    try { if ($script:trayIcon) { $script:trayIcon.Visible = $false; $script:trayIcon.Dispose(); $script:trayIcon = $null } } catch {}
    try { if ($script:folderWatchTimer) { $script:folderWatchTimer.Stop() } } catch {}
    try { if ($script:runTimer) { $script:runTimer.Stop() } } catch {}
  })
  [void]$win.ShowDialog()
}
# ---------------------------------------------------------------- scan cache
# Tracks already-scanned items so unchanged ones are skipped. Keyed by full path;
# a "signature" of size+mtime (file) or count+size+newest-mtime (folder) detects
# changes without hashing file contents.
function Get-Signature {
  param([string]$Path)
  try {
    $it = Get-Item -LiteralPath $Path -Force -ErrorAction Stop
    if ($it.PSIsContainer) {
      $count = 0; $size = [long]0; $maxT = [long]0
      Get-ChildItem -LiteralPath $Path -Recurse -File -Force -ErrorAction SilentlyContinue | ForEach-Object {
        $count++; $size += $_.Length
        $t = $_.LastWriteTimeUtc.Ticks; if ($t -gt $maxT) { $maxT = $t }
      }
      return "D|$count|$size|$maxT"
    }
    return "F|$($it.Length)|$($it.LastWriteTimeUtc.Ticks)"
  } catch { return $null }
}
function Load-Cache {
  $h = @{}
  if (Test-Path $CacheFile) {
    try {
      $j = Get-Content $CacheFile -Raw | ConvertFrom-Json
      if ($j.entries) { foreach ($p in $j.entries.PSObject.Properties) { $h[$p.Name] = $p.Value } }
    } catch {}
  }
  return $h
}
function Save-Cache {
  param([hashtable]$Cache)
  $o = [ordered]@{ version = 1; entries = [ordered]@{} }
  foreach ($k in $Cache.Keys) { $o.entries[$k] = $Cache[$k] }
  try { ($o | ConvertTo-Json -Depth 6) | Set-Content -Path $CacheFile -Encoding UTF8 } catch { Warn "Could not save scan cache: $_" }
}
# The cache is keyed by path, so a folder MOVED between watched locations would
# normally re-scan from scratch. Its signature (file count|total size|newest
# mtime - all preserved by moves and copies) plus its name identify the same
# content at a new path: a CLEAN entry matching both is treated as this unit,
# already scanned. Only clean entries transfer - never a skipped infection.
function Find-MovedCacheEntry {
  param([hashtable]$Cache, [string]$Unit, [string]$Sig)
  if (-not $Sig -or $Sig -eq 'D|0|0|0') { return $null }   # all empty folders share this sig
  $leaf = Split-Path $Unit -Leaf
  foreach ($k in @($Cache.Keys)) {
    if ($k -ieq $Unit) { continue }
    $e = $Cache[$k]
    if ($e -and $e.result -eq 'clean' -and $e.sig -eq $Sig -and ((Split-Path $k -Leaf) -ieq $leaf)) { return $k }
  }
  return $null
}

# ================================================================ MAIN
if ($Install)          { Invoke-Install; return }
if ($InstallEngines)   { Install-Engines; return }
if ($Shortcut)         { New-DesktopShortcut -Elevated $true; return }
if ($NoPromptShortcut) { Register-NoPromptTask; return }
if ($Gui)              { Show-Gui; return }
if ($SelfUpdate)       { $r = Update-FromGitHub; if ($r.ok) { Ok $r.msg } else { Bad $r.msg }; return }
if ($InstallContextMenu) { Install-ContextMenu; return }
if ($RemoveContextMenu)  { Remove-ContextMenu; return }
if ($ListQuarantine)     { Show-Quarantine; return }
if ($RestoreQuarantine)  { Restore-QuarantineItems -Names $RestoreQuarantine; return }
if ($Configure)        { Invoke-Configure | Out-Null; return }
# update definitions only (no scan) - used by the Updates page
if ($UpdateDefs) {
  $cfg = Load-Config; if (-not $cfg) { Bad 'No config. Run -Install first.'; return }
  $eng = switch ($UpdateDefs) {
    'both' { @('clamav','emsisoft') }
    'all'  { @('clamav','emsisoft','defender') }
    default { @($UpdateDefs) }
  }
  $script:LiveScan = ($VerbosePreference -ne 'SilentlyContinue')
  Update-Definitions -Cfg $cfg -Engines $eng | Out-Null
  return
}

# Explorer right-click entry. Always run elevated: if not admin, relaunch this
# scan into a visible elevated window (one UAC prompt); if admin, scan that folder
# with default settings (incremental kept, shared cache) and no blocking prompt.
if ($ContextScan) {
  if (-not (Test-IsAdmin)) {
    try {
      $hostExe = (Get-Process -Id $PID).Path
      # -EncodedCommand: a "-File" arg quoted with a trailing backslash (e.g. the
      # drive root "C:\") escapes its own closing quote; a single-quoted PS command
      # string inside an encoded blob has no such parsing hazard.
      $cmd = "& '{0}' -ContextScan '{1}' -Verbose; Write-Host ''; Read-Host 'Finished - press Enter to close this window' | Out-Null" -f ($PSCommandPath -replace "'", "''"), ($ContextScan -replace "'", "''")
      $enc = [Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes($cmd))
      Start-Process -FilePath $hostExe -Verb RunAs -ArgumentList @('-NoProfile','-ExecutionPolicy','Bypass','-EncodedCommand', $enc)
    } catch { Bad "Elevation cancelled/failed: $_" }
    return
  }
  $Path = @($ContextScan); $NoPrompt = $true   # admin: fall through to the scan flow
}

# manage the saved scan-folder list without re-running the whole wizard
if ($AddFolder -or $RemoveFolder -or $ListFolders) {
  $cfg = Load-Config
  if (-not $cfg) { Bad 'No config yet. Run: scan-av -Install   (or scan-av -Configure)'; return }
  $list = @($cfg.scanFolders)
  foreach ($f in $AddFolder) {
    $rf = try { (Resolve-Path -LiteralPath $f -ErrorAction Stop).Path } catch { $f }
    if (-not (Test-Path -LiteralPath $rf)) { Warn "  path not found (added anyway): $rf" }
    if ($list -notcontains $rf) { $list += $rf; Ok "added: $rf" } else { Info "already present: $rf" }
  }
  foreach ($f in $RemoveFolder) {
    $rf = try { (Resolve-Path -LiteralPath $f -ErrorAction Stop).Path } catch { $f }
    if ($list -contains $rf) { $list = @($list | Where-Object { $_ -ne $rf }); Ok "removed: $rf" } else { Info "not in list: $rf" }
  }
  if ($AddFolder -or $RemoveFolder) {
    $cfg.scanFolders = @($list)
    try { ($cfg | ConvertTo-Json -Depth 6) | Set-Content -Path $CfgFile -Encoding UTF8 } catch { Bad "Could not save config: $_"; return }
  }
  Sec 'Configured scan folders'
  if (@($cfg.scanFolders).Count) { @($cfg.scanFolders) | ForEach-Object { Info "  $_" } } else { Info '  (none)' }
  return
}

$cfg = Load-Config
if (-not $cfg) { Warn 'No config found - running first-run setup.'; $cfg = Invoke-Configure; if (-not $cfg) { return } }

# which engines this run
$engines = @()
$cfgDef  = if ($cfg.engines.PSObject.Properties['defender']) { [bool]$cfg.engines.defender } else { $false }
$toolDef = if ($cfg.tools.PSObject.Properties['defender'])   { $cfg.tools.defender } else { $null }
$want = if ($Engine -eq 'config') { @{clamav=$cfg.engines.clamav; emsisoft=$cfg.engines.emsisoft; defender=$cfgDef} }
        elseif ($Engine -eq 'both') { @{clamav=$true; emsisoft=$true; defender=$false} }
        elseif ($Engine -eq 'all')  { @{clamav=$true; emsisoft=$true; defender=$true} }
        else { @{clamav=($Engine -eq 'clamav'); emsisoft=($Engine -eq 'emsisoft'); defender=($Engine -eq 'defender')} }
if ($want.clamav   -and $cfg.tools.clamscan) { $engines += 'clamav' }
if ($want.emsisoft -and $cfg.tools.a2cmd)    { $engines += 'emsisoft' }
if ($want.defender) { if (-not $toolDef) { $toolDef = Find-Defender; if ($toolDef) { $cfg.tools | Add-Member -NotePropertyName defender -NotePropertyValue $toolDef -Force } }
                      if ($toolDef) { $engines += 'defender' } }
if (-not $engines) { Bad 'No usable engine for this run (check config / -Engine).'; return }
if ($Full) { $cfg.options.mode = 'full' }

# Auto-elevate: Emsisoft's a2cmd requires admin and self-elevates into a separate
# window mid-scan. Relaunch the whole run elevated first (ONE UAC prompt) so a2cmd
# runs inline. Skipped if already admin (e.g. launched from the elevated shortcut),
# if -NoElevate, if config disables it, or if Emsisoft isn't part of this run.
$autoElev = if ($null -ne $cfg.options.autoElevate) { [bool]$cfg.options.autoElevate } else { $true }
if (($engines -contains 'emsisoft') -and $autoElev -and -not $NoElevate -and -not (Test-IsAdmin)) {
  Info 'Emsisoft needs admin - relaunching elevated (one UAC prompt)...'
  if (Invoke-RelaunchElevated -Bound $PSBoundParameters) { return }
  Warn 'Not elevated; Emsisoft may open its own UAC window. (Use -NoElevate to silence this, or -Engine clamav.)'
}

# -Verbose streams each engine's live per-file output to the console
$script:LiveScan = ($VerbosePreference -ne 'SilentlyContinue')
if ($script:LiveScan) { Info 'Verbose: streaming live engine output.' }

# definition updates: -Update forces; -NoUpdate skips; otherwise auto-update when the
# config enables it AND definitions are older than options.updateMaxAgeHours.
$doUpdate = $false
if ($Update) {
  $doUpdate = $true
} elseif (-not $NoUpdate) {
  $auto = if ($null -ne $cfg.options.autoUpdate) { [bool]$cfg.options.autoUpdate } else { $true }
  if ($auto) {
    $maxAge = if ($cfg.options.updateMaxAgeHours) { [double]$cfg.options.updateMaxAgeHours } else { 12 }
    $stamp  = Join-Path $AppDir 'last-update.txt'
    $ageH   = $null
    if (Test-Path $stamp) {
      try { $ageH = ([DateTime]::UtcNow - [DateTime]::Parse((Get-Content $stamp -Raw).Trim()).ToUniversalTime()).TotalHours } catch { $ageH = $null }
    }
    if (($null -eq $ageH) -or ($ageH -ge $maxAge)) { $doUpdate = $true }
    else { Info ("Definitions updated {0:N1}h ago (< {1}h) - skipping. Use -Update to force." -f $ageH, $maxAge) }
  }
}
if ($doUpdate) { Update-Definitions -Cfg $cfg -Engines $engines | Out-Null }

# targets
$targets = if ($Path) { $Path } else { $cfg.scanFolders }
if (-not $targets) { Warn 'Nothing to scan. Pass -Path <file/folder> or add folders via -Configure.'; return }

# incremental scan-cache: skip already-scanned, unchanged items
$incremental = if ($null -ne $cfg.options.incremental) { [bool]$cfg.options.incremental } else { $true }
if ($NoIncremental) { $incremental = $false }
$cache = if ($incremental) { Load-Cache } else { @{} }

# Feature: ask whether to re-scan everything or only new/changed (when a cache exists)
$rescanAll = [bool]$RescanAll
# Only prompt in a real interactive console. -NoPrompt (used by the app's hidden
# child process) skips it - otherwise Read-Host blocks forever with no console.
if ($incremental -and -not $rescanAll -and -not $NoPrompt -and $cache.Count -gt 0) {
  try {
    $ans = Read-Host 'Re-scan ALL items, or only NEW/CHANGED since last scan? (a = All / Enter = new only)'
    if ($ans -match '^\s*[Aa]') { $rescanAll = $true }
  } catch {}   # non-interactive host -> keep new-only
}

# Expand targets into per-child units so unchanged items get skipped on later runs.
# A target is a LIBRARY only if it's one of the user's CONFIGURED scan folders (a
# parent the user is watching): it's expanded so each sub-folder/file
# is its own cache unit, which means a NEW or moved-in sub-folder is always a fresh
# unit that gets scanned - never hidden inside the parent's single cache entry.
# Anything else (a specific folder picked via Scan Checked, a context-menu folder, a
# sub-folder of a library) is CONTENT: scanned as ONE recursive unit. That avoids
# splitting content into its internal folders, and avoids the per-file clamscan
# DB-reload storm (each clamscan invocation reloads the whole ~3.6M-sig DB).
$rootSet = @{}
foreach ($rf in @($cfg.scanFolders)) { if ($rf) { $rootSet[([string]$rf).TrimEnd('\','/').ToLowerInvariant()] = $true } }
$units = @()
foreach ($t in $targets) {
  $isRoot = $rootSet.ContainsKey(([string]$t).TrimEnd('\','/').ToLowerInvariant())
  if ($incremental -and $isRoot -and (Test-Path -LiteralPath $t -PathType Container)) {
    $kids = @(Get-ChildItem -LiteralPath $t -Force -ErrorAction SilentlyContinue)
    $subDirs    = @($kids | Where-Object { $_.PSIsContainer })
    $looseFiles = @($kids | Where-Object { -not $_.PSIsContainer })
    if ($subDirs.Count -gt 0) {
      $subDirs    | ForEach-Object { $units += $_.FullName }   # each immediate child folder = its own unit
      $looseFiles | ForEach-Object { $units += $_.FullName }   # loose archives/files at the root
    } else {
      $units += $t   # library with no sub-folders yet -> scan whole
    }
  } else { $units += $t }   # a specific content folder -> one recursive scan
}

New-Item -ItemType Directory -Force -Path $LogDir | Out-Null
Prune-Logs
$tag = if ($incremental -and -not $rescanAll) { ' (incremental)' } elseif ($rescanAll) { ' (rescan all)' } else { '' }
Sec ("scan-av  -  engines: {0}   mode: {1}   items: {2}{3}" -f ($engines -join '+'), $cfg.options.mode, @($units).Count, $tag)

# Diagnostic plan written to the (synced) log dir: what was configured, what
# targets this run used, how they expanded into units, and each unit's outcome.
# Lets a "nothing new" run be explained: is the folder watched? new unit? cached?
$plan = New-Object System.Collections.Generic.List[string]
[void]$plan.Add(("scan-av plan  {0}" -f ([DateTime]::Now.ToString('yyyy-MM-dd HH:mm:ss'))))
[void]$plan.Add(("incremental={0}  rescanAll={1}  engines={2}" -f $incremental, $rescanAll, ($engines -join '+')))
[void]$plan.Add(("configured scanFolders ({0}):" -f @($cfg.scanFolders).Count))
foreach ($f in @($cfg.scanFolders)) { [void]$plan.Add("    [root] $f") }
[void]$plan.Add(("targets this run ({0}):" -f @($targets).Count))
foreach ($t in @($targets)) { [void]$plan.Add(("    {0}{1}" -f $t, $(if ($rootSet.ContainsKey(([string]$t).TrimEnd('\','/').ToLowerInvariant())) { '   <- watched root (expanded)' } else { '   <- single item (whole scan)' }))) }
[void]$plan.Add(("expanded into {0} unit(s):" -f @($units).Count))

$all = @(); $skipped = 0

# ---- pass 1: decide, per unit, scan vs cached (lets ClamAV batch what follows) ----
$toScan = @(); $sigs = @{}
foreach ($u in $units) {
  $sig = if ($incremental) { Get-Signature $u } else { $null }
  $sigs[$u] = $sig
  $entry = $cache[$u]
  if ($incremental -and -not $rescanAll -and $entry -and ($entry.result -eq 'clean') -and $sig -and ($entry.sig -eq $sig)) {
    Ok ("cached (clean), skipping: {0}" -f (Split-Path $u -Leaf)); $skipped++
    [void]$plan.Add(("    [CACHED] {0}" -f $u)); continue
  }
  # not cached at THIS path - same name+signature cached clean elsewhere means the
  # item was moved (or copied) between folders; migrate the entry instead of re-scanning
  if ($incremental -and -not $rescanAll -and $sig -and -not $entry) {
    $movedFrom = Find-MovedCacheEntry -Cache $cache -Unit $u -Sig $sig
    if ($movedFrom) {
      Ok ("cached (clean, moved), skipping: {0}   (was: {1})" -f (Split-Path $u -Leaf), $movedFrom); $skipped++
      $mvUtc = [string]$cache[$movedFrom].utc; if (-not $mvUtc) { $mvUtc = [DateTime]::UtcNow.ToString('o') }
      $cache[$u] = @{ sig = $sig; utc = $mvUtc; result = 'clean' }
      if (-not (Test-Path -LiteralPath $movedFrom)) { $cache.Remove($movedFrom) }   # a copy keeps both entries
      [void]$plan.Add(("    [CACHED] {0}   (moved from {1})" -f $u, $movedFrom)); continue
    }
  }
  [void]$plan.Add(("    [SCAN]   {0}{1}" -f $u, $(if (-not $entry) { '   (new - not in cache)' } elseif (-not $sig) { '   (no signature)' } else { '   (changed since last scan)' })))
  $toScan += $u
}

# ---- ClamAV batch: ONE signature-database load for all in-place units, instead
# of a multi-second DB reload per unit. Archives are excluded (each needs its own
# extraction) and keep their per-unit clamscan of the extracted surface.
$clamBatch = $null
if (($engines -contains 'clamav') -and $cfg.tools.clamscan) {
  $direct = @($toScan | Where-Object {
    (Test-Path -LiteralPath $_) -and
    ((Test-Path -LiteralPath $_ -PathType Container) -or ($ArchiveExt -notcontains ([IO.Path]::GetExtension($_).ToLower())))
  })
  if ($direct.Count -gt 1) {
    Sec ("ClamAV batch - scanning {0} item(s) with one database load" -f $direct.Count)
    if ($NoPrompt) { Write-Host ("##PROGRESS|0|{0}|ClamAV batch scan" -f @($toScan).Count) }
    $blog = Join-Path $LogDir ("clamav_batch_{0}.log" -f (Get-Random))
    $clamBatch = Invoke-ClamBatch -Targets $direct -Cfg $cfg -Log $blog
    Info "    log: $blog"
  }
}

# ---- per-folder VirusTotal mode: roots the user marked "VT: all files" ----
$vtAllRoots = @{}
try {
  if ($cfg.PSObject.Properties['folderVtAll']) {
    foreach ($p in $cfg.folderVtAll.PSObject.Properties) {
      if ([bool]$p.Value) { $vtAllRoots[([string]$p.Name).TrimEnd('\','/').ToLowerInvariant()] = $true }
    }
  }
} catch {}

# ---- pass 2: scan ----
$idx = 0
foreach ($u in $toScan) {
  $idx++
  # progress marker parsed by the app's scan page (its child runs pass -NoPrompt)
  if ($NoPrompt) { Write-Host ("##PROGRESS|{0}|{1}|{2}" -f $idx, @($toScan).Count, (Split-Path $u -Leaf)) }
  $preset = $null
  if ($clamBatch -and $clamBatch.Contains($u)) { $preset = @{ clamav = $clamBatch[$u] } }
  # does this unit live under a root marked "VT all files" (or -VtAll this run)?
  $unitVtAll = [bool]$VtAll
  if (-not $unitVtAll -and $vtAllRoots.Count) {
    $lu = ([string]$u).TrimEnd('\','/').ToLowerInvariant()
    foreach ($rk in $vtAllRoots.Keys) { if ($lu -eq $rk -or $lu.StartsWith($rk + '\')) { $unitVtAll = $true; break } }
  }
  $prevUtc = $null
  if (-not $rescanAll) {
    $entry = $cache[$u]
    if ($entry -and $entry.utc) { try { $prevUtc = [DateTime]::Parse([string]$entry.utc).ToUniversalTime() } catch {} }
  }
  $r = Scan-Target -Target $u -Cfg $cfg -Engines $engines -Preset $preset -VtAllFiles $unitVtAll -PrevScanUtc $prevUtc
  if ($r) {
    $all += $r
    if ($incremental) {
      $sig = $sigs[$u]
      # Only cache CLEAN + VALID results: Hits=0 with $r.Valid=$false means every
      # engine errored - caching that would skip a never-scanned item forever.
      if ($r.Hits -eq 0 -and $r.Valid) { $cache[$u] = @{ sig = $sig; utc = ([DateTime]::UtcNow.ToString('o')); result = 'clean' } }
      elseif ($cache.ContainsKey($u)) { $cache.Remove($u) }   # infected/errored -> don't remember as clean
    }
  }
}
if ($incremental) { Save-Cache -Cache $cache }
[void]$plan.Add(("result: scanned={0}  cached/skipped={1}" -f $all.Count, $skipped))
try { ($plan -join "`r`n") | Set-Content -LiteralPath (Join-Path $LogDir ("_scan-plan_{0}.log" -f ([DateTime]::Now.ToString('yyyyMMdd_HHmmss')))) -Encoding UTF8 } catch {}

# final summary
Write-Host ''
Sec 'SUMMARY'
$threats = @($all | Where-Object { $_.Hits -gt 0 })
$failed  = @($all | Where-Object { $_.Hits -eq 0 -and -not $_.Valid })
$clean   = @($all | Where-Object { $_.Hits -eq 0 -and $_.Valid })
foreach ($r in $all) {
  if ($r.Hits -gt 0) {
    $vtStr = ''
    $vk = @($r.Vt | Where-Object { $_.Status -eq 'ok' })
    if ($vk.Count) {
      $m = 0; $t = 0
      foreach ($v in $vk) { $s = [int]$v.Malicious + [int]$v.Suspicious; if ($s -ge $m) { $m = $s; $t = [int]$v.Total } }
      $vtStr = "  [VT: $m/$t]"
    }
    Bad ("  THREAT  {0}  ({1} hit(s)){2}" -f $r.Target, $r.Hits, $vtStr)
  }
  elseif (-not $r.Valid) { Warn ("  error   {0}  (NOT scanned - engine/extraction failure, will retry next run)" -f $r.Target) }
  else                   { Ok  ("  clean   {0}" -f $r.Target) }
}
if ($skipped -gt 0) { Info ("  cached  {0} unchanged item(s) skipped" -f $skipped) }
Write-Host ''
if ($threats)               { Bad ("{0} of {1} scanned item(s) flagged. Review logs in $LogDir and verify on VirusTotal." -f $threats.Count, $all.Count) }
elseif ($failed.Count)      { Warn ("{0} item(s) could NOT be scanned (see logs in $LogDir); the rest are clean. They will be retried next run." -f $failed.Count) }
elseif ($all.Count -eq 0)   { Ok  ("Nothing new - all {0} item(s) already scanned & unchanged. (Choose 'Full' to re-scan everything.)" -f $skipped) }
else                        { Ok  ("All {0} scanned item(s) clean{1}." -f $all.Count, $(if ($skipped) { " ($skipped skipped, unchanged)" } else { '' })) }

# Structured results for the app (results cards + completion toast).
try {
  $tRecs = @($threats | ForEach-Object {
    $vk = @($_.Vt | Where-Object { $_.Status -eq 'ok' })
    $m = 0; $t = 0
    foreach ($v in $vk) { $s = [int]$v.Malicious + [int]$v.Suspicious; if ($s -ge $m) { $m = $s; $t = [int]$v.Total } }
    $shas = @($_.Vt | ForEach-Object { $_.Sha } | Where-Object { $_ })
    @{ target = $_.Target; hits = [int]$_.Hits; vtMax = $m; vtTotal = $t
       vtLink = $(if ($shas.Count) { 'https://www.virustotal.com/gui/file/' + $shas[0] } else { '' })
       qpaths = @($_.QPaths) }
  })
  $setupLikeName = '(?i)(^|[\s._-])(setup|install|installer|redist|vcredist|dxsetup)([\s._-]|$)'
  $cRecs = @($clean | ForEach-Object {
    $target = [string]$_.Target
    $name = Split-Path $target -Leaf
    $kind = 'clean item'
    $runnablePath = ''
    $isFolder = $false
    try {
      if (Test-Path -LiteralPath $target -PathType Container) {
        $isFolder = $true
        $preferredExecutable = Get-ChildItem -LiteralPath $target -Recurse -File -Force -ErrorAction SilentlyContinue |
          Where-Object { $_.Extension -match '^\.(msi|msix|appx|exe)$' -and ($_.BaseName -match $setupLikeName) } |
          Select-Object -First 1
        if ($preferredExecutable) {
          $kind = 'folder with launchable file'
        } else {
          $exe = Get-ChildItem -LiteralPath $target -Recurse -File -Force -ErrorAction SilentlyContinue -Filter *.exe | Select-Object -First 1
          $kind = if ($exe) { 'folder with executable' } else { 'clean folder' }
        }
      } else {
        $ext = [IO.Path]::GetExtension($target).ToLowerInvariant()
        if ($ext -in @('.msi','.msix','.appx')) {
          $kind = 'launchable package'
          $runnablePath = $target
        } elseif ($ext -eq '.exe' -and ([IO.Path]::GetFileNameWithoutExtension($target) -match $setupLikeName)) {
          $kind = 'launchable executable'
          $runnablePath = $target
        } elseif ($ArchiveExt -contains $ext) {
          $kind = 'archive'
        } elseif ($ext -eq '.exe') {
          $kind = 'executable'
          $runnablePath = $target
        } else {
          $kind = 'clean file'
        }
      }
    } catch {}
    @{ target = $target; name = $name; kind = $kind; isFolder = $isFolder; runnablePath = $runnablePath }
  })
  @{ utc = [DateTime]::UtcNow.ToString('o'); scanned = $all.Count; skipped = $skipped; failed = $failed.Count; threats = $tRecs; clean = $cRecs } |
    ConvertTo-Json -Depth 5 | Set-Content -LiteralPath (Join-Path $AppDir 'last-results.json') -Encoding UTF8
} catch {}

# Offer quarantine in interactive console runs (the app has its own buttons).
if ($threats.Count -gt 0 -and -not $NoPrompt) {
  $qcand = @($threats | ForEach-Object { $_.QPaths } | Where-Object { $_ } | Select-Object -Unique)
  if ($qcand.Count) {
    $doQ = $false
    try { $doQ = AskYesNo ("Quarantine the {0} flagged file(s)/archive(s) now? (moved to quarantine, restorable)" -f $qcand.Count) $false } catch {}
    if ($doQ) { Invoke-Quarantine -Paths $qcand -Reason 'flagged by scan' | Out-Null }
  }
}

# Exit code for scripted callers: 0 = clean, 1 = threats found, 2 = scan failures.
if ($threats.Count -gt 0) { exit 1 } elseif ($failed.Count -gt 0) { exit 2 } else { exit 0 }
